-- Poems batch 387
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('080d396b-a87b-435f-a6ad-fa9db32caed6','外屏不固婢有思逸者小兒作髙柵限之','王洋','宋','宋诗','song-poetry','','[]','一從爲客今五年，囊中羞澁無一錢。',224,'全唐诗/poet.song.96000.json','["一從爲客今五年，囊中羞澁無一錢。", "雖逢惡客如櫟社，匠石不顧斤斧全。", "自矜尚可詫妻子，不用戒謹長安眠。", "性慵外戶縱不閉，竊類陳平佐刺船。", "昨者小兒治藩落，堅不可拔髙踰肩。", "心疑過意使輟作，瓦棺自免一坏穿。", "答云竈下不安室，慵倦未終頻計日。", "饑鷹在臂常掣韝，病鶴傷心懷舊匹。", "有自而然爾莫慚，無以聚人吾自黜。", "又思廚清固無餘，以我養爾何怨疾。", "忍饑只合且困眠，何爲目眺思悠然。", "爾今腸空尚圖逸，藉飽安得同周旋。", "人生有命甘淡泊，安貧聽我歌薰弦。", "古來饑渇第可忍，醉飽以德方稱賢。"]'),
('35923556-c714-4452-ab06-4641aada2bdc','方春時群兔食麥先生置罝焉終無所獲今者原頭草枯無所隱遁乃得以投湯餅是兔得所嗜以死而先生之憤亦快也既感斯語因繼前韻','王洋','宋','宋诗','song-poetry','','[]','吳山積雪不潤麥，客子思鄉疑卜宅。',96,'全唐诗/poet.song.96000.json','["吳山積雪不潤麥，客子思鄉疑卜宅。", "先生好客如聚書，豈料向來遭五厄。", "㕙㕙自是安無虞，爾身那計歸庖廚。", "遐方自此欲同軌，書文正合求長鬚。", "當時咀食應矜狡，湯餅于今得稱巧。", "幸因所嗜同一烹，吾鼎饒伊送肝腦。"]'),
('910d1b63-bdcd-4a0c-a04c-d94726404a1d','臘八日書齋早起南鄰方智善送粥方雪寒欣然盡之因成小詩','王洋','宋','宋诗','song-poetry','','[]','臘月八日梁宋俗，家家相傳侑僧粥。',112,'全唐诗/poet.song.96000.json','["臘月八日梁宋俗，家家相傳侑僧粥。", "栗桃棗柿雜甘香，蓤椇芝栭俱不錄。", "金僊託言成道時，不認饕饞借稱目。", "誰謂毗耶清淨身，何有塵埃更須浴。", "今晨雪屋梳白頭，南鄰與饋如素求。", "未須怊悵思往昔，坐變勁峭同春柔。", "鋪排短韻一作戲，爲君姑續歲時記。"]'),
('56956386-f9a1-46cc-aa3d-1ee623268929','僊上人舉進士過三十不第作詩曰男兒三十未有立人世百年徒自勞徑拂衣削髪爲比丘今二十年矣精力甚健及將遊天台既羡師行復自悔訟因其將行作詩紀之','王洋','宋','宋诗','song-poetry','','[]','春風只解吹春花，靈根古木無生芽。',224,'全唐诗/poet.song.96000.json','["春風只解吹春花，靈根古木無生芽。", "玲瓏拳石出萬様，碧峰千仞藏煙霞。", "世間百事總如此，偶然感慨還興嗟。", "上人本是龍門客，少小辭家來射策。", "可憐奇物未化神，卻與凡鱗同點額。", "當時三十未爲老，急電抽身能覺早。", "一投空跡二十年，留得詩腸至今好。", "我始與君同業書，明瓊偶紀張雙魚。", "强將野鶴落樊圃，不與閑雲同卷舒。", "君將風袖隨煙霞，我獨塵緣著冠屨。", "試問堂中老衲師，定見兩人優劣處。", "天台風路埋雲根，寒巖夜嘯鼪鼯群。", "脱身也自不費力，未疑此心長羡君。", "他年邂逅雲門路，不止分君一片雲。"]'),
('4832bea9-61ae-4105-876d-be0472b69088','賀生孫詩','王洋','宋','宋诗','song-poetry','','[]','紛紛郁郁煙結扉，傳道老何孫子歸。',96,'全唐诗/poet.song.96000.json','["紛紛郁郁煙結扉，傳道老何孫子歸。", "褓中不作嬰兒泣，芝蘭共見生庭闈。", "于公决獄德莫比，今日何公亦如此。", "掌中送此麒麟兒，不是如來須孔子。", "長兒本自長沙得，驥子生孫定奇特。", "未論玉骨秋水神，聞說已傳湯餅色。"]'),
('487262f7-acdb-4346-8e82-8ab5380d09b2','尤生說字','王洋','宋','宋诗','song-poetry','','[]','正名百物與神謀，禍福無門亦自求。',96,'全唐诗/poet.song.96000.json','["正名百物與神謀，禍福無門亦自求。", "君獨何心分象數，筆端無復見全牛。", "探心取意陳前修，一字或可談封侯。", "逆知喜怒容點頭，攻君乃是操君矛。", "謡書失腳似可笑，雜今雜古近同調。", "乃知人事亦天然，吾心或者司化權。"]'),
('2c35b19e-2ae1-45c0-9181-c9362c40c905','昨日往候伯源承軒蓋未還第見兩夫守舍面目嚴冷有羽林貔貅勢一僕候門遇故客乃加禮振聲折腰應對響答若騁駿足而未果者因問主翁何在日晏何尚未歸僕從如汝輩凡幾人三人者齊聲答曰主人旦暮出入結駟榮盛奔走執事畢具間枉車騎過客它舍群騶之外尚餘三人我輩是也見其庭戶森然黄簾綠幕朱戶扃固此三人者特外隸耳而勢已如此使僕誤入帷帳深處又當何如僕時病起與羸夫爲三既不得見因招籃舁將還三人者自後指而笑之意誚客太無堪態主人真可誇也俛首興嗟不能自已因成小詩且于卒章自見其志併發一笑','王洋','宋','宋诗','song-poetry','','[]','洞中僊子丹藥成，鬼神妬嫉喘且驚。',144,'全唐诗/poet.song.96000.json','["洞中僊子丹藥成，鬼神妬嫉喘且驚。", "龍門虎踞工守視，始知異類窺僊靈。", "先生本是玉京客，藍橋邂逅邀雲英。", "是宜收藏此丹鼎，貔貅呵禁門長扃。", "亦如猛虎守厲禁，千山不許一鳥鳴。", "主人日食大尉府，都騎自合連輜軿。", "只嫌底事苦未足，要有蘭玉羅階庭。", "行人過者莫回面，牆東鞦韆不可見。", "我有丹砂不似君，待與葛洪評貴賤。"]'),
('8ebc765d-0778-43f1-9098-95dedddcadeb','寶覺師畫少陵像用筆甚簡伯氏稱賞之因戲爲長言寫之','王洋','宋','宋诗','song-poetry','','[]','破帽麻鞋肩傴僂，回頭意若呼宗武。',128,'全唐诗/poet.song.96000.json','["破帽麻鞋肩傴僂，回頭意若呼宗武。", "行歌又似出關時，飯顆山前日當午。", "公如冰玉天賦成，玉爲溫潤冰爲清。", "廟中朱絃堂上曲，一唱三嘆知遺聲。", "平生但飽主人飯，身後空傳世上名。", "蕭條冷炙殘杯氣，寂寞千秋萬古情。", "吳僧筆端龍幻化，幻出前賢世無價。", "可憐見畫未見詩，更合愛詩方愛畫。"]'),
('9d2d57e6-7777-4317-8158-771750b53778','曾谹父招客盛夏轉涼','王洋','宋','宋诗','song-poetry','','[]','火雲烈烈燒塵土，八月炎風正三鼓。',96,'全唐诗/poet.song.96000.json','["火雲烈烈燒塵土，八月炎風正三鼓。", "使君傳教招近局，雨打紅塵風起舞。", "人言神物戲慳人，長爲微情愛三暑。", "晴時得雨靜招風，若飲清涼汗如雨。", "了知人意通三界，達士揮金天不怪。", "今朝賓客雜鄒枚，想有筆端風雨快。"]'),
('f5751c5f-1bcf-4297-96d0-064c4f2387b6','季文作真率會遇大雪寒甚主人之居狹不容散步爲嫌作數語爲解','王洋','宋','宋诗','song-poetry','','[]','一風一雨天醖雪，溪上行人手吹裂。',144,'全唐诗/poet.song.96000.json','["一風一雨天醖雪，溪上行人手吹裂。", "主人掃巷作光華，滿注金罍喚賓客。", "酒酣耳熱膽量寬，容我口開非偪仄。", "天寒促膝政相宜，共道興來連舉白。", "人心好客天亦知，平時思雪不可期。", "寒消內熱沃肺渇，瑤花滿眼真瑰奇。", "一尺呈豐有成驗，三白譴厲徴前爲。", "不辭秉燭達曙光，别思共醉今何辭。", "此身對酒願長健，明年花發春遲遲。"]'),
('898d1ae3-13de-4eae-8024-673c63c1bff7','鄭吏部設川饌招客戲成長言呈諸丈','王洋','宋','宋诗','song-poetry','','[]','茫茫四海天宇髙，九州列貢分地毛。',192,'全唐诗/poet.song.96000.json','["茫茫四海天宇髙，九州列貢分地毛。", "江黄之區橘柚國，細腰宫衣無吳庖。", "□□不得供刀匕，况走川珍自岷水。", "鄭翁幻戲不作難，縮地分甘五千里。", "老人種蔬薑滿畦，買薑留錢人不知。", "丁寧使者市蜀錦，恍惚異味來如期。", "乃知此事古亦有，鄭老此戲誠瑰奇。", "擣珍䐑臠投巨鼎，繚肝末肺分全犧。", "南方搖落青未已，梅蘂垂垂照青泚。", "雪消冰盡飽陽和，更待春風轉沙尾。", "穠華只說錦官城，匝地燒燈夜初起。", "從翁已幸不齎粮，期向城都看藥市。"]'),
('13b579bd-3c69-406b-be54-9953f57dcb33','題徐明叔海舟横笛圖','王洋','宋','宋诗','song-poetry','','[]','莫愛一掬水，海闊觀狂瀾。',120,'全唐诗/poet.song.96000.json','["莫愛一掬水，海闊觀狂瀾。", "莫愛手中月，空明海上山。", "人生適意貴如此，前度徐郎在千里。", "噴雲裂石天宇髙，夜寒水冷魚龍起。", "世間俗客貪昏睡，波濤不識神靈意。", "更令疊奏數曲終，鯨山會作玻璃翠。", "畫工妙手今無幾，可惜徐卿今老矣。", "醉中睡起百憂寬，與君一笑西風裏。"]'),
('ac022cc3-54b2-4e22-b047-b1dfb6bcd3d1','石澗','王洋','宋','宋诗','song-poetry','','[]','帝令銀漢推餘澤，不與人間較刀尺。',160,'全唐诗/poet.song.96000.json','["帝令銀漢推餘澤，不與人間較刀尺。", "剪綃爲練課天孫，濺溜成文照東壁。", "我疑蒲城鬼神入，腳踏飛車翻霹靂。", "怒當十倍縛王離，瓦震三軍開許歷。", "仙翁題詩詩有史，畫史紛紛俱屈膝。", "至今盛事隨山中，往往摩挲到金石。", "歸來滿口說江湖，不學平生論感激。", "乃知卷舒在虛懷，誰道今人不如昔。", "有時坐我天姥下，但覺清風生羽翼。", "長令淨洗五兵閑，回看萬事皆塵跡。"]'),
('c044a8a2-b617-489d-a4b6-74ce6c4fe54e','寄題永新鄧成之粟庵','王洋','宋','宋诗','song-poetry','','[]','學詩學禮子已文，種花種竹居不貧。',144,'全唐诗/poet.song.96000.json','["學詩學禮子已文，種花種竹居不貧。", "門閭正可務廣大，如何一粟容君身。", "結庵名粟亦何寄，口不盡言知有意。", "鵾鵬羽翼自垂天，蜩鷽飛鳴有餘地。", "短長小大爭長雄，舒卷不離方寸中。", "小如一粟大江海，萬形宇內寧非同。", "君如推此充寥廓，回集塵端亦棲託。", "放言切勿誚蒙莊，伯夷永名仲尼博。", "更須談理勿談空，此道根原由守約。"]'),
('d8710bf7-a334-4ea3-89a4-f286ac257ee4','凝雲堂','王洋','宋','宋诗','song-poetry','','[]','浮雲蹤跡真何處，會若無心是同住。',112,'全唐诗/poet.song.96000.json','["浮雲蹤跡真何處，會若無心是同住。", "此間我若解忘情，應與閑雲共來去。", "面山結屋開虛明，屈伸與我同太清。", "紅塵洗淡一翻手，悠然適見雲平凝。", "回看詩客時滿堂，雕刻品彙俱奔忙。", "亦知泉石成膏肓，與人裝取錦繡腸。", "寥廓萬里同翺翔，唯有白雲來帝鄉。"]'),
('7f260df9-2257-428f-8846-a313d3cd0af5','庚午歲伯氏生朝作樂府一章爲壽','王洋','宋','宋诗','song-poetry','','[]','木公金母傳瑤爵，九虎開門動魚鑰。',160,'全唐诗/poet.song.96000.json','["木公金母傳瑤爵，九虎開門動魚鑰。", "瑤池曼倩别煙霞，海上安期降喬嶽。", "東牟先生德彌大，靜課虛無明寂寞。", "背連海嶠三雙鼇，手取西山一丸藥。", "推先當戶培芳蘭，斗牛寶氣搖光寒。", "光華章綬表奇格，照耀廣陌馳花鞍。", "春風物色論長久，柳拂腰支梅勸酒。", "百篇聊復付西江，盛事會須傳不朽。", "天上老驥禾充腸，一秣萬里瀆空蒼。", "年年歲歲身長健，歲歲年年春草長。"]'),
('334c7da7-2a98-410f-97f3-c78f1d89e68e','同劉仲忱舍人先生鄭武子餞伯氏賦兩篇得聖歡二韻','王洋','宋','宋诗','song-poetry','','[]','南州本非行路難，年來行客多悲酸。',64,'全唐诗/poet.song.96000.json','["南州本非行路難，年來行客多悲酸。", "黄花白酒且今夕，驚風晚日催雙翰。", "一杯交歡意方屬，四座相顧顔不歡。", "如今守邉戍不遠，政合勉力勸加餐。"]'),
('4948afb4-883a-419e-8401-15e4c3b39d7d','送周仲固運使之官湖北','王洋','宋','宋诗','song-poetry','','[]','梅花滿野春欲蘇，漢家使者臨重湖。',224,'全唐诗/poet.song.96000.json','["梅花滿野春欲蘇，漢家使者臨重湖。", "使君作意不求異，解使愁歎成歡娯。", "往年奉法佐廷尉，縱遣狐兔誅封嵎。", "平生獄吏弄爪觜，民不畏吏從君初。", "即今持節下澤國，要令比屋歌唐虞。", "父兄便飽倉有粟，童子莫恨衣無襦。", "溫溫和氣徧封服，坐運豈必勞傳呼。", "桃花之源誠有無，吾恐誕幻成荒誣。", "不如使君三聖書，總括萬彙包堪輿。", "一編韋带在掌握，藏之懷抱時卷舒。", "古今事物不外取，但用指訣開迷途。", "斯民識路從變化，履泰去否攣中孚。", "使君早訖外郎課，歸奉天子陳王圖。", "他年訪我當踟蹰，欲餉白飯陳青芻。"]'),
('071a5a17-9c8f-45cc-a107-3d6d6a26dfd4','偶得上饒芡實頗佳分薦同邑以詩送','王洋','宋','宋诗','song-poetry','','[]','明珠寶簿藏貝宫，姮娥取置空明中。',176,'全唐诗/poet.song.96000.json','["明珠寶簿藏貝宫，姮娥取置空明中。", "神仙法施仗秘呪，一粒變化傳無窮。", "水府仙人通妙訣，擘破寒泉弄明月。", "左庚右甲養素胎，珠勝醍醐色如雪。", "錬丹水底含太陽，世人錯比煎硫磺。", "丹成不合戀凡殻，雄鷄冠碎鴻頭傷。", "紫苞裂處呈芳髓，火候溫溫闇香起。", "青荷猶著舊衣裳，玉質可憐供軟美。", "我家舊住長淮湄，花開十丈芙蓉旗。", "年年割鮮喚同社，徑醉忘卻還家時。", "何人縮地有幻巧，容我短棹追馮夷。"]'),
('a0b2c390-ac4f-40d8-bf02-c44d9dbb8a00','借笠澤叢書于陳長卿以詩還之','王洋','宋','宋诗','song-poetry','','[]','親見子雲貎不颺，遲以歲月名自彰。',208,'全唐诗/poet.song.96000.json','["親見子雲貎不颺，遲以歲月名自彰。", "松江笠澤幾多地，古今三作勝士場。", "鴟夷已去乘海航，季鷹撫事驚秋霜。", "五百年間天隨子，汀洲杜若齊芬芳。", "筆牀茶竈湖光裏，欸乃聲中弄清泚。", "有廚無煙釡爨空，過午懸簞藜莧美。", "詩窮文怪兩奇絕，造化别分閑日月。", "一峰下嶺晚當門，四頰寒鱸夜飛雪。", "甘同世上伏臘勤，肯作人間觴豆客。", "辟書不爲救口忙，銜命終辭一官熱。", "借書當借物外書，洗除塵坌觀浮虛。", "異時曾此一過眼，故人相遇誠歡娯。", "翩然好去追黄鵠，酒無兩瓻歌一曲。"]'),
('f8426b4b-79a5-44e5-b6f8-cf94b655f5ef','聞何爲孫作內集以長言戲之','王洋','宋','宋诗','song-poetry','','[]','門前春田澍膏雨，門內春風動歌舞。',112,'全唐诗/poet.song.96000.json','["門前春田澍膏雨，門內春風動歌舞。", "瑑爲璋玉男子祥，起作繡鞋女兒舞。", "阿翁吹簫兒獻旅，粉面嬌孫侍家主。", "一門歡笑足戲樂，盛事流傳百年語。", "村歌社曲莫插手，定本風流教坊譜。", "一家有喜百家同，况是相逢淪落中。", "犀錢玉果大開說，已愧湯餅霑無功。"]'),
('0cab7694-aa48-4f10-87d6-ff09c269f374','周秀實書云裴奇卿好茶得病鍾熙仲酣醉任真西林老逢場作戲同倚花下一時信筆作詩爲戲','王洋','宋','宋诗','song-poetry','','[]','閑來得病緋衣客，著酒當茶桑苧翁。',144,'全唐诗/poet.song.96000.json','["閑來得病緋衣客，著酒當茶桑苧翁。", "誰知十室有二士，復得周叟同從容。", "叟今行年餘七十，七歲詩成鬼神泣。", "即今吻合主盟壇，籍湜驚奔汗流急。", "兩君置陣亦嚴整，未許行人私越境。", "有時爭利逐輜車，掉鞅安行發機穽。", "戰者方酣見者真，走書取證石壁人。", "石壁老人方睡起，巖前一笑桃花春。", "遲君待我同徙倚，共催短棹東風裏。"]'),
('a20e6564-c0e6-4f9a-b4db-e7ec64313b96','方何二公回自郡所得不同作詩戲之','王洋','宋','宋诗','song-poetry','','[]','南鄰博士只破幃，春來數日分春衣。',192,'全唐诗/poet.song.96000.json','["南鄰博士只破幃，春來數日分春衣。", "東風陌上催蒙茀，不許看花緩緩歸。", "那知此理未可訴，破費書廚走長路。", "靜思我咎安致然，杳杳人情無問處。", "歸來粉黛包亦結，安得衾禂更羅列。", "嬌兒冬暖不須啼，正恐當寒更無韈。", "命數從來有奇耦，北里士師真好手。", "一時歡笑父子同，箧載縑緗船載酒。", "歸遺欣欣樂可期，婦運金刀時哺飴。", "先憂後喜尊吉卜，釃酒烹魚消百罹。", "世間得失類如此，解使空腸作悲喜。", "紅白紛紛一種花，試向東風問桃李。"]'),
('fb3f96e0-3af3-4f21-ac03-afe27ee8cc51','戲鄭曾二老','王洋','宋','宋诗','song-poetry','','[]','兩編千片白雪繭，六百二斗青銅錢。',208,'全唐诗/poet.song.96000.json','["兩編千片白雪繭，六百二斗青銅錢。", "不辭破費十日産，要向几上追前賢。", "前賢已死不可慕，世上流傳只佳句。", "不尋斷簡賞心符，定自前賢無覓處。", "鄭翁知我用意誠，云有甲乙分餘明。", "盧仝書到孟郊富，李老被酒張翁醒。", "當時儲館典讎校，今日取送傳芳馨。", "分多析少每如此，翁甑百金杯千羹。", "北鄰老子苦好客，懸簞過午須賓食。", "昨朝喚客啖鵝炙，十字浮光湯餅滑。", "須臾碾畔百塵飛，語是奴童破珪璧。", "此翁香串數百枚，一一啖客當千回。", "啜香飽炙勘詩譜，但度流年無所苦。"]'),
('875966bb-2873-4b29-8a2b-dcef2b41d34d','以校正字學還方智善作詩贈之','王洋','宋','宋诗','song-poetry','','[]','惟古於文藏妙理，自然之音見微旨。',360,'全唐诗/poet.song.96000.json','["惟古於文藏妙理，自然之音見微旨。", "唇舌齒喉母生子，清濁重輕毛髪比。", "古者八歲方毁齒，小學師承方肄此。", "時及春秋循一軌，臺輿亦知窺閫壘。", "齊人謀莒本秘詭，登樓密語不敢指。", "兩脣含合不哆侈，見者能知豈徒爾。", "後人學疏忽源委，傳會流俗兼下里。", "庚辰吳入記前史，郢永遂令齊亥豕。", "少知長老習步跬，紅綠誰能辨朱紫。", "縱有是師無是士，聞者一笑或掩耳。", "我年六十老書几，倣彿聲形多取似。", "目前趨過或但已，翻覆討論徒累累。", "方侯大梁舊冠履，結髪儒衣長槐市。", "發憤編摩貪寸晷，索摘真能窮骨髓。", "持以告人遭詆毁，方侯持心直如矢。", "尊吾所聞寧轉徙，若不我從知已矣。", "我留龜溪同梵庋，羶蕕偶幸親蘭芷。", "時論古意自鞭箠，不覺此心思奮起。", "乃知古學惟審是，晚乃紛紜聽華綺。", "考永聲律究終始，縱不有疑心固喜。", "要好誰云不傳紙，革誤鉏疑云糠粃。", "欲障東流歸海水，識路直須行不已，靖節琴中有宫徵。"]'),
('458f5991-5692-457e-a8c0-b43266b4484c','聽琴贈遠師','王洋','宋','宋诗','song-poetry','','[]','世人傾耳聽繁音，太音古淡難爲聽。',288,'全唐诗/poet.song.96000.json','["世人傾耳聽繁音，太音古淡難爲聽。", "有如廣庭題旌夏，或者驚遁疑有神。", "當時舜牀調五絃，薰風煽物無窮人。", "若言造化不愛翫，安得感君回陽春。", "遺音相繼嗣者誰，窮山緇侣黄冠師。", "非干此意樂窮靜，世路自與相参差。", "我今試聽清風操，野鶴孤猿對殘照。", "琅琊山下醉翁吟，分明撥向琴中調。", "人言大弦如玉溫，小弦廉折亮以清。", "春秋自是隔寒暑，天地不得令偕行。", "豈如七弦轉十指，勁節諧音同到耳。", "乃知造化在指端，豈但髙山與流水。", "道人不肯長懷珍，亦曾挾藝遊車塵。", "髙門八字驚未見，脱贈往往捐千純。", "如今飄泊困長路，更覺世味難將迎。", "應將感愴赴琴曲，一聽萬慮羅心兵。", "道人勿苦生冰炭，古道須信非人情。", "哀音果要洗俗耳，更去嬌弦三兩聲。"]'),
('7c27f00c-eb4e-4c46-a98d-40cba18606fe','陳道士年十三骨氣有異弈棋得妙處鮮能對者推此藝以他學何所不可因成短篇贈之','王洋','宋','宋诗','song-poetry','','[]','一枰局上無多歧，世人到此懷自疑。',256,'全唐诗/poet.song.96000.json','["一枰局上無多歧，世人到此懷自疑。", "方圓動靜曾未識，生死眼前那得知。", "長頭道士年十三，眼如巖電光爛爛。", "已將雙腳落城市，猶自面目藏烟嵐。", "局中應答每閑暇，揮霍紛紜窮變化。", "回頭卻笑世人疏，不認盈虛成取捨。", "我聞此藝在專攻，莫起妄念思冥鴻。", "冥鴻不至局已敗，弓繳漫自存胸中。", "我欲將君比弈秋，專持此藝從君游。", "但期白黑得歸處，一枰勝負吾無求。", "又聞奕棋多仙侣，常向局中送寒暑。", "世間利害疾轉頭，妙手如今向誰語。", "昔時陶令曾鼓琴，爲嫌弦上多繁音。", "七弦除去五音斷，卻於此處知琴心。", "我知此藝亦如此，不似推枰休刻齒。", "請君長大具芒鞋，共向鹿門尋石髓。"]'),
('bdff2726-78cc-441e-834b-4c92888e9f6d','贈向揚州','王洋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','耐官丞相千載人，傳家愛國不愛身。',384,'全唐诗/poet.song.96000.json','["耐官丞相千載人，傳家愛國不愛身。", "兒孫當使風流在，已許絕代誇殊倫。", "其間淮上禮樂帥，氣象直出追芳塵。", "未論十世數眷屬，况是雲幕椒房親。", "揚州自昔鎮平野，東控七澤南甌閩。", "肩摩轂擊接晝夜，賓從雜沓朝天津。", "尊前芍藥照金翠，堂下楊柳眠芳茵。", "上中下地貢賦錯，二十四橋風月新。", "百年人事有更變，冥冥原隰桑麻春。", "中興天子撫方夏，選用世德分憂勤。", "劬勞鴻雁事安集，藍縷篳路張羅閩。", "即今施設如有神，突兀壯勢何逡巡。", "髙城樓觀插空碧，畫橋舟艤浮奫淪。", "黄童白叟息愁嘆，自言重見風俗淳。", "野人本住蓬莱側，寄籍淮甸老阡陌。", "飄流自分不重來，重來翻欲謀安宅。", "昨宵晚渡長江來，扁舟欲泊長河側。", "送徒勉我但安行，此地何人名惡客。", "元戎號令皆有時，令行禁止須臾期。", "請君委櫜付大尹，野宿山行良勿疑。", "行行古埭弔謝公，平堤一笑逢老翁。", "語多雜亂唯說尹，但道還樂今年豐。", "吳娘踏歌兒起舞，不須社日長聞鼓。", "若令未即棄塵埃，會見黄金價如土。"]'),
('1c0de6e6-c49a-40ae-b711-5f6477b5e1fe','贈鄒德年','王洋','宋','宋诗','song-poetry','','[]','短檠三尺照座隅，眵昏兩目頭不梳。',192,'全唐诗/poet.song.97000.json','["短檠三尺照座隅，眵昏兩目頭不梳。", "丈夫功業務廣大，安用事此牛尾書。", "多求舊聞助器識，欲駕萬里須舟輿。", "要堅志節在專苦，積螢照夜真前車。", "道鄉先生好門戶，髯季晚出充門閭。", "昻昻鷄群見野鶴，炯炯虎視嗟黔驢。", "如何天公不着眼，棄此異寶猶紛挐。", "我知造物自有意，將騁健駿先虛徐。", "金須百錬作鐘鼎，玉試三火真璠璵。", "來年明光再射策，聊取髙第酬三餘。", "古今人事自差别，見晚用速皆乘除。", "他年雲路着鞭穩，無忘過我中田廬。"]'),
('3bdab8a1-0b94-4b98-ad47-e91b00664638','贈大猷','王洋','宋','宋诗','song-poetry','','[]','棲遲下國傷蹉跎，更生父子交琢磨。',192,'全唐诗/poet.song.97000.json','["棲遲下國傷蹉跎，更生父子交琢磨。", "雀羅門外賓客省，三鱣堂中經史多。", "菑川起奉太常策，風雅先入光祿科。", "人間盛事有如此，東平江夏今如何。", "一廛聊寄吳山曲，白柄長鑱斸黄獨。", "飲從野老自有餘，飯在先生長不足。", "人言功名難力取，我意功名要勤苦。", "分明經訓是菑畬，誰道今人不如古。", "山陽隱士家傳饑，長身季子今流離。", "聞君酬唱得此客，牧兒販婦哦新詩。", "我將六十筋骨羸，形骸行赴溝壑期。", "如君名遂尚可見，幅巾他日期追隨。"]'),
('a0a29f00-fae9-44e6-b797-fd1a35fbfe2f','古詩贈沈約之','王洋','宋','宋诗','song-poetry','','[]','蘇端薛復同黄土，海內文章誰接武。',160,'全唐诗/poet.song.97000.json','["蘇端薛復同黄土，海內文章誰接武。", "即今七字續長言，沈子揮豪照今古。", "朝爲百賦更賈勇，暮作千詩猶奮怒。", "補天綵筆不費工，捲地奔風隨插羽。", "窮途得所喜入眼，口誦新篇身起舞。", "已知奔逸逐驊騮，况復逡巡蹈規矩。", "薦書指日登姓名，藝圃方期富倉庾。", "閻公色動瞻斗牛，處士當筵賦鸚鵡。", "跨海鯨魚要力求，翡翠蘭苕不須數。", "不嫌投迹老龜溪，看子聲名滿寰宇。"]'),
('5bd76ba7-d524-409c-a3a7-6d2971418ff5','贈丁執中','王洋','宋','宋诗','song-poetry','','[]','計子産餘身可足，有子有妻難免俗。',64,'全唐诗/poet.song.97000.json','["計子産餘身可足，有子有妻難免俗。", "平生食案好擇餘，今日虛倉不贏粟。", "忍饑自是學道功，萬事由來同轉燭。", "天生異寶世須求，說是君衷自懷玉。"]'),
('56d72d31-7dee-4167-b58d-2cfa317d378a','懷范子以詩贈之','王洋','宋','宋诗','song-poetry','','[]','開正占晴符古語，便謂春風徧花塢。',160,'全唐诗/poet.song.97000.json','["開正占晴符古語，便謂春風徧花塢。", "那知天意不可謀，纔告休期便風雨。", "急追令節已難尋，臥向空齋思勝侣。", "可憐十步五步寬，似隔千山萬山阻。", "今朝馮夷巧作便，翦刻天花散飛舞。", "峭寒燠沐兩不同，况是南箕正三鼓。", "若求此花勝彼花，少霽威嚴無用武。", "桑錢未出土未興，緩給豐膏亦無苦。", "半分僧室依環堵，滿目愁來不堪數。", "需公排日作好詩，細破春愁看幾許。"]'),
('53a809c9-0a8d-4a6a-b4ae-5301439db144','聞丁永安屋下疊山甚有佳趣恨未之見作詩寄之','王洋','宋','宋诗','song-poetry','','[]','買山幾人真愛山，束薪煮石凋朱顔。',64,'全唐诗/poet.song.97000.json','["買山幾人真愛山，束薪煮石凋朱顔。", "老丁謀作久長計，洗寒疊翠房櫳間。", "簾通庵扉即洞戶，人映山色多煙鬟。", "住山住庵似丁老，脫棄妻子真愚頑。"]'),
('5422b429-3eb1-4063-9442-768c2a96d757','周秀實以近多讀書少對棋有詩及之因以寄','王洋','宋','宋诗','song-poetry','','[]','識情變易須臾期，躁動未得安無爲。',128,'全唐诗/poet.song.97000.json','["識情變易須臾期，躁動未得安無爲。", "幽思傷神靜生苦，游藝且復招僧棋。", "棋中趣味亦何有，勝負紛紛翻覆手。", "分排事外雜窺圖，得失坐中分好醜。", "要須忘年在書史，不出空齋見千里。", "昏塵積習要揩磨，晚學未應談至理。", "終當謝遣惠子琴，不挂一弦存五音。", "日損其半思慮盡，此道孰知無古今。"]'),
('f5b5c77c-c84d-41d4-bd88-c646212a0b65','因與伯氏同一僧話武夷事作詩追寄之','王洋','宋','宋诗','song-poetry','','[]','直峰峭壁天半青，髙簷張燈疑挂星。',320,'全唐诗/poet.song.97000.json','["直峰峭壁天半青，髙簷張燈疑挂星。", "山川勢力有如此，擇地信可棲仙靈。", "我前解官古樵戍，志願本欲探珠庭。", "時當恢台積氛霧，一日三雨時三停。", "載舟撐石逆噴浪，自謂力可登青冥。", "篙工榜岸遭急灑，回宿荒宇依祠廳。", "二三道士謬告語，云此潤澤來雲軿。", "比聞輿人誦舊說，仙官下矚如明熒。", "遊占晴爽惡昏滯，官去此法當伶俜。", "果還近甸阻天路，一官泛跡隨飄萍。", "退之昔日徙南服，祝融騰擲開仙扃。", "近時蘇翁失定武，太行毛髪無餘形。", "一晴一雨告休咎，晴者人樂陰天刑。", "我意神官與人異，宜以行事分羶𦎬。", "人如阨棄神亦厭，世間利達真芳馨。", "窮通兼忘扶正直，人知戒勸思常經。", "有如神意本不爾，人意忘卜欺愚聽。", "黄鐘大呂絕世韻，扣擊距躍嗟短莛。", "心知得路適遠意，願結茅廬當寒汀。", "真遊適遠未可必，搖寄此語通丁寧。"]'),
('acec305c-1ef0-4a52-b72a-d0e844c5cf3c','答裴寄卿書因寄長篇','王洋','宋','宋诗','song-poetry','','[]','裴郎短身衣弊服，衣長過身幾半幅。',140,'全唐诗/poet.song.97000.json','["裴郎短身衣弊服，衣長過身幾半幅。", "髙裙大袖領占肩，要是精神大於腹。", "古書古字談古人，洗盆滌盎供慈親。", "慈親居貧不道苦，裴郎醉中頻起舞。", "里中驚怪無此人，往往爭看立環堵。", "妻兒醉時亦同醉，未免醒時生竊議。", "裴郎裴郎切勿論錢錢有菜。", "我家伯氏亦翛然，得官去官俱醉眠。", "裴郎有意縱短棹，雪夜待君明月邉。"]'),
('0a29e2dd-1e8e-4bc6-b927-64361a028ae5','喜雨寄上饒守','王洋','宋','宋诗','song-poetry','','[]','東村叢祠聞伐鼓，西村巫家女兒舞。',176,'全唐诗/poet.song.97000.json','["東村叢祠聞伐鼓，西村巫家女兒舞。", "滿城半笑半悲啼，唯有使君心獨苦。", "使君日日拜土龍，尊彝浄潔籩豆豐。", "公廚彌月不御肉，七十行老筋力充。", "明明上天採民譽，先使千嶂雲朣朧。", "知公不肯愛珠玉，非玉非珠只雨粟。", "如今萬室動歌弦，穩保千箱滿穜稑。", "不須袞袞談政理，但持此事獻天子。", "從來上瑞是豐年，會有徴書封玉璽。", "有如不掩造物功，盡付妙手歸長空。", "長空冥冥不可名，請公便作喜雨亭。"]'),
('aae59665-80f5-4633-8463-05a886a4493f','寄曹嘉父','王洋','宋','宋诗','song-poetry','','[]','廣陵隋家天子都，背負巨海襟江湖。',384,'全唐诗/poet.song.97000.json','["廣陵隋家天子都，背負巨海襟江湖。", "江分青山湖獻白，梁宋千里傳膏腴。", "朱坊瓊園翫月夜，谷林九曲秋陽徂。", "奇辭巧語不可極，盛事往往開天衢。", "我家太傅官三載，文物方值開元初。", "四幷堂前木芍藥，小金山下紋車璖。", "沸天哀笳律新婉，照水粉面衣襜褕。", "少年意盛不自屈，直欲赤手擒於菟。", "翁云學等不可躐，俾著逄掖勤詩書。", "泮宫得就弟子列，親見士子衣諸于。", "子時燕頷出頭角，衆中轉目窺陳吳。", "孤羆自爾事拱默，嫫姆未免爭妍姝。", "夤緣傍石見光彩，驚破塵匣開明珠。", "同袍傳諷梅花句，知子名字須氈毺。", "分攜两家止隔歲，果見貢篚先鄉書。", "巍巍廣殿厭長策，曄曄盛譽嗤諸儒。", "蓬萊海徼通外服，坐戢巨浪張威弧。", "超騰意子便得路，亦復坎壈游窮途。", "我年二十始冠弁，一門嬰禍奔淮隅。", "辛勤往來幾萬里，壯志滅沒忘前圖。", "再遊黨塾事商較，齒髪已壯頭須梳。", "十年低徊不附奏，閭閻婦子欣揶榆。", "年將四十偶占第，朱顔已變無膚腴。", "一官從此浪隨牒，十生九死群鼪鼯。"]'),
('f5f14f1f-e68a-4490-8a17-2ec40b083a3a','寄何宣仲','王洋','宋','宋诗','song-poetry','','[]','同年進士同壇僧，暫聯戢戢如浮萍。',384,'全唐诗/poet.song.97000.json','["同年進士同壇僧，暫聯戢戢如浮萍。", "一從仕版秪事役，往往牢落如明星。", "假能作意篤恩好，言語不過時芳馨。", "死生貴賤兩乖角，黄鐘可扣非柔莛。", "吾見何子取路别，秋霜皦日看鴻冥。", "一言意合即定分，咄嗟洞見無留停。", "慈親八十髪黄素，稚子三歲眸青熒。", "此翁貧苦不敢嘆，意欲歡笑娯親庭。", "往年我官南武郡，士有林子家伶俜。", "一兒得官走上國，投銓中品書安寧。", "忽去病死不得返，我亦憤泣傷飄零。", "徐言中表有賢丈，已收旅骨依林坰。", "是年我歸再通訊，冬日已照堯階蓂。", "書中報我方急擾，我意官下非常經。", "鄱陽胡子遽客死，此翁立爲營輜軿。", "我時方臥生歎息，不覺洒淚霑牀屏。", "恩宜先施士固有，德不期報人誰聽。", "貧猶務德幸今見，死不背義聞前銘。", "又思此翁乃常履，盛譽未足滋芳名。", "有如此翁空試用，慕附始見真羶腥。", "一官未用念鄉里，九鼎自合尊朝廷。", "行看謦欬立事業，下邦震動如雷霆。", "淮田野人分屏置，雙鬢不復當年青。", "乾愁道路阻會面，恨酒不醉嗟長醒。"]'),
('9580dfde-5a09-4d86-88b9-d9736aa37342','寄周秀實','王洋','宋','宋诗','song-poetry','','[]','天目之水停山椒，滙爲雙溪霅與苕。',96,'全唐诗/poet.song.97000.json','["天目之水停山椒，滙爲雙溪霅與苕。", "先生苕上結鄰好，遠得徑山中洞霄。", "浮圖道人支若永，赤城黄冠陸修靜。", "前山後山松柏幃，七盤九盤龍虎鼎。", "山前籃舁過者誰，不是長鬚謝靈運。", "此遊已恨失春期，更待清和閑晝景。"]'),
('ab94dbae-cfa7-4105-99e4-a8f0de70d932','寄廉宣仲','王洋','宋','宋诗','song-poetry','','[]','繞淮邑屋綿千區，畫簷綺棟吹笙竽。',240,'全唐诗/poet.song.97000.json','["繞淮邑屋綿千區，畫簷綺棟吹笙竽。", "冶金合範結樞紐，冰銷水釋無須臾。", "盗前乞死火中走，幾人脫迹逃江湖。", "靜思朋舊若滿目，不取神禍遭囚俘。", "其間善類豈不有，安得變化歸同符。", "平生宣子富心事，先奉白髪攜童孥。", "吳山越山好處所，飯炊香稻歌吳歈。", "我家盗焚先子業，每仗餘德寬天誅。", "悲傷扶病别鄰里，崎嶇僅得來東吳。", "稻梁在世竟何物，與子各隔天一隅。", "近聞詩章不减舊，昔日健筆爭華敷。", "鵷鸞羽翼困州縣，况事糟酒分錙銖。", "隔江搖想思會合，安得兩腳生雙鳬。", "溪邉樵風趁短棹，杖頭明月兼酒壺。", "十漿饋我五漿少，萬事一醉真良圖。"]'),
('bfaf3ba6-4ae3-417e-ae6a-59c8dd44bd3d','寄何子楚','王洋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江如凈練山如幕，人道老何得真樂。',192,'全唐诗/poet.song.97000.json','["江如凈練山如幕，人道老何得真樂。", "寒溫語後再拜前，每得書來話寂寞。", "米鹽細碎百慮寬，自昔仁賢學道難。", "詩書可樂卷胸臆，啼號不救如饑寒。", "去年嘉興租不足，今年山田米炊玉。", "稍須酒肉療枯腸，雪老凌霜不從欲。", "丈夫功名無後先，請翁拭眼看前賢。", "西湖處士竦吟骨，饑乞僧飯紓長年。", "香山居士箕尾客，東坡老子金鑾仙。", "生前千騎不招買，身後一盞同寒泉。", "我意何翁亦如此，髙人不飲無錢水。", "忍饑徹老守清臞，它年配食赤松子。"]'),
('03121a13-4aae-4a96-ae59-a758c08fe608','寄廉仲載','王洋','宋','宋诗','song-poetry','','[]','吾州阿載志尚古，瓦豆鉶羹列尊俎。',192,'全唐诗/poet.song.97000.json','["吾州阿載志尚古，瓦豆鉶羹列尊俎。", "存心淡泊自有餘，過眼浮華俱不與。", "但知古人力可到，不管今人棄如土。", "白頭老子舉嘆嗟，黄口小兒方靳侮。", "淮田平衍真樂所，地遠溪山老清苦。", "天教置子一壑中，句曲海東疏藥圃。", "道中小吏三四家，邑前傍海饒桑麻。", "初疑一飯不可飽，那知歲久今爲家。", "别君十年勞肺腑，遣問寒溫訪兒女。", "一書還我報何如，志老益堅無軟語。", "喜君書語談古人，身雖隔遠心相親。", "扁舟何日載樽酒，共泛清江千尺綸。"]'),
('fa23a1e8-8e83-4a6c-aa15-ab298f6f669b','和秀實寄詩','王洋','宋','宋诗','song-poetry','','[]','去年河南歸故地，今年朔方兵又起。',128,'全唐诗/poet.song.97000.json','["去年河南歸故地，今年朔方兵又起。", "血牲面埋曾幾時，無乃姦盟神不喜。", "嗟爾萬人來遠荒，豈無戰士傷金瘡。", "封疆萬里尚越境，金帛露積猶多藏。", "國家彌文今尚武，已碎銅山鑄銅虎。", "勿矜突騎飲長河，肅慎燕陲吾北土。", "且知成功俱自天，天心可卜因豐年。", "但令三錢博斗米，任爾自枕干戈眠。"]'),
('ff88da9b-9875-41f3-b21e-148ab5ce59d5','和鄭侍郎贈晁倅','王洋','宋','宋诗','song-poetry','','[]','昭德文公百孫子，存者風流今尚幾。',208,'全唐诗/poet.song.97000.json','["昭德文公百孫子，存者風流今尚幾。", "封胡羯末定可人，往往髙吟笑侯喜。", "自期不解世俗書，肯學持竿釣溫水。", "江國蕭條一郡丞，萬事得君無不理。", "窗間五老亦多情，點綴青天一張紙。", "庾樓明月清宵起，夜夜柴桑空故里。", "黄壚日日曲江頭，曲聲日日關山裏。", "使君勿厭簿書煩，解有哀猿醒俗耳。", "詩中能事了幾人，智有三公力任鄙。", "鄭翁老自愛詩情，餘事紛紛不挂齒。", "一篇長韻十四詞，付與鵾弦作桃李。", "我於此事亦何有，盛事與翁傳不朽。", "搖瞻小隊到柴桑，采采黄花薦清酒。"]'),
('3a0eda07-239f-4e74-9af5-9bb1cec5f03a','和張文潛輸麥行寄滁守魏彦成','王洋','宋','宋诗','song-poetry','','[]','琅琊山青讓泉白，上計使君封瑞麥。',128,'全唐诗/poet.song.97000.json','["琅琊山青讓泉白，上計使君封瑞麥。", "田家煮麥燒秸忙，一笑相煎何太迫。", "醉翁亭上綠縹囊，亭前庾積蟠蛇岡。", "家家輸送不掃場，謂取我廩金斗量。", "賸錢沽酒追良伴，使君莫數星霜換。", "願君容我借三年，他日萬錢供一飯。", "山頭飛雉鳴朝日，哺我老翁張射畢。", "誰言田舍漫蹉跎，輕裘年少每相過。"]'),
('d4a269d1-9179-45f4-8f24-823406088695','和謝齊解元見惠','王洋','宋','宋诗','song-poetry','','[]','楚東六邑多秀民，其間達者海內聞。',256,'全唐诗/poet.song.97000.json','["楚東六邑多秀民，其間達者海內聞。", "恨我眼闇不識真，客舍道傍初見君。", "徴君當以文章顯，照眼青錢充萬選。", "胡爲過我誤淮揚，山徑蹊荒費鉏剪。", "龍鍾野老安用哉，偶隨江上浮鷗來。", "簿書魚鳥少閑暇，賦斂戶口煩徴催。", "君今蹉跎壯非少，隴首棲遲雜長嘯。", "上書自薦莫崢嶸，直氣如虹亦奇峭。", "詩書滿腹燈火勤，勿言此道非由人。", "雪霜不厭松骨老，桃李自與春風新。", "短書御袖懷珍具，文字天成絕斤斧。", "一鳴行即駕雷車，萬卷它年勞電母。", "北窗紋簟清如水，青蠅側翅如畏刑。", "側身甘旨寢疾愈，負我此腹何由靈。", "身世浮雲不留處，書生白首談堯禹。", "書窗行几幸虛閑，過我蕭蕭聽夜雨。"]'),
('88062f5f-2196-4610-bc1b-449dec649f58','和監丞去歲賦巖桂','王洋','宋','宋诗','song-poetry','','[]','南方火老不告疲，秋物過半新凉時。',96,'全唐诗/poet.song.97000.json','["南方火老不告疲，秋物過半新凉時。", "姮娥剪花趁時節，新月借色天風吹。", "平生仰望婆娑影，一日坐對連蜷枝。", "異時寒梅憶老伴，過眼春物真群兒。", "人間著名終自疑，但取質幹稱文犀。", "天清夜寂兩相對，萬里不寄長相思。"]'),
('0b73c712-8899-4572-90c1-f7c616884ed0','次韻周秀實見寄長篇','王洋','宋','宋诗','song-poetry','','[]','當年識君恨不早，麗句清髙人縹緲。',208,'全唐诗/poet.song.97000.json','["當年識君恨不早，麗句清髙人縹緲。", "有如商律變初秋，慢綠夭紅俱一掃。", "自親蘭社襲餘芳，歸熱寒爐陋昏棗。", "乃知形骨縱龍鍾，勝處精神不衰老。", "我辭官下曾幾時，囊甑雖貧未空倒。", "女兒索嫁金無餘，錄過知難坐丘嫂。", "人言貴賤在天公，饑飽更須關富媪。", "是事姑置無相聞，瓜蓏分區竹有孫。", "暑風長養遠林密，雨腳幷合前溪渾。", "傷心事慮漸消省，胡不俯仰隨欣欣。", "有時放意枕書臥，亦復倚杖看荷翻。", "殷勤不如偶相遇，過我思同明月尊。", "世間明月向人好，丞不負余余負君。"]'),
('5b2ffe76-93fa-419b-816e-cb360f3161fe','陳長卿以詩見别依韻','王洋','宋','宋诗','song-poetry','','[]','朱弦之琴三人嘆，此曲宜傳廣陵散。',128,'全唐诗/poet.song.97000.json','["朱弦之琴三人嘆，此曲宜傳廣陵散。", "要知太上乃忘情，山上嬰兒是雷電。", "情鍾我輩才力中，路傍野草年年豐。", "原頭火燒去不盡，天外春意來無窮。", "西方真人言可恃，愛斷有情如愛子。", "暮年收足欲依僧，一鉢一缾聊止止。", "西臺仙客傳風流，細說閑情寬我愁。", "此身已分松窗下，衲被無人自𧛾頭。"]'),
('2f77eeab-d6f1-45a3-99c0-03aa2340e145','次韻酬江如晦','王洋','宋','宋诗','song-poetry','','[]','命數奇窮誰與伍，陋巷甘同一命僂。',192,'全唐诗/poet.song.97000.json','["命數奇窮誰與伍，陋巷甘同一命僂。", "怕寒長苦地多風，厭滯每遭星好雨。", "命在天公難自由，若知安命當無憂。", "三斟長得供卯醉，米鹽不辨俱悠悠。", "去年約子招佳客，貧不關心真達伯。", "共貪靜適且過從，追恨窮途昔暌隔。", "二月黄鸝初好音，槐陰柳幄青羅衿。", "杖頭挂錢只買酒，與子作意時登臨。", "此鄉秀野多水石，莫道雲遊不如昔。", "松柏相望泉下人，試數幾人能滿百。", "生前一飽復一眠，得失塵緣俱偶然。", "長年無事頻相見，此自前賢今古傳。"]'),
('f67045a0-e8df-4294-8a24-76b5c24727dd','冬雨不止鄭丈作詩次韻','王洋','宋','宋诗','song-poetry','','[]','海門山外天池雨，來趁沱江打鼉鼓。',128,'全唐诗/poet.song.97000.json','["海門山外天池雨，來趁沱江打鼉鼓。", "望夫臺上濕愁紅，玉斧壇邉沒沙渚。", "貂裘公子思寒侣，佩玉鳴鸞不成舞。", "殷勤舉爵祝雲師，壯士端須氣相許。", "果然晴日照魚梁，鴻雁髙飛肅霜羽。", "西清丈人詩眼髙，師友淵雲僕徐庾。", "興來弄筆起春風，暖日桃花靜初吐。", "且題紅藥寄長沙，不用短衣從猛虎。"]'),
('7bf0cad6-1be5-4f15-a5ad-206fa091c4a6','曾谹父再賦鼓字韻詩再賦一篇','王洋','宋','宋诗','song-poetry','','[]','頭如青山手如雨，十日瓦溝鳴羯鼓。',128,'全唐诗/poet.song.97000.json','["頭如青山手如雨，十日瓦溝鳴羯鼓。", "南城病客偏作愁，魚遊淺釡蛙同渚。", "去年曾困夏畦乾，巫祝陳牲女師舞。", "淮南米賤隔關河，漫道歸期久已許。", "誰同著力破愁城，願備前行插飛羽。", "那知物理自乘除，原思五秉公西庾。", "暑雨祁寒人莫嗟，潔籩滌豆神其吐。", "茅簷生意滿晴川，方信虀腸能抵虎。"]'),
('05a250e6-5dfa-40e5-99ee-25b174e5645f','谹父又賦鼓字一篇復次韻','王洋','宋','宋诗','song-poetry','','[]','魯人小信廉纖雨，大國雷車起三鼓。',128,'全唐诗/poet.song.97000.json','["魯人小信廉纖雨，大國雷車起三鼓。", "堂堂千里埶無前，安用渠彌設三渚。", "使君賓客多英侣，碧玉傾香細腰舞。", "浮花浪蘃爭取憐，醉乞一言終不許。", "有時斗酒詩百篇，猛將腰間掣金羽。", "公家丞相在當年，寒解衣裘饑發庾。", "風流世德今固存，一沐三乾飯三吐。", "生男何用金滿籯，傳家願學文中虎。"]'),
('68332aa1-ff4c-42a0-9885-a9c7d4106149','陳長卿侍郎以玉友末利見餉幷示長言已酬再示一篇再此次韻','王洋','宋','宋诗','song-poetry','','[]','少常仙伯詞翰光，天鵝綬带連天香。',96,'全唐诗/poet.song.97000.json','["少常仙伯詞翰光，天鵝綬带連天香。", "崆峒之人瞻北斗，假面不敢呈西凉。", "浮名於我亦何有，不愛熱官能炙手。", "詩參祖律品度髙，飲遇故人情分久。", "夢中不踏肥馬塵，覺來驚看瓊樹新。", "只愁三疊詩更好，有如恩愛成煩惱。"]'),
('bd14f67a-b5b7-4496-a714-3d58fdc28cb9','劉行簡以自題所畫墨竹詩見示依韻酬之','王洋','宋','宋诗','song-poetry','','[]','買花無謀謀買竹，少陵未必甘同谷。',160,'全唐诗/poet.song.97000.json','["買花無謀謀買竹，少陵未必甘同谷。", "索酒缾空方索茶，陶水終慚錦茵宿。", "我生絕意鶴背錢，犯分猶貪竹間肉。", "穠華穩付桃李春，寂寞頗疑松柏獨。", "自逢劉叟用意好，錢不看囊不羞忸。", "誤身冠在竹皮寬，比酒葉宜衫色綠。", "如翁須著第一流，藝能飽勝三千秋。", "少名數輩列青士，語放干雲封素侯。", "詩成自寫真三絕，筆下琅玕手中鐵。", "若須推轂極清髙，有待朝天寒栗烈。"]'),
('cddff6f0-148f-45ef-9f2f-a40cd29d1a59','又題琳師房劉行簡給事墨竹','王洋','宋','宋诗','song-poetry','','[]','黄門給事二千粟，日割三牲亦應足。',176,'全唐诗/poet.song.97000.json','["黄門給事二千粟，日割三牲亦應足。", "劉翁食俎厭羶腥，千畝渭川期滿腹。", "吳人束簡如束芻，百錢可了三日廚。", "劉翁平生幾兩屐，可能千畝無贏餘。", "獨嫌納腹未可盡，更爲揮毫寫清峻。", "庭空月落千丈長，老柏喬松未髙勁。", "錦綳稚子置腹中，鐵面老人凌遠風。", "此君族類俱得所，多事索此霜髯翁。", "腹饑眼飽徒倥偬，只說饕饞疑作俑。", "何以先生日照盤，更看嬋娟勢飛動。", "琳師從此唯善看，時時更爲通平安。"]'),
('b10cbd89-7b2c-4081-9276-5ac9fda54836','酬政老見贈','王洋','宋','宋诗','song-poetry','','[]','君於取予無乃廉，筆端自許能摧堅。',128,'全唐诗/poet.song.97000.json','["君於取予無乃廉，筆端自許能摧堅。", "摧堅不是老僧事，賈用不售將誰還。", "卻收神觀反初視，先種熟耨終有年。", "早知游息造溟漠，不爲耳目辭嚻喧。", "新詩投我苦褒拂，豈但一讀頭風痊。", "方今冠履尚錯總，不到巨浸非長川。", "姦窮否極會一返，快掃醜類論億千。", "乾清坤夷龍妥帖，與師訪遠同留連。"]'),
('b95bd36a-50a0-4278-8abc-292f166953e8','子楚以二酒合而爲一且效洞庭春色以詩叙其事因奉酬','王洋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','世間百味俱有正，偶失酸醎俱一病。',96,'全唐诗/poet.song.97000.json','["世間百味俱有正，偶失酸醎俱一病。", "須知論酒如論才，軟美悦人嚴太勁。", "韓青居士貴調和，田竇醉時籍福勝。", "寂然二物俱有光，物外洞庭容借香。", "共談已造名理窟，一鞭亟入亡何鄉。", "了知此處有真趣，再聽牖下鳴糟牀。"]'),
('85486e8d-42c4-4a4f-ba33-bbc9d1559ad7','又謝丁執中寄黄龍菜','王洋','宋','宋诗','song-poetry','','[]','吳山草長春暖時，吳人髻中金卷箷。',192,'全唐诗/poet.song.97000.json','["吳山草長春暖時，吳人髻中金卷箷。", "家家饋薦作寒食，貧富豐儉要適宜。", "富兼庶品助取醉，貧得勝具兼哦詩。", "金缾玉筯固華麗，雕章繢句真瑰奇。", "西溪友生居占野，不務結屋留園葵。", "歲時供給不外索，野花滿院蔬本肥。", "今朝懷我寄餘劑，色照匕箸光陸離。", "我慚此腹負此物，但用當肉無它辭。", "舊聞書生飯不足，朝暮虀鹽只充腹。", "勸餐齒頰雜宫商，若比哥舒薦梁肉。", "我歌短章持報辱，恐子詩成費追逐。", "好音佳惠不敢虛，寄以離騷三十六。"]'),
('bfc55157-8301-49f2-b9cf-728454905c89','謝章季萬寄新篘','王洋','宋','宋诗','song-poetry','','[]','面山堂上迎秋色，使君舉酒當月白。',64,'全唐诗/poet.song.97000.json','["面山堂上迎秋色，使君舉酒當月白。", "冰磁雪腕方取憐，看破妖嬈念羈客。", "溪邉從騎何奔忙，溪童疊厭爭窺牆。", "爲公一洗窮愁腸，與公草木同輝光。"]'),
('ffd2e9ec-f842-4b0e-aff1-983a0e70baf4','謝淮南徐巨源寄酒','王洋','宋','宋诗','song-poetry','','[]','淮南有酒誰人得，分餉東吳無酒客。',96,'全唐诗/poet.song.97000.json','["淮南有酒誰人得，分餉東吳無酒客。", "應憐蔀屋寒氣多，倍費行廚春色力。", "人道使君宜在朝，我視使君宜逍搖。", "已聞財計免催索，况是閭閻安教條。", "增秩賜金古亦有，且留使君與淮叟。", "玉隆香火幸留人，年年要飲淮南酒。"]'),
('60b943ce-e3c4-4a42-a7af-692ca3684f7f','子楚持小甑中實以物餉予啗之如芋而味勝曰此黄獨也野人得之故以分遺因感少陵詩率然有作','王洋','宋','宋诗','song-poetry','','[]','君不見野人謀食搜山谷，不似輸錢買金粟。',147,'全唐诗/poet.song.97000.json','["君不見野人謀食搜山谷，不似輸錢買金粟。", "䕷薇細瑣俱見情，豈有靈根不收錄。", "少陵饑走徧九州，命寄長鑱生事足。", "早知雪盛又無苖，擬欲誅求已皸瘃。", "先生蔬食亦易饑，意感鄰夫荷斤斸。", "僅同冠芋又隱藏，遠勝鳬茈適疏縟。", "癡兒且食驚未見，便欲負鋤自捃挶。", "人生留滯誠可憐，坐使百憂寬濕束。", "煩君轉寄與殷勤，晚食何時飽顔蠋。"]'),
('561c76f8-5fcd-448e-80a8-652203f5c440','謝人寄茶','王洋','宋','宋诗','song-poetry','','[]','建溪珪璧能圓方，萬錢一啜難輕償。',144,'全唐诗/poet.song.97000.json','["建溪珪璧能圓方，萬錢一啜難輕償。", "奔騰千里羞貢篚，天應不數金錢綱。", "侯家錢如大國楚，陵肉澠漿推大戶。", "早知煩滯厭膏粱，貴此新香兩三數。", "一朝百室困干戈，在十于今或去五。", "老工既死無典刑，髣髴兒孫追故步。", "誰令遠寄山澤仙，來洗沈疴太華巔。", "攻頑治癬恨無術，且共山頭玉井蓮。", "殷勤更語抱琴客，不用君歸人未眠。"]'),
('1b8bec53-3a69-4b9d-971f-775ca6011c44','嘗新茶','王洋','宋','宋诗','song-poetry','','[]','僧催坐夏麥留寒，吳人未御絺綌單。',160,'全唐诗/poet.song.97000.json','["僧催坐夏麥留寒，吳人未御絺綌單。", "溪雲谷雨作昏翳，思假快飲消沈煩。", "商人遠處抱珪璧，千里來從建溪側。", "報云蟄戶起驚雷，鞭走龍蛇鬼神力。", "色新茗嫩取相宜，留得一年春雪白。", "先修天貢奉珍團，次向人間散春色。", "僧窗虛白無埃塵，碾寬羅細杯勺勻。", "寒泉一種已清絕，况此靈品天香新。", "人間富貴有除折，靜中此味真殊絕。", "誰言僧飯獨蕭條，勝處誰容較優劣。"]'),
('3470292d-7d20-4f26-b084-214479e10e6f','梅花林','王洋','宋','宋诗','song-poetry','','[]','横横直直迷人路，誰知恰是藏春處。',64,'全唐诗/poet.song.97000.json','["横横直直迷人路，誰知恰是藏春處。", "減春一片亦何傷，切莫輕狂作飛絮。", "開正盡數一至七，無雨無風保休吉。", "此遊不記後難尋，聊寫長言記時日。"]'),
('56968e63-bc70-4e67-947e-37b9e081ea1f','王亞之元夕招客庭下紅梅兩株相對盛開','王洋','宋','宋诗','song-poetry','','[]','君家不種通神錢，只種春色留庭前。',224,'全唐诗/poet.song.97000.json','["君家不種通神錢，只種春色留庭前。", "庭前春色誰最妍，二女解珮來江邉。", "沉沉華屋清夜起，火樹銀花月如水。", "自然顔色變韶稚，况乃新粧露初洗。", "春初艷粉秋初蓮，絳綃廣袂羅群仙。", "華清池畔嬌無力，赤鳯樓中困未眠。", "後來更許誰相擬，海棠欲睡薰穠李。", "亦知等級且追陪，格外風流不相似。", "一枝乞得歸茅屋，窗裏銅缾窗外竹。", "不禁清絕意蕭然，大似佳人依草木。", "閬苑花無世上緣，收香還入四禪天。", "明朝風雨催歸去，花月重圓又一年。", "神情邃美膚粗惡，涇渭由來兩清濁。", "要求繪筆盡芳妍，更問尊前老文學。"]'),
('b6785fe9-4a5f-471d-823c-aa24620990f8','詠蠟梅','王洋','宋','宋诗','song-poetry','','[]','江梅已勝猶非似，此外餘芳更堪數。',96,'全唐诗/poet.song.97000.json','["江梅已勝猶非似，此外餘芳更堪數。", "信知風格忌太髙，至此從前難著語。", "世間初無字可誇，且隨顔色稱蠟花。", "醉人香味解禪定，捩眼靜佇辭紛華。", "徐熙畫花只畫神，黄筌細瑣皆逼真。", "要須别花如别畫，只恐此心難付人。"]'),
('035fd0ce-a84f-4093-8b8f-62617fb00c78','席上和鄭顧道燭下海棠','王洋','宋','宋诗','song-poetry','','[]','日長花困眠初熟，故向花前張燈燭。',80,'全唐诗/poet.song.97000.json','["日長花困眠初熟，故向花前張燈燭。", "要教未敢脱羅裳，玉頰長紅黛長綠。", "生憐杏火發中林，無奈桃顋倚修竹。", "爭如錦帳照佳人，一笑嫣然春意足。", "獨疑工部不題詩，端爲風流欠芬馥。"]'),
('1a48c07e-b801-4c38-ac38-df240dcacc1a','題范子濟雙頭芍藥','王洋','宋','宋诗','song-poetry','','[]','煙粘草露珠結窼，淮上人疑春未多。',160,'全唐诗/poet.song.97000.json','["煙粘草露珠結窼，淮上人疑春未多。", "揚州東部紛芍藥，已與天地分中和。", "雙苞一色生同蒂，不是花妖是和氣。", "恩霑雨露力偏饒，來向人間自應貴。", "欄邉鼓徹無奈何，欲留白日誰揮戈。", "練緗聊記舊容質，猶得勝士長吟哦。", "八姨不列真妃上，大姨穩作昭儀様。", "無雙顔貌卻成雙，背立無言似惆悵。", "淮南通守别花眼，曾向花前傾玉琖。", "左看右看俱可人，欲選嬌娘倩誰柬。"]'),
('d012823e-af32-4cde-a530-22f6bacdbc02','戲咏酴醿示邑宰','王洋','宋','宋诗','song-poetry','','[]','芳洲繞郭溪如練，中有風光共流轉。',96,'全唐诗/poet.song.97000.json','["芳洲繞郭溪如練，中有風光共流轉。", "方今得尹日添長，化作河陽一花縣。", "獨龍注雨澆桑麻，芳菲總不爭紛華。", "陽州地遠牡丹少，酴醿晚作留春花。", "君家朱樓映池沼，髙架瓊瑤覆花島。", "欲求此花同一巵，試勸春歸無草草。"]'),
('808e5dab-9b32-4877-900e-d2107df56371','題長興陳朝檜','王洋','宋','宋诗','song-poetry','','[]','蒼髯石根皴皵膚，夭矯枝榦中半枯。',160,'全唐诗/poet.song.97000.json','["蒼髯石根皴皵膚，夭矯枝榦中半枯。", "有如老人自離立，亭亭不用兒孫扶。", "六朝兵戈日相逼，晚向陳隋生道側。", "不知何計脱鋒鋩，三十六中居上策。", "臨春結綺迷仙處，晉王只用陳船渡。", "車書從此稍通津，無乃培根偶堅固。", "百年已長復百年，邑人說自曾髙傳。", "即此兒孫作父祖，只應相對猶依然。", "桃葉桃根即零落，獨保長年應澹泊。", "老人果解復嬰兒，分我一丸童子藥。"]'),
('ce7fab12-307b-450b-9e55-e892f4585bd2','聞鶯','王洋','宋','宋诗','song-poetry','','[]','階前芳草一尺齊，黄鸝始向林間啼。',176,'全唐诗/poet.song.97000.json','["階前芳草一尺齊，黄鸝始向林間啼。", "一聞傳聲人失喜，駑馬並立逢駃騠。", "我思此鳥固妍好，人喜亦緣來不早。", "若令春到便輕遷，厭聽誰憐迹如掃。", "正恐貪歸有近期，三月麗景方舒遲。", "園林上下弄晴晝，羡汝語默真知時。", "秃鳩黑鳥有何惡，每到天陰自酬酢。", "婦翁詛罵兒彈射，恨不身隨羽翰落。", "戒汝一物莫嘆嗟，金衣公子春爲家。", "汝無禍福咎亦淺，况異子鵩當日斜。", "人間美惡有如許，且放黄鸝作嬌語。"]'),
('e2d81f2a-675c-4f4e-aae1-d3989ec173be','鵲巢','王洋','宋','宋诗','song-poetry','','[]','今年結巢不近地，門戶人言解知歲。',160,'全唐诗/poet.song.97000.json','["今年結巢不近地，門戶人言解知歲。", "了知積累功力勞，投伴鳲鳩無此智。", "閭里爭如惡少年，不持彈射操空拳。", "探巢取子盡居室，旁觀禁止無由緣。", "父翔母噪力不加，小雛在手鳴楂楂。", "群兒不逞至若此，增巢不得安生涯。", "漢家春夏禁採捕，詔書非止行三輔。", "可憐科罪掛墻壁，國家禁絕非不預。", "鶉居熙熙太古民，就令闚巢不用嗔。", "同遊飲啄不相害，海上鷗飛不避人。"]'),
('e235e939-c08e-4240-9d9e-2a6185d76e66','大笑鳥','王洋','宋','宋诗','song-poetry','','[]','夜聞慨欬如老翁，若悲若嘯空山中。',224,'全唐诗/poet.song.97000.json','["夜聞慨欬如老翁，若悲若嘯空山中。", "老妻幼子疑問我，此名何物來何從。", "我知此物不常有，豈解招祥宜報咎。", "狐鳴梟噪殆所傳，惟祝停聲聲轉久。", "明朝問人此何鳥，僧言此鳥名大笑。", "幸災樂禍撼主人，僥倖前知非善告。", "我聞此語益悽然，我從坎壈今有年。", "若徒報禍未報死，子之告我何遷延。", "異時白骨滿城郭，此時子笑何人前。", "昔年長沙賈太傅，鵩鳥飛鳴告其故。", "滔滔宇宙鵩安知，應怪達人任來去。", "窗前靈鵲人樂聞，谷鶯上下長和鳴。", "汝曾不效乃效此，汝性險遠知難更。", "汝其更笑我自娯，取酒與爾同歌呼。"]'),
('6cf2404c-89a0-447a-8ef6-6f25cc8fdfdf','晚宿村居','王洋','宋','宋诗','song-poetry','','[]','早趁林鴉泊，荒籬四面同。',48,'全唐诗/poet.song.97000.json','["早趁林鴉泊，荒籬四面同。", "田夫留古意，野水識和風。", "倦僕欺予遠，疲輿念汝功。", "爾嫌冬日促，吾興在寒空。"]'),
('20fbc5f8-a6f9-4df8-8454-b8e3d6b53293','自忻村被酒歸失方竹杖','王洋','宋','宋诗','song-poetry','','[]','我貧難致遠，得此有夤緣。',48,'全唐诗/poet.song.97000.json','["我貧難致遠，得此有夤緣。", "弟爲兄身老，書來意已傳。", "扶衰惟獻直，入手不随圓。", "偶向醉中别，如何不黯然。"]'),
('03ef7504-6e5b-4cc1-91fa-932cb045eef2','夜聞賽神鼓','王洋','宋','宋诗','song-poetry','','[]','坎坎豐年鼓，鱗鱗賽社人。',48,'全唐诗/poet.song.97000.json','["坎坎豐年鼓，鱗鱗賽社人。", "神寬陟降禮，情取笑言真。", "掩豆豚肩薄，分餘福斝頻。", "靈壇本宜夜，考鼓已疏津。"]'),
('31339589-8402-4edd-ad04-3cd5ee69893d','重九日至雲號','王洋','宋','宋诗','song-poetry','','[]','梯山七千丈，接跡上清虛。',48,'全唐诗/poet.song.97000.json','["梯山七千丈，接跡上清虛。", "鐘雜鈞天奏，僧参梵帝居。", "攝衣鵬展背，灑墨雁添書。", "今日登髙眼，平生總不如。"]'),
('a6c2a31e-1776-4e0a-b5f9-0aca165eab96','歲晏書事','王洋','宋','宋诗','song-poetry','','[]','打打鳴窗雨，昏昏带岫雲。',48,'全唐诗/poet.song.97000.json','["打打鳴窗雨，昏昏带岫雲。", "酒寒難作熱，爐冷不成熏。", "梅頰夢中笑，雁聲愁處聞。", "傷懷目前事，細數費云云。"]'),
('6388e05e-f7dc-4e2d-8697-6757fb61ed97','樂飲','王洋','宋','宋诗','song-poetry','','[]','何意親杯杓，初期樂性真。',48,'全唐诗/poet.song.97000.json','["何意親杯杓，初期樂性真。", "若教狂勝德，多被酒忘身。", "談笑交情密，氤氲酒力醇。", "勸酬如錯雜，莫過两三巡。"]'),
('b398d26e-8e1e-4346-8ef7-8f2e3ec66799','安眠','王洋','宋','宋诗','song-poetry','','[]','隨處便隨眠，昬昬息萬緣。',48,'全唐诗/poet.song.97000.json','["隨處便隨眠，昬昬息萬緣。", "魂如雙翅蝶，身在四禪天。", "素飾羅爲幌，芳茵錦作筵。", "心如懷寵辱，未必得安然。"]'),
('c4fa5a6e-873b-4918-83bc-060f973b31ae','觀擊食','王洋','宋','宋诗','song-poetry','','[]','結習慕金僊，西方省問禪。',48,'全唐诗/poet.song.97000.json','["結習慕金僊，西方省問禪。", "時分四季社，報積後生緣。", "念戀期無問，辛勤已有年。", "會緣如有約，此理自誰傳。"]'),
('4b5bb230-2750-48a4-b465-a8db7fa26159','五老峰','王洋','宋','宋诗','song-poetry','','[]','已作人間瑞，飛空老尚豪。',48,'全唐诗/poet.song.97000.json','["已作人間瑞，飛空老尚豪。", "勢分方岳重，名列緯星髙。", "月夜霜添髮，花晨露染袍。", "此翁無奈事，占詠亦徒勞。"]'),
('8ca93416-eaeb-4d78-b22f-ce940cf0c296','遊呂庵偶題','王洋','宋','宋诗','song-poetry','','[]','結屋得勝處，群山簇畫屏。',48,'全唐诗/poet.song.97000.json','["結屋得勝處，群山簇畫屏。", "春城花覆白，野路麥鋪青。", "趁暖鳩呼婦，先時柳化萍。", "年年寒食近，心自歎飄零。"]'),
('fd8c5fc1-9681-4484-9647-9a94173a92c1','無盡藏齋詩  其一','王洋','宋','宋诗','song-poetry','','[]','造物本無盡，貪求乃不公。',48,'全唐诗/poet.song.97000.json','["造物本無盡，貪求乃不公。", "此能随量取，彼亦一無窮。", "水底家家月，窗間處處風。", "要知真宰意，不在有無中。"]'),
('80fcc897-cda0-4a96-bb68-a3b320b01168','無盡藏齋詩  其二','王洋','宋','宋诗','song-poetry','','[]','潢潦集須臾，朝盈夕已除。',48,'全唐诗/poet.song.97000.json','["潢潦集須臾，朝盈夕已除。", "沛然随飽滿，廓爾是清虛。", "金穀輸倉篋，錙銖較簿書。", "不知方寸地，無計脫苞苴。"]'),
('2887f34e-67ad-4750-915c-e6284aceec42','題楊道人庵庵基舊縣邑有廢井存','王洋','宋','宋诗','song-poetry','','[]','空室寄空山，柴門不用關。',48,'全唐诗/poet.song.97000.json','["空室寄空山，柴門不用關。", "虛心觀夢幻，塵世獨清閑。", "舊井前村古，新泉一勺慳。", "蕭條齏粥外，身世有無間。"]'),
('e5dd6d91-7454-485c-a3b7-b5369472a823','寄題韓勉夫枝巢  其一','王洋','宋','宋诗','song-poetry','','[]','萬物各有性，逍搖即自安。',48,'全唐诗/poet.song.97000.json','["萬物各有性，逍搖即自安。", "均鳩得巢易，躁蟹寄身難。", "莫羡髙頭樹，須防静處丸。", "如今洛陽第，誰到子孫看。"]'),
('f061435d-2627-412d-8038-2e9594ff570e','寄題韓勉夫枝巢  其二','王洋','宋','宋诗','song-poetry','','[]','逍搖惟所適，小大浪殊觀。',48,'全唐诗/poet.song.97000.json','["逍搖惟所適，小大浪殊觀。", "溟渤鯤鵬近，藩籬燕雀寬。", "宅髙非遠害，藏密定成安。", "不似南山樹，枝間有弹丸。"]'),
('5c3eb191-ce26-4453-9709-c5038e779733','寄題韓勉夫枝巢  其三','王洋','宋','宋诗','song-poetry','','[]','適時非履險，足分不憂貧。',48,'全唐诗/poet.song.97000.json','["適時非履險，足分不憂貧。", "須信人間世，宜思物外身。", "榮柯堪歎蟻，飽露可憐螓。", "更謝東方朔，能安一老臣。"]'),
('200c948b-918b-4f7f-9808-664534ec6b7e','望山間西際寺','王洋','宋','宋诗','song-poetry','','[]','聞說林間寺，攀蘿一徑斜。',48,'全唐诗/poet.song.97000.json','["聞說林間寺，攀蘿一徑斜。", "有僧眠雪月，無客賞風花。", "丈室虛名在，方袍歲事賒。", "空王無係著，破屋便傳家。"]'),
('1658120c-61a4-4f1b-9bed-5bd362c71f43','三峽橋','王洋','宋','宋诗','song-poetry','','[]','萬馬戰空山，聲馳宇宙間。',48,'全唐诗/poet.song.97000.json','["萬馬戰空山，聲馳宇宙間。", "窺髙增健大，照勇怯孱顔。", "洗石無千古，招僧過一關。", "不知平去易，何似倒流艱。"]'),
('a9278c90-853c-40b4-a47b-4baf22c206ad','此日湖源回展叔穎書頗及往歲經行暨諸同志賞梅花之一笑急景相催又復幾年感而有作因寄叔穎幷呈子楚','王洋','宋','宋诗','song-poetry','','[]','憶昨越溪曲，官梅正發時。',48,'全唐诗/poet.song.97000.json','["憶昨越溪曲，官梅正發時。", "追隨連日飲，酬唱幾篇詩。", "淡佇看人意，清香許自知。", "憑誰將恨寄，爲說鬢成絲。"]'),
('285635e8-9edd-43cc-be44-76ba7cc379ac','寄彦文','王洋','宋','宋诗','song-poetry','','[]','張子蕭條後，空山十五年。',48,'全唐诗/poet.song.97000.json','["張子蕭條後，空山十五年。", "缾無粟遮眼，門有客求錢。", "折補經綸手，拘留褊短緣。", "尋詩有情否，旋送两三篇。"]'),
('1a9aef97-9140-4ce4-a3e6-19c39df74d06','寄夏孝叔','王洋','宋','宋诗','song-poetry','','[]','夏子賦分淺，凄凉不喜看。',48,'全唐诗/poet.song.97000.json','["夏子賦分淺，凄凉不喜看。", "星星脫兵火，歲歲獨饑寒。", "世若均如子，人應不羡官。", "如何閏月底，怨淚亦闌干。"]'),
('7d227131-6fdc-4da4-96a5-df115080a6c7','寄周表卿  其一','王洋','宋','宋诗','song-poetry','','[]','不見秘書久，經時失寄書。',48,'全唐诗/poet.song.97000.json','["不見秘書久，經時失寄書。", "交情猶繾綣，遣訊問何如。", "郡籍藏崑府，班行近玉除。", "自憐無藉在，不敢夢華胥。"]'),
('2f069e82-dfb4-4464-ad8b-20045a1e9a3b','寄周表卿  其二','王洋','宋','宋诗','song-poetry','','[]','簿領正塵埃，天邉驛使來。',48,'全唐诗/poet.song.97000.json','["簿領正塵埃，天邉驛使來。", "姓名傳寶琰，朋舊集蘭臺。", "始望豈及此，故人安在哉。", "曾陪丞相幕，撫事勿驚猜。"]'),
('58f98c79-5921-483d-bd57-4c4e080cd7f1','寄永新元老元書云已辭廣孝復歸禾山白雲矣','王洋','宋','宋诗','song-poetry','','[]','已尚清髙久，須教去住艱。',48,'全唐诗/poet.song.97000.json','["已尚清髙久，須教去住艱。", "強分雲出岫，終放鶴歸山。", "煙带重嵐潤，衣侵霧雨斑。", "輕身如有藥，猶恐費躋攀。"]'),
('5ee4007b-f694-4979-928a-cbf40d3e4093','寄熊叔雅','王洋','宋','宋诗','song-poetry','','[]','天上郎官宿，人間又幾年。',48,'全唐诗/poet.song.97000.json','["天上郎官宿，人間又幾年。", "莫思華轂貴，好種錦溪田。", "山色青盈眼，梅花雪滿川。", "儻因魚雁信，時寄两三篇。"]'),
('7a62e815-5435-4a64-a7f2-5ca02b8d8962','寄陳元載','王洋','宋','宋诗','song-poetry','','[]','太丘傳祖道，作邑興何如。',48,'全唐诗/poet.song.97000.json','["太丘傳祖道，作邑興何如。", "著意招風月，随緣遣簿書。", "吏參名例外，詩託笑談餘。", "偏憶當樽酒，論文意不疏。"]'),
('1e5669ac-009e-46de-967a-84f28f985148','送谹父守光州','王洋','宋','宋诗','song-poetry','','[]','沉戟臥江臯，詩人擁節旄。',48,'全唐诗/poet.song.97000.json','["沉戟臥江臯，詩人擁節旄。", "便期犀結带，安事馬騰槽。", "地入淮源重，霜随雁信髙。", "命書催入覲，應及薦香醪。"]'),
('2284d50e-613f-4035-be0e-c5a80ebaf452','送小劉解元赴試南宫','王洋','宋','宋诗','song-poetry','','[]','衰年稅蕭寺，偶與鳳巢鄰。',48,'全唐诗/poet.song.97000.json','["衰年稅蕭寺，偶與鳳巢鄰。", "萬里刷鮮羽，一鳴驚衆人。", "寒催征騎急，春接賜袍新。", "折取如丹桂，歸榮鶴髮親。"]'),
('736e5aea-fc3b-461c-b539-743731cf3370','寄伯氏','王洋','宋','宋诗','song-poetry','','[]','同占溪名邑，還從佛借居。',48,'全唐诗/poet.song.97000.json','["同占溪名邑，還從佛借居。", "懶便書眼暗，静愛酒杯疏。", "山路閑供課，僧房步當車。", "地爐貪軟火，未得賦歸歟。"]'),
('69777e59-60bd-48bf-95a3-c5adcc2aecec','贈龜峰書記','王洋','宋','宋诗','song-poetry','','[]','本是三山侣，閑爲七澤游。',48,'全唐诗/poet.song.97000.json','["本是三山侣，閑爲七澤游。", "放寬千里目，散遣一身愁。", "詩韻松來往，經窗竹獻酬。", "蒙頭一衲外，萬事看浮漚。"]'),
('4aba9ad1-4650-4d34-9fd3-d5823018e999','贈恭侍者','王洋','宋','宋诗','song-poetry','','[]','學有千門路，恭爲百行初。',48,'全唐诗/poet.song.97000.json','["學有千門路，恭爲百行初。", "謙和人愛重，放傲腹空虛。", "樹大求斤斧，皮柔易卷舒。", "請君觀巨海，萬水豈能如。"]'),
('654f4878-5a2e-4482-bed4-904572be99d2','寄題鄧成之粟庵','王洋','宋','宋诗','song-poetry','','[]','一粟本非慳，縱横透入關。',48,'全唐诗/poet.song.97000.json','["一粟本非慳，縱横透入關。", "要知千種解，不離一塵間。", "透徹通真境，拘留即妄攀。", "須彌聊比喻，未是最髙山。"]'),
('f85c8de3-2b05-4d64-b01a-64096405daae','崇壽印師以詩見惠次韻答之','王洋','宋','宋诗','song-poetry','','[]','客問王居士，如何是半僧。',48,'全唐诗/poet.song.97000.json','["客問王居士，如何是半僧。", "祛緣都未盡，學道又無能。", "身世随忙業，妻兒飽歲登。", "時逢方外士，陪奉說心燈。"]'),
('db827a9e-7ab9-42f8-920a-1a6a3281b1f2','贈辨侍者','王洋','宋','宋诗','song-poetry','','[]','莫恨常無辨，須防辨有魔。',48,'全唐诗/poet.song.97000.json','["莫恨常無辨，須防辨有魔。", "易生人我見，恐爲記持多。", "弄巧它生怨，藏鋒性自和。", "辨心休辨口，方信是婁羅。"]'),
('c1ffc69c-617d-45ea-b654-2a7b8dcc9b26','郊行','王洋','宋','宋诗','song-poetry','','[]','曾問征夫路，名山两日程。',48,'全唐诗/poet.song.97000.json','["曾問征夫路，名山两日程。", "能銷幾兩屐，况值一川晴。", "詩欲謀於夜，雲多不近城。", "暮年塵事有，逐處得心清。"]'),
('8e5e87d4-19b4-462b-a8fd-000ac6799495','次韻曾吉父清明','王洋','宋','宋诗','song-poetry','','[]','暄晴猶苦促，那更遇春霖。',48,'全唐诗/poet.song.97000.json','["暄晴猶苦促，那更遇春霖。", "花色存餘態，春臺得重臨。", "主觴方意展，客意已愁侵。", "是底書生事，時爲洛下吟。"]'),
('d0ccfb93-75c9-4283-980a-b9a1d2e62674','吉父賦南池詩次韻吉父詩雖云紅蕖在眼而獨與白鷺關情蓮上人何望輙戲呈','王洋','宋','宋诗','song-poetry','','[]','水府朝元路，牙分女隊行。',48,'全唐诗/poet.song.97000.json','["水府朝元路，牙分女隊行。", "神仙天外事，風月世間情。", "步有凌波勢，廊無響屧聲。", "何妨沉醉後，珠履小縱横。"]'),
('a7d29403-0a03-433f-954d-55f1c291166c','和曾谹父春半書懷  其一','王洋','宋','宋诗','song-poetry','','[]','節物各自好，春風獨太華。',48,'全唐诗/poet.song.97000.json','["節物各自好，春風獨太華。", "装添山衣錦，零落地鋪花。", "趁課蜂招侣，幽吟鶴自嗟。", "放開平望眼，翠幕不須遮。"]'),
('5a000534-c768-41fc-9218-296ecf9d004c','和曾谹父春半書懷  其二','王洋','宋','宋诗','song-poetry','','[]','敲火開香焙，書齋思漸清。',48,'全唐诗/poet.song.97000.json','["敲火開香焙，書齋思漸清。", "田翁新社長，巢燕舊門生。", "學僻詩無味，心開語見情。", "不愁無樂事，正與物俱榮。"]'),
('8362b2c6-b507-4bee-b0b4-5af4224ba983','和曾谹父春半書懷  其三','王洋','宋','宋诗','song-poetry','','[]','今日前溪好，晴空事事明。',48,'全唐诗/poet.song.97000.json','["今日前溪好，晴空事事明。", "草長顔色重，鳬暖去來輕。", "游女矜髙髻，書生厭短檠。", "懸簞雖過午，碧澗煑芹羹。"]'),
('abc84313-b324-46ac-b9e7-d45d79e4d778','和曾谹父雨中詩  其一','王洋','宋','宋诗','song-poetry','','[]','案體無尊骨，畦丁有賤蔬。',48,'全唐诗/poet.song.97000.json','["案體無尊骨，畦丁有賤蔬。", "鳬鷖憑岸氾，雲海占空虛。", "婦老能論舊，兒癡尚带吳。", "旁人如見問，老子即遷居。"]'),
('cf262cd8-8534-4c26-9426-f073ff02efdc','和曾谹父雨中詩  其二','王洋','宋','宋诗','song-poetry','','[]','往年茅屋水，痕過一由旬。',48,'全唐诗/poet.song.97000.json','["往年茅屋水，痕過一由旬。", "人論方宜夏，心驚已畏春。", "花光如勸酒，山色獨談真。", "補拙供吟課，聊開一笑頻。"]'),
('4df23c0e-450e-45d6-a563-8ae2c2ae09ce','和谹父連雨快晴  其一','王洋','宋','宋诗','song-poetry','','[]','十日雨易滿，一鳩嗚更多。',48,'全唐诗/poet.song.97000.json','["十日雨易滿，一鳩嗚更多。", "開眉初對月，生耳不憂禾。", "兔走無留跡，輪空不受它。", "乘風若歸去，九虎莫誰何。"]'),
('4c9ae12e-e702-45e9-8942-005291533203','和谹父連雨快晴  其二','王洋','宋','宋诗','song-poetry','','[]','官無三不遇，身負四宜休。',48,'全唐诗/poet.song.97000.json','["官無三不遇，身負四宜休。", "無意花迷眼，唯因月上樓。", "役車懸白地，社鼓祭黄收。", "何事關心切，逢人說有秋。"]'),
('43a9564c-c581-43ee-b002-90c22150acef','和春雨韻  其一','王洋','宋','宋诗','song-poetry','','[]','客路元來促，春情本自長。',48,'全唐诗/poet.song.97000.json','["客路元來促，春情本自長。", "送愁誰納款，遣癖又無方。", "失性陪飄雪，凋顔自染霜。", "吟君春雨句，縈拂爲牽腸。"]'),
('8ff4789a-c442-4b23-99e4-f7f8309d548d','和春雨韻  其二','王洋','宋','宋诗','song-poetry','','[]','榮辱一時夢，浮生百種心。',48,'全唐诗/poet.song.97000.json','["榮辱一時夢，浮生百種心。", "愚因難化穏，懶爲不治深。", "分退何須卜，貪髙每自斟。", "須君說情話，澤畔欲行吟。"]'),
('aa3ec8ff-dc38-4a83-9ade-d18fc2d748b7','和曾谹父中秋前六日二詩  其一','王洋','宋','宋诗','song-poetry','','[]','怪底暑風淺，明珠照座寒。',48,'全唐诗/poet.song.97000.json','["怪底暑風淺，明珠照座寒。", "鋪張平地錦，峻激急流灘。", "吟諷千篇過，更移一字難。", "少留明艷句，拂拭菊花間。"]'),
('ac4cee9a-3eca-4b8e-aba7-a0e7b099b89f','和曾谹父中秋前六日二詩  其二','王洋','宋','宋诗','song-poetry','','[]','誰將兔消長，用卜月陰晴。',48,'全唐诗/poet.song.97000.json','["誰將兔消長，用卜月陰晴。", "三穴由來暗，中天本自明。", "金盆如未滿，玉斚爲誰傾。", "處處随人去，長空不送迎。"]'),
('68fd80b8-6d51-4fd2-a21c-70737c9fc698','和曾谹父促叢珍之集','王洋','宋','宋诗','song-poetry','','[]','布穀但催耕，鳴鳩不喚晴。',48,'全唐诗/poet.song.97000.json','["布穀但催耕，鳴鳩不喚晴。", "風添前夜急，花負去年盟。", "老去歡娛少，茶多懷抱清。", "論文一樽酒，何日向人傾。"]'),
('5054f705-77c1-4930-ae47-9eb754942012','和谹父留别  其一','王洋','宋','宋诗','song-poetry','','[]','細雨關山路，梅花識舊鄰。',48,'全唐诗/poet.song.97000.json','["細雨關山路，梅花識舊鄰。", "擁旄紅額騎，抺杖白頭民。", "故國悲王粲，年光送李頻。", "搖瞻解鞍馬，正是小陽春。"]'),
('83a681fe-8aa5-4f6d-8bd5-61eaecc8e977','和谹父留别  其二','王洋','宋','宋诗','song-poetry','','[]','臥鼓開亭障，斯人久晏然。',48,'全唐诗/poet.song.97000.json','["臥鼓開亭障，斯人久晏然。", "宣王思采芑，羊祜保新邉。", "妙手傳干葉，鰲頭控六連。", "使君雙眼闊，塞草不供憐。"]'),
('3e3ad8ae-c9b8-4d73-b58f-0ce476438287','和谹父問訊吉父  其一','王洋','宋','宋诗','song-poetry','','[]','北園依梵庋，東郭據梧桐。',48,'全唐诗/poet.song.97000.json','["北園依梵庋，東郭據梧桐。", "鶴並千年骨，詩傳一祖風。", "有愁添鬢白，無藥駐顔紅。", "臺上秋期句，思君類渴虹。"]'),
('41237a19-47e7-401d-9648-7cb98b256655','和谹父問訊吉父  其二','王洋','宋','宋诗','song-poetry','','[]','困臂知三折，攻頑費七旬。',48,'全唐诗/poet.song.97000.json','["困臂知三折，攻頑費七旬。", "不聞覆杯水，能救一輿薪。", "俗傲軒轅聖，巫誇越女神。", "百年勾漏術，觸處白頭新。"]'),
('da165a0d-63e3-47a5-8397-34648b032506','和鄭丈戲贈谹父','王洋','宋','宋诗','song-poetry','','[]','生疏僮僕賤，顔色病妻同。',48,'全唐诗/poet.song.97000.json','["生疏僮僕賤，顔色病妻同。", "定有明人眼，真煩壽乃翁。", "仙曹歌法曲，詞伯綴秋風。", "不是人間譜，霓裳墮月中。"]'),
('b2c9a1f1-c97a-4cc5-a4f1-4f72948e0900','和谹父答鄭丈','王洋','宋','宋诗','song-poetry','','[]','鄭圃潛仙客，陳留繼阮生。',48,'全唐诗/poet.song.97000.json','["鄭圃潛仙客，陳留繼阮生。", "掄才俱道用，昌譽得詩鳴。", "未解侯三接，先歌玉六成。", "篇篇多痩骼，疑似带銅聲。"]'),
('80c4160d-6c7e-484b-bbcb-8d4c7c85d47a','和鄭貳卿别賦','王洋','宋','宋诗','song-poetry','','[]','病逐秋風至，年隨塞草衰。',48,'全唐诗/poet.song.97000.json','["病逐秋風至，年隨塞草衰。", "家如百年夢，身入四愁詩。", "北焙聯圭璧，南薰潤岳池。", "齋房多勝事，可但滑琉璃。"]'),
('b950b1a6-3444-453d-8d95-ef1c22f2c136','又和新字','王洋','宋','宋诗','song-poetry','','[]','清秋移象緯，皎月一更新。',48,'全唐诗/poet.song.97000.json','["清秋移象緯，皎月一更新。", "巖桂陪賓席，黄花似故人。", "詩參工部正，道入醉鄉醇。", "搖指靈山下，長衫賽社神。"]'),
('3815dade-42a8-4ef3-a52b-5c1d5e415c72','和伯氏示兒姪','王洋','宋','宋诗','song-poetry','','[]','屋僻唯宜静，櫳疏巧受寒。',48,'全唐诗/poet.song.97000.json','["屋僻唯宜静，櫳疏巧受寒。", "衾光宵獻白，爐火晝無丹。", "潦倒投僧梵，依稀似宰官。", "一錢不停蓄，卻喜布囊寬。"]'),
('89426f2b-7895-4691-bea2-8facd780f7b2','和方簽判詩乞芭蕉於教官','王洋','宋','宋诗','song-poetry','','[]','緗帙文書展，青衿懷抱空。',48,'全唐诗/poet.song.97000.json','["緗帙文書展，青衿懷抱空。", "花前添翠幕，句後捲詩筒。", "雲重能鄣暑，身輕不礙風。", "相期三伏日，借此作寒叢。"]'),
('46fd3591-6f9d-45a7-be7d-e671122e404b','和酬鄭共老','王洋','宋','宋诗','song-poetry','','[]','萬事易瓦裂，故人情未休。',48,'全唐诗/poet.song.97000.json','["萬事易瓦裂，故人情未休。", "殷勤一詩語，辛苦百端求。", "書託峰頭雁，人随海上鷗。", "終期斷湖尾，卜築共良謀。"]'),
('244199c8-c06b-4e8d-8a7d-8087608091f1','江如晦以詩送蕙一本以詩謝之','王洋','宋','宋诗','song-poetry','','[]','幽芳不弄妍，人意自推先。',48,'全唐诗/poet.song.97000.json','["幽芳不弄妍，人意自推先。", "比德人間願，同心事外賢。", "香因天力與，名自楚詞傳。", "桃李多顔色，相逢不敢鮮。"]'),
('651dcf41-c863-40d2-8d30-00b9a733fb15','謝筠守趙從周寄黄蘖中洲茶','王洋','宋','宋诗','song-poetry','','[]','道院文書静，傳籖報兩衙。',48,'全唐诗/poet.song.97000.json','["道院文書静，傳籖報兩衙。", "籠山疏藥圃，祖寺摘春茶。", "珍品少爲貴，佳名遠更誇。", "要知清白德，盞面看浮花。"]'),
('e9bb08cb-99e4-4bda-98b4-f7e96f671e61','李丞相挽章  其一','王洋','宋','宋诗','song-poetry','','[]','名紀三朝重，身居百辟師。',48,'全唐诗/poet.song.97000.json','["名紀三朝重，身居百辟師。", "華夷占用否，進退繋安危。", "見夢英靈在，成功命數奇。", "出師身已老，垂淚憶當時。"]'),
('75656944-9d9d-409d-be74-6475dd128be0','李丞相挽章  其二','王洋','宋','宋诗','song-poetry','','[]','風雲扶日月，堯舜正衣裳。',48,'全唐诗/poet.song.97000.json','["風雲扶日月，堯舜正衣裳。", "壯烈周方叔，從容漢子房。", "鼎彛酬鉅業，典禮賁幽光。", "悵望它山遠，千年綠野堂。"]'),
('157c3282-8289-4954-ac39-3ff5c39f238c','王侍郎挽章','王洋','宋','宋诗','song-poetry','','[]','位列仙官籍，名随海賈船。',48,'全唐诗/poet.song.97000.json','["位列仙官籍，名随海賈船。", "前旌衝瘴雨，拱木兆新阡。", "玉骨埋黄土，金聲麗藻編。", "兩行懷舊淚，灑向菊花天。"]'),
('f6bbf22c-9013-4084-8a12-83b320fe537d','曾侍郎挽章  其一','王洋','宋','宋诗','song-poetry','','[]','道盛當堯日，名髙嗣聖初。',48,'全唐诗/poet.song.97000.json','["道盛當堯日，名髙嗣聖初。", "人推金鼎望，帝念玉樓居。", "舊典尊王迹，傳家教孝書。", "崇文華夏事，澹泊寄情疏。"]'),
('a30b85a1-b1b4-43da-899e-ff34d06a0344','曾侍郎挽章  其二','王洋','宋','宋诗','song-poetry','','[]','未下蒲輪詔，先驚柏府寒。',48,'全唐诗/poet.song.97000.json','["未下蒲輪詔，先驚柏府寒。", "九州方鎮節，萬里使華冠。", "歲晚一庵密，風流百世寬。", "永懷函丈訓，泣涕自汍瀾。"]'),
('488169ab-4174-4d4b-80a0-3c185c906c32','呂尚書挽章  其一','王洋','宋','宋诗','song-poetry','','[]','古遠儒冠拙，時忙壯士尊。',48,'全唐诗/poet.song.97000.json','["古遠儒冠拙，時忙壯士尊。", "百年難保命，萬里未歸魂。", "身後塞翁馬，生前廷尉門。", "悲笳咽遺恨，行矣不須論。"]'),
('f7feaf81-91f9-4eba-8a5a-d6b790843afd','呂尚書挽章  其二','王洋','宋','宋诗','song-poetry','','[]','載纘世基日，群公扈聖年。',48,'全唐诗/poet.song.97000.json','["載纘世基日，群公扈聖年。", "伏蒲鳳岡上，持節雁峰邉。", "外閫風猷遠，中臺出處全。", "履聲傷易盡，不得輔中天。"]'),
('31b52372-fe15-44b4-9e7f-19e28ac7b0f2','呂尚書挽章  其三','王洋','宋','宋诗','song-poetry','','[]','四海詘伸勢，安危俯仰殊。',48,'全唐诗/poet.song.97000.json','["四海詘伸勢，安危俯仰殊。", "犬戎蟠洛邑，晉鄙握兵符。", "楊李生同烈，髙秦死異區。", "誰如雙劍化，義烈一門俱。"]'),
('c47fd980-09dd-4828-84f3-8f2202d6ca2d','挽向倅','王洋','宋','宋诗','song-poetry','','[]','襟量塵埃外，功名慷慨中。',48,'全唐诗/poet.song.97000.json','["襟量塵埃外，功名慷慨中。", "人懷不滿望，身有未全功。", "逸氣猶驚眼，馳光息轉蓬。", "蕭條古原上，松柏自號風。"]'),
('34412661-ecb3-4ef2-acad-c79f2ac7f010','挽程伯禹  其一','王洋','宋','宋诗','song-poetry','','[]','盛德師千古，髙名滿四方。',48,'全唐诗/poet.song.97000.json','["盛德師千古，髙名滿四方。", "位登三品貴，身任百夫防。", "公在衣冠重，公歸遠近傷。", "哀榮終始事，褒典在徽章。"]'),
('b42e8f60-0ad1-4fd4-8bf1-714b2b6c2618','挽程伯禹  其二','王洋','宋','宋诗','song-poetry','','[]','待問盈朝日，群生解褐初。',48,'全唐诗/poet.song.97000.json','["待問盈朝日，群生解褐初。", "太常方奏第，儒舘下除書。", "出入勞忠藎，襟懷自卷舒。", "如何奪公早，不得待懸車。"]'),
('c4338ba5-dae1-4522-a2b6-955ad38dbeff','挽焦適道寺丞  其一','王洋','宋','宋诗','song-poetry','','[]','學有千箱富，言無一字欺。',48,'全唐诗/poet.song.97000.json','["學有千箱富，言無一字欺。", "脊令慈孝地，兄弟急難詩。", "頌美觀名士，傳家付令兒。", "平日磨玷缺，此理上天知。"]'),
('181f04fe-3c9f-48a2-8666-fee503a20d4a','挽焦適道寺丞  其二','王洋','宋','宋诗','song-poetry','','[]','亹亹談多緒，諄諄意恐傷。',48,'全唐诗/poet.song.97000.json','["亹亹談多緒，諄諄意恐傷。", "行孤違衆好，誠盡是君長。", "生死人間異，經營地上忙。", "静中如有趣，遺譽自芬芳。"]'),
('6b7ebf79-df70-4a4c-bd11-053d97e092b9','挽喬民瞻','王洋','宋','宋诗','song-poetry','','[]','世德書青史，榮名在本朝。',48,'全唐诗/poet.song.97000.json','["世德書青史，榮名在本朝。", "如何元士葬，不得大夫招。", "惆悵空蕭瑟，秋風正泬寥。", "搖看古原上，松柏暮蕭蕭。"]'),
('52b64958-5abf-4592-8544-119442f25075','臧夫人挽詩二首  其一','王洋','宋','宋诗','song-poetry','','[]','奕世流芳遠，傳家慶有餘。',48,'全唐诗/poet.song.97000.json','["奕世流芳遠，傳家慶有餘。", "簪荆蘋薦潔，曳練寶粧疏。", "載德光門閥，成名振里閭。", "如何裁半日，一旐向輀車。"]'),
('d3793c5f-6ea2-4d50-8e11-54a6c0d794b7','臧夫人挽詩二首  其二','王洋','宋','宋诗','song-poetry','','[]','義有臧侯者，寥寥幾百年。',48,'全唐诗/poet.song.97000.json','["義有臧侯者，寥寥幾百年。", "豈唯君子貴，亦有女郎賢。", "寧捨家藏富，先歸宿貸錢。", "自然難到處，風烈是家傳。"]'),
('3d1d6399-608f-4e31-873f-ac2d09f9c914','哭嘉彦','王洋','宋','宋诗','song-poetry','','[]','釋蹻淮西土，平生質勝文。',48,'全唐诗/poet.song.97000.json','["釋蹻淮西土，平生質勝文。", "形模笑婦女，術業富丘墳。", "客路酒歡喜，官曹名放紛。", "銀章猶斷壠，餘事付青雲。"]'),
('42269bad-d799-44b1-a35a-d4c30ae08014','哭李清卿侍郎  其一','王洋','宋','宋诗','song-poetry','','[]','薄壘氈車咽，危臺斥候移。',48,'全唐诗/poet.song.97000.json','["薄壘氈車咽，危臺斥候移。", "孤忠萬夫望，獨許寸心知。", "義動乾坤正，生殘日月虧。", "南山竹有限，難盡泣君辭。"]'),
('827c419d-7a5d-4d79-a5c9-39123696dec5','哭李清卿侍郎  其二','王洋','宋','宋诗','song-poetry','','[]','金石雖云久，精誠諒不移。',48,'全唐诗/poet.song.97000.json','["金石雖云久，精誠諒不移。", "但期忠可仗，誰謂敵難知。", "籲極天應泣，難諶信有虧。", "報君如不盡，禍福定虛辭。"]'),
('eddf5050-fa22-4bcb-a737-746ffbc4608d','哭李清卿侍郎  其三','王洋','宋','宋诗','song-poetry','','[]','皇澤淹時久，人懷孝可移。',48,'全唐诗/poet.song.97000.json','["皇澤淹時久，人懷孝可移。", "不應當後患，端恨未前知。", "國破言猶壯，身亡義不虧。", "青編照千古，昭代有芳辭。"]'),
('052a8a63-35b4-4ae8-8ca1-e6a0e864cbdc','哭李清卿侍郎  其四','王洋','宋','宋诗','song-poetry','','[]','眼見盟城築，俄聞鐘鼎移。',48,'全唐诗/poet.song.97000.json','["眼見盟城築，俄聞鐘鼎移。", "憶君還抆淚，胡爾大無知。", "名擅千鈞重，功無一簣虧。", "殺身因主辱，獨爲實前辭。"]'),
('35ffacd7-53cc-4a89-a222-787665c8bf6f','賦紅梅','王洋','宋','宋诗','song-poetry','','[]','爲怯清宵短，然膏約凭欄。',48,'全唐诗/poet.song.97000.json','["爲怯清宵短，然膏約凭欄。", "頰疑西子醉，花誤北人看。", "點露燕支破，啼粧風雨殘。", "莫嫌翠袖薄，猶得護春寒。"]'),
('fe810b98-465c-4a48-82b0-f95e8dce063b','初螢','王洋','宋','宋诗','song-poetry','','[]','腐草漸時澤，翩然變化功。',48,'全唐诗/poet.song.97000.json','["腐草漸時澤，翩然變化功。", "分光衣作炫，乘暗力排空。", "自表因存照，雖多不暖風。", "偶緣膏火盡，得到兀窗中。"]'),
('b2582702-835a-4d13-b2a9-f3a6d168cdc3','病眼','王洋','宋','宋诗','song-poetry','','[]','飛花無復數，遇物輙成雙。',48,'全唐诗/poet.song.97000.json','["飛花無復數，遇物輙成雙。", "書畫疏幽閣，屏幃戀北窗。", "懶開辭俗客，寫望憶秋江。", "椒菊供朝餌，猶須發酒缸。"]'),
('b30c61b4-4c22-462d-8b79-b5f39082605f','和陳長卿五人同集韻','王洋','宋','宋诗','song-poetry','','[]','受廛均宅畝，寸矩漸經營。',120,'全唐诗/poet.song.97000.json','["受廛均宅畝，寸矩漸經營。", "湖泛輕舟遁，峰排老岫嶸。", "牧之推上第，吏部絕心兵。", "列爵分全服，和聲奏大庭。", "暫辭侯馬貴，聊撫帝弦清。", "黍在穀爲重，雞緣德勝鯖。", "無功須滿斗，仲雅計全升。", "顧我窮難送，如公福正榮。", "惠施書已富，陵也句初鳴。", "徑醉相逢樂，亡聊一洗平。"]'),
('c7e14e39-c253-468b-87dc-8d1587b085d4','省題泰帝鼓瑟','王洋','宋','宋诗','song-poetry','','[]','雅樂聞琴瑟，相因泰昊前。',72,'全唐诗/poet.song.97000.json','["雅樂聞琴瑟，相因泰昊前。", "朱絲疑雜奏，素女減哀弦。", "破竹符終合，分魚目不全。", "所餘裁五五，再續未綿綿。", "損益時皆有，虧成理或然。", "茫茫千古意，漢帝自誰傳。"]'),
('37994efe-d236-4ca2-8c44-431efb077c20','新隱四首 古亭','王洋','宋','宋诗','song-poetry','','[]','四注飛簷略勢寬，江湖城郭得同看。',64,'全唐诗/poet.song.97000.json','["四注飛簷略勢寬，江湖城郭得同看。", "縱饒縮地神僊術，長要移人視聽難。", "僊子月多呈顧兔，女兒牀晚欲棲鸞。", "使君飲散攅燈火，長怕浮空水面寒。"]'),
('57c60c5a-b32c-4a8c-b304-84945e5690b0','新隱四首 新亭','王洋','宋','宋诗','song-poetry','','[]','題輿記榻得髙賢，寄意真同物象先。',64,'全唐诗/poet.song.97000.json','["題輿記榻得髙賢，寄意真同物象先。", "收拾蕪莱成院落，𠟃量邉幅占風煙。", "登臨斗覺今知要，雲水從斯入畫傳。", "斫竹洞門無鎖鑰，時攜客枕一慵眠。"]'),
('9c55cbd2-ea80-4ddf-b531-a21f7532a81a','新隱四首 荷池','王洋','宋','宋诗','song-poetry','','[]','香分净社色專城，冠盖如雲照乘眀。',64,'全唐诗/poet.song.97000.json','["香分净社色專城，冠盖如雲照乘眀。", "曉露一粧秋艷曳，凉風吹月夜經營。", "戲荷魚小波紋近，戞玉船低笑響輕。", "聞說笠乾燒供夜，無邉華燭競歡迎。"]'),
('bab01d43-f189-413b-a440-57b51f201384','新隱四首 南峰','王洋','宋','宋诗','song-poetry','','[]','郭外溪流溪外山，山峰長在白雲間。',64,'全唐诗/poet.song.97000.json','["郭外溪流溪外山，山峰長在白雲間。", "開懷幸對百年友，屈指何憂一日顔。", "煩燠尚寬秋占野，林巒欲暮鳥知還。", "夜歸猶隔溪橋水，不記重門欲上關。"]'),
('e16e3aa6-e9d5-45a6-9315-d5d0ab0d125e','上元二首  其一','王洋','宋','宋诗','song-poetry','','[]','火樹銀花起夜煙，驂驔朱幰競駢闐。',64,'全唐诗/poet.song.97000.json','["火樹銀花起夜煙，驂驔朱幰競駢闐。", "一千戶外開金鎖，十二里中然玉蓮。", "何日行宫祠太一，誰從摩詰問諸天。", "歌臺且喜宜正月，柳岸今年勝去年。"]'),
('7ea32217-d4ad-4341-a499-cf4092e0e364','上元二首  其二','王洋','宋','宋诗','song-poetry','','[]','誰將膏粥飯蠶師，輕薄兒童覓綵衣。',64,'全唐诗/poet.song.97000.json','["誰將膏粥飯蠶師，輕薄兒童覓綵衣。", "遊騎但知誇艷麗，祠門直莫歎寒微。", "東城南陌春迷眼，逐馬隨車醉未歸。", "莫怪老翁閑坐久，鬅鬙燈火照柴扉。"]'),
('b2bed642-b3a1-4696-8173-c7864292c15c','和尹少稷上元  其一','王洋','宋','宋诗','song-poetry','','[]','年少輕衫競彩霄，老翁心地寄參寥。',64,'全唐诗/poet.song.97000.json','["年少輕衫競彩霄，老翁心地寄參寥。", "照人燈火成何事，示我威儀貴不恌。", "閑卻剪刀尋斷夢，任隨錦轂縱華鑣。", "固知行樂承恩澤，亦喜豐年樂一瓢。"]'),
('8955eb4a-e57b-4445-9114-b30547bc04e0','和尹少稷上元  其二','王洋','宋','宋诗','song-poetry','','[]','故人飄泊少相逢，喜向雲間得士龍。',64,'全唐诗/poet.song.97000.json','["故人飄泊少相逢，喜向雲間得士龍。", "少日功名鵬萬里，長年風月酒千鍾。", "已知吟思才難敵，自嘆簪皤髪已童。", "聞說玉池蓮十丈，相期摘實上髙峰。"]'),
('7c94cbaa-afd8-4bfc-a420-7dbed36db32c','三月三十日','王洋','宋','宋诗','song-poetry','','[]','寂寞餘紅點翠衣，曉風捲盡絮花飛。',64,'全唐诗/poet.song.97000.json','["寂寞餘紅點翠衣，曉風捲盡絮花飛。", "避人黄鳥遠山去，背我青春此日歸。", "倦舞柳條猶作意，侵階芳草不知非。", "老無年少尋芳恨，一榻清風展翠帷。"]'),
('e563ea14-a02e-4f28-8ae8-ff1d6d176b76','喜雨','王洋','宋','宋诗','song-poetry','','[]','去年秋日百神求，歲度春風尚未優。',64,'全唐诗/poet.song.97000.json','["去年秋日百神求，歲度春風尚未優。", "補貼稀疏三日澤，栽培飽滿一年秋。", "已乾桑柘蠶多飽，待濟舟航水接流。", "雲雨筭来多少力，夕陽處處聽漁謳。"]'),
('133942e0-18d9-47af-9e72-274c1a6cf8c4','苦寒','王洋','宋','宋诗','song-poetry','','[]','平侵爐火易成灰，穏閉齋扉不用開。',64,'全唐诗/poet.song.97000.json','["平侵爐火易成灰，穏閉齋扉不用開。", "浩蕩晚風隨伴起，遲回前雪待朋来。", "他無雜念專思酒，縱有交情敢憶梅。", "静坐不聞簫鼓急，土牛莫是送春回。"]'),
('a025b0ce-d8db-47d7-a55a-f8ddbc6d0e98','和苦寒韻','王洋','宋','宋诗','song-poetry','','[]','秋容落落轉頭空，誰與元冥競長雄。',64,'全唐诗/poet.song.97000.json','["秋容落落轉頭空，誰與元冥競長雄。", "侵剝老條無硬對，栽培玉樹是家風。", "漫誇鶴骨飛饒健，彊說龜腸語轉工。", "對此只宜常袖手，眀年春物共君同。"]'),
('74037ad6-81c1-42c9-87fb-8f0c7a91ddf0','一夕大風偶成呈諸兄簡士修思遠','王洋','宋','宋诗','song-poetry','','[]','狂飈一夜撼天關，徹曉陽烏勢未還。',64,'全唐诗/poet.song.97000.json','["狂飈一夜撼天關，徹曉陽烏勢未還。", "早恨餘寒誇老健，重憐新物損朱顔。", "强留殘火如相別，已典春衣不可攀。", "料得雲端風背上，融和那肯似人間。"]'),
('57896556-e7a4-457c-a8d9-3ebaad8bfd37','雪晴','王洋','宋','宋诗','song-poetry','','[]','牆角寒梅未試鹽，熬波何事被凝嚴。',64,'全唐诗/poet.song.97000.json','["牆角寒梅未試鹽，熬波何事被凝嚴。", "解教爐火添餘燼，似妬陽烏到短簷。", "幽谷但期回暖律，交光何用映疏簾。", "朝来一掃窮陰處，先照群峰最上尖。"]'),
('ad1d6a58-24c7-4427-be94-e4d52ae1f3f5','冬節日疾作不能親祀事但具禮不拜戲作示內','王洋','宋','宋诗','song-poetry','','[]','他鄉易感歲時侵，病入衰骸苦不禁。',64,'全唐诗/poet.song.97000.json','["他鄉易感歲時侵，病入衰骸苦不禁。", "臥聽兒孫羞栗脯，倦依爐火只愁吟。", "房無肥腯牲三俎，幕有馨香酒數斟。", "苦與黔婁分等級，尚爲吾婦莫傷心。"]'),
('f56156cf-29e0-470e-9e45-e86b8ff78d90','歲除前一日病中作','王洋','宋','宋诗','song-poetry','','[]','客寄他年又一鄉，椒花隨興飲杯長。',64,'全唐诗/poet.song.97000.json','["客寄他年又一鄉，椒花隨興飲杯長。", "病疑寒健銷陰脉，愁怯花寬笑酒觴。", "去住自知身老大，經過長恨歲窮忙。", "眼前兒女陪懽悦，年少從教各自彊。"]'),
('1407641d-4ff6-4377-b833-18ac589f3c82','病痰有感','王洋','宋','宋诗','song-poetry','','[]','氣堙風貫血行遲，運用工夫了不知。',64,'全唐诗/poet.song.97000.json','["氣堙風貫血行遲，運用工夫了不知。", "待盡生涯蠶作繭，就衰榜様髪繰絲。", "稍因對酒頭先眩，未是多行力早疲。", "更若尋思年少戲，如何不送老頭皮。"]'),
('2475669b-bba6-4b2b-b867-432c2cc0cdbc','琴枕','王洋','宋','宋诗','song-poetry','','[]','琢石髹池省練弦，寂塵不動五音全。',64,'全唐诗/poet.song.97000.json','["琢石髹池省練弦，寂塵不動五音全。", "應嫌雜奏妨人樂，正可常攜對客眠。", "投倦乍如傾耳聽，起醒惟欠籟聲傳。", "舞雲家範升堂席，寂寞依稀萬古賢。"]'),
('b45fa5c4-7230-4e6f-84ac-fd57a198bfb8','闢方丈地供香火','王洋','宋','宋诗','song-poetry','','[]','全家共寄一庵中，庖滌因連奥胙通。',64,'全唐诗/poet.song.97000.json','["全家共寄一庵中，庖滌因連奥胙通。", "穴不容身銜窶籔，芥分餘地結齋宫。", "幾甌粥借鄰僧飯，一瓣香尋祖佛風。", "十笏比邱居有限，包羅眷屬要無窮。"]'),
('b6e047f5-67f5-492b-a203-bd3fcb9dd988','從鄰庵求浴','王洋','宋','宋诗','song-poetry','','[]','口多屋褊分張窄，堂室齋庖約略分。',64,'全唐诗/poet.song.97000.json','["口多屋褊分張窄，堂室齋庖約略分。", "春服乍成宜穏貼，浴盂無處集蘭薰。", "供分清净如霑露，氣郁芬芳過食芹。", "自引一杯歸路穏，從教歌詠不成文。"]'),
('0490e395-46ef-49c9-984f-a5745078ebd7','閑中即事','王洋','宋','宋诗','song-poetry','','[]','蟲有鋋矛獸有戈，江中飛燕避淘河。',64,'全唐诗/poet.song.97000.json','["蟲有鋋矛獸有戈，江中飛燕避淘河。", "點紅翡翠飛傳錦，展翅鸕鷀臥晒蓑。", "絕境芳菲時喚客，隔林機杼夜催梭。", "平生約略閑忙境，到底閑中得較多。"]'),
('465de756-0fed-4082-92cb-6024c72c2e98','即事','王洋','宋','宋诗','song-poetry','','[]','官閑久愧叨祠廩，身幸真堪學種瓜。',64,'全唐诗/poet.song.97000.json','["官閑久愧叨祠廩，身幸真堪學種瓜。", "月給郡倉三斛米，日尋山路一川花。", "盤空婢去催燒笋，爐暖妻来趁焙茶。", "閲盡鄰僧閑况味，官供粥飯勝僧家。"]'),
('6d417292-6259-460f-a9eb-151a399b8b7e','和邵堯夫韻示兒侄','王洋','宋','宋诗','song-poetry','','[]','言貴安徐行貴常，與人平淡勿相傷。',64,'全唐诗/poet.song.97000.json','["言貴安徐行貴常，與人平淡勿相傷。", "莫貪順路行時快，到了回思見去長。", "克已定知天降福，害人只是自貽殃。", "長教言行樞機密，此外虚心不用防。"]'),
('36829711-8c79-4257-8b4f-8ab0636ff3e7','觀僧作藏會','王洋','宋','宋诗','song-poetry','','[]','推崇社首勸来人，歲結春緣轉寶輪。',64,'全唐诗/poet.song.97000.json','["推崇社首勸来人，歲結春緣轉寶輪。", "誅及米鹽知産罄，事干生死見誠真。", "歸持福壽憑懷劵，時及暄和謂有神。", "安得勸農官考古，春秋禮射莫辭頻。"]'),
('b6b84b96-f50b-4fd7-8274-82cc4e15b72b','從伯氏攜稚孺游保慶即事','王洋','宋','宋诗','song-poetry','','[]','提攜未便即歸山，暫扣僧園且暫閑。',64,'全唐诗/poet.song.97000.json','["提攜未便即歸山，暫扣僧園且暫閑。", "歲晚東君顔色近，霜晴寒意有無間。", "前溪雨後渾通路，荒戍人歸不上關。", "笻竹一枝天正暖，卻嫌飛鳥倦思還。"]'),
('5313a199-b4fa-41ff-a583-d82dd90f91cc','壬戌立冬十月十一日陪路文周朋攜禔祖同訪後山道人庵道人出就庵烹茶庵外採菊拾橡實以歸偶成即事  其一','王洋','宋','宋诗','song-poetry','','[]','倦緣閑景散閑情，人未歸庵戶不扃。',64,'全唐诗/poet.song.97000.json','["倦緣閑景散閑情，人未歸庵戶不扃。", "試撥柴煙尋宿火，旋添泉水洗茶瓶。", "黄花采采盈衣袖，橡實離離傍短萍。", "何日一邱藏曲折，與君同伴劚青冥。"]'),
('4afe2e9f-8447-4f6e-8ace-da5d58a6cfd5','壬戌立冬十月十一日陪路文周朋攜禔祖同訪後山道人庵道人出就庵烹茶庵外採菊拾橡實以歸偶成即事  其二','王洋','宋','宋诗','song-poetry','','[]','養生無欠亦無餘，種竹圈籬草結廬。',64,'全唐诗/poet.song.97000.json','["養生無欠亦無餘，種竹圈籬草結廬。", "鑿地覓甘分乳脉，鉏田得實飽新蔬。", "壁間數本空王像，架上都無養性書。", "我自病来能晚食，從今緩步當安輿。"]'),
('19657770-f01f-4357-8e37-5e7a822979f5','己巳三月十二日陪凌季文游水南陳氏園次壁間徐眀叔韻','王洋','宋','宋诗','song-poetry','','[]','不慚衰白照溪光，清晝穿梁訪野堂。',64,'全唐诗/poet.song.97000.json','["不慚衰白照溪光，清晝穿梁訪野堂。", "物外風煙多喜客，人間草木亦宗王。", "浮花競作争新艷，近侍全收殿後香。", "秉燭便須期醉賞，勝饒吳榜起漁榔。"]'),
('ecc51465-5608-454b-ab1f-71f76439b93d','同吳周朋髙虞卿尋泉憩積暑下庵','王洋','宋','宋诗','song-poetry','','[]','繚繞尋泉遠步遲，倦逢籬外敞庵扉。',64,'全唐诗/poet.song.97000.json','["繚繞尋泉遠步遲，倦逢籬外敞庵扉。", "門前竹長雲垂舞，巖下泉甘雪未飛。", "景物偏幽緣舍小，茶香看客爲僧稀。", "相公房舍添人否，擬灌春園住翠微。"]'),
('4d330e42-082f-40e4-a325-f7ef0ccae70b','陪方何諸人後庵謝客紀事','王洋','宋','宋诗','song-poetry','','[]','後山客館報聘禮，野寺僧甌當酒茶。',64,'全唐诗/poet.song.97000.json','["後山客館報聘禮，野寺僧甌當酒茶。", "雲未散屯知候雨，溪唯貪漲不容沙。", "草間翁仲今塵跡，雪後江梅是故花。", "一掃窮愁無不足，方知謀醉是生涯。"]'),
('05af38bf-3aec-4777-8dc3-2f64af938675','同張德和遊沈道士庵','王洋','宋','宋诗','song-poetry','','[]','上春甲子送窮日，早破煙扉令節求。',64,'全唐诗/poet.song.97000.json','["上春甲子送窮日，早破煙扉令節求。", "指點葆光僊侣洞，招期南極老人遊。", "龜前香火木稱士，堂後交蟠石作牛。", "我恐上真無碍意，使君息慮是清修。"]'),
('ee1b7e0a-2722-46cc-ae19-1cadd5fd8e1c','題僧邀遊梅和庵','王洋','宋','宋诗','song-poetry','','[]','地接山腰舍遶泉，豐堂巍殿勢蟬聯。',64,'全唐诗/poet.song.97000.json','["地接山腰舍遶泉，豐堂巍殿勢蟬聯。", "非禪非律三百輩，有圃有場千畝田。", "中坐獨尊司獄佛，几前雜事地行仙。", "若無生死驚愚俗，正恐齋廚亦悄然。"]'),
('6b99ca64-84d1-4571-bc9d-716f78b2d086','中冬下澣一日陪方丈訪客因過向氏園亭有感','王洋','宋','宋诗','song-poetry','','[]','前疏水竹界桑麻，桃李畦分小徑斜。',64,'全唐诗/poet.song.97000.json','["前疏水竹界桑麻，桃李畦分小徑斜。", "山數青黄人住久，路排藜藿客行賒。", "雲寒煙合入長暝，梅懶春催未放花。", "聞道蒼頭長兒女，主人遊宦不還家。"]'),
('d5cc92f4-8e6c-4b0b-9410-696ced3f92c0','去秋過吳江臞翁園亭追作','王洋','宋','宋诗','song-poetry','','[]','水接舟航陸接鞍，忙中光景靜中看。',64,'全唐诗/poet.song.97000.json','["水接舟航陸接鞍，忙中光景靜中看。", "無窮宇宙規模遠，出格池臺制度寬。", "一水斯須分靜僻，四橋繚繞照波瀾。", "擬分風月知何日，且趁鱸魚整釣竿。"]'),
('1deaf32e-bb97-455d-b1a2-1eda11ad6fc2','聞沈氏小亭欲往主人辭出先聞趙丞相嘗遊','王洋','宋','宋诗','song-poetry','','[]','籬橫地狹曲相裁，倦掃殘花長綠苔。',64,'全唐诗/poet.song.97000.json','["籬橫地狹曲相裁，倦掃殘花長綠苔。", "連榭似聞兼靜雅，閑情暫欲洗塵埃。", "料將春色供家用，那有芳尊爲客開。", "怪見門前少車馬，多因只要相公來。"]'),
('908e69df-6d0b-4cff-9fa8-5aed0ecd6120','至法海寺','王洋','宋','宋诗','song-poetry','','[]','天有陰晴地有艱，一山如隔萬重山。',64,'全唐诗/poet.song.97000.json','["天有陰晴地有艱，一山如隔萬重山。", "偶逢冬少三餘雨，况置身無百慮關。", "歲熟役車容借客，閑来崖寺可開顔。", "懸危既免逢饑虎，又得休公半偈還。"]'),
('8915a234-ba3a-40f4-b34b-e6d04e15b416','又題祤禪客龜峰圖','王洋','宋','宋诗','song-poetry','','[]','不用丹青染素翰，疏煙分染碧雲端。',64,'全唐诗/poet.song.97000.json','["不用丹青染素翰，疏煙分染碧雲端。", "一千里地境中鎮，三十六峰天半寒。", "巢露葉中呈物象，濾羅带畔疊林巒。", "人間此是清凉藥，時向塵中爲展看。"]'),
('00c366f2-c5fd-480c-8959-63be10c93c90','留題翠峰','王洋','宋','宋诗','song-poetry','','[]','陶朱山下金僊宅，云是當年故相家。',64,'全唐诗/poet.song.97000.json','["陶朱山下金僊宅，云是當年故相家。", "去國豈知傳貎象，扁舟端自訪煙霞。", "平吳霸越功何在，弔古傷今事可嗟。", "早是登臨饒客淚，幾行征雁落寒沙。"]'),
('ed6a664f-41f8-404d-927e-8faff503d306','歸雁亭次東坡韻','王洋','宋','宋诗','song-poetry','','[]','平時何憚不成歸，猶向亭前送雁飛。',64,'全唐诗/poet.song.97000.json','["平時何憚不成歸，猶向亭前送雁飛。", "弱羽可堪繒繳密，寒沙那得稻粱稀。", "燕吳真恐音書絕，城郭猶疑今古非。", "若爲哀鳴相原野，依隨豈惜共卑微。"]'),
('45f50745-a87b-46e9-8308-59efc0923e51','煮泉亭','王洋','宋','宋诗','song-poetry','','[]','昔人来去本無情，世自貪賢爲結亭。',64,'全唐诗/poet.song.97000.json','["昔人来去本無情，世自貪賢爲結亭。", "身在雲間天繚繞，夢無塵事性疏靈。", "撐腸大欠五千卷，拄眼今看萬疊青。", "景物卻因閑處見，前賢詩已說丁寧。"]'),
('4a26209c-c51a-49d8-a1ca-190443d445e1','題鄰僧房壁','王洋','宋','宋诗','song-poetry','','[]','南窗日暖北窗凉，時節頻移意自長。',64,'全唐诗/poet.song.97000.json','["南窗日暖北窗凉，時節頻移意自長。", "半坐蒲團七家飯，兩函經卷一爐香。", "身辭塵雜元無累，人見朝昏卻自忙。", "雪屋夜寒燈火暗，蕭條氣味合鄰墻。"]'),
('40a1226e-04e7-468f-92e6-555be72b1dc0','題齊政壁','王洋','宋','宋诗','song-poetry','','[]','柳經沈雨舞腰慵，鶯入新陽曲未終。',64,'全唐诗/poet.song.97000.json','["柳經沈雨舞腰慵，鶯入新陽曲未終。", "照徑自藏塵外境，憎花不愛世間紅。", "橋分知爲前溪改，寺遠因尋別路通。", "更待薰風日清永，長歌呼就滿蒲風。"]'),
('907e5a8a-9957-4c54-a2bf-4cfd08b723e6','題懷玉上方','王洋','宋','宋诗','song-poetry','','[]','蟠踞峰巒面勢多，天分雄望鎮關河。',64,'全唐诗/poet.song.97000.json','["蟠踞峰巒面勢多，天分雄望鎮關河。", "足開煙霧鵬垂翼，手摘星辰月轉波。", "問法舊聞裴相國，傳經今見李維摩。", "禪徒到此棲塵跡，方信青雲路可過。"]'),
('fe788a39-d8d7-4b1c-b110-b3814d36ec5e','無盡藏齋','王洋','宋','宋诗','song-poetry','','[]','矯首層霄俯翠巒，虚空不住骨毛寒。',64,'全唐诗/poet.song.97000.json','["矯首層霄俯翠巒，虚空不住骨毛寒。", "古今等是無窮境，風月何嫌取意看。", "巢寄一枝惟自足，風摶九萬豈知難。", "與君同入逍搖境，方信乾坤宇宙寬。"]'),
('9aa90d1e-9098-4581-9f91-4411be37b17e','題龍溪橋','王洋','宋','宋诗','song-poetry','','[]','放出清泉疊舊蹊，行人但渡不沾泥。',64,'全唐诗/poet.song.97000.json','["放出清泉疊舊蹊，行人但渡不沾泥。", "與君暫濯紅塵足，留我長澆白玉畦。", "千古蜿蜒潛窟穴，他年頭角上雲梯。", "信知法海津梁別，認作東林是虎溪。"]'),
('413cfc88-ad11-4e42-a2a8-bb09a8702912','思徑山','王洋','宋','宋诗','song-poetry','','[]','汲引凡軀駕海鰲，恢張奇壮自僊曹。',64,'全唐诗/poet.song.97000.json','["汲引凡軀駕海鰲，恢張奇壮自僊曹。", "九龍獻宅金園貴，四衆添花寶範髙。", "身住四禪觀夢境，眼收萬象比秋毫。", "經行會遇登臨處，勉策筋骸莫歎勞。"]'),
('c2e6d67a-9867-49da-9132-94c2adb03394','僧自臨安歸說遠信','王洋','宋','宋诗','song-poetry','','[]','幻形變滅困須臾，晚景尤驚歲易徂。',64,'全唐诗/poet.song.97000.json','["幻形變滅困須臾，晚景尤驚歲易徂。", "滿目交遊多故物，傷心風雨對今吾。", "逝波昨日方追霅，覆簣今朝又過衢。", "旋打青梅新薦酒，且須耳熱聽歌呼。"]'),
('30313bc7-bccf-4aec-9587-e8ef0d8990bb','與鄭侍郎','王洋','宋','宋诗','song-poetry','','[]','還卻天官尺一書，清時有味保懸車。',64,'全唐诗/poet.song.97000.json','["還卻天官尺一書，清時有味保懸車。", "公年尚壮去何蚤，古道誰言今不如。", "南部方開新榜麗，西清人說舊遊疏。", "半簪白髪無拘束，不用黄精自掃除。"]'),
('3ba33cdb-c404-4cdf-9145-ad45627d4ed4','還龜溪成拙句呈給事劉兄','王洋','宋','宋诗','song-poetry','','[]','上春日暮暮春頭，翠淺芳濃草色柔。',64,'全唐诗/poet.song.97000.json','["上春日暮暮春頭，翠淺芳濃草色柔。", "五十日天和暖候，一帆風地往来舟。", "棋神得雋驚逢敵，酒病尋醫尚入流。", "只有風流動文采，較量沈謝亦推劉。"]'),
('071fc3b2-b389-4df2-b51c-a16efb7edebe','發龜溪道中','王洋','宋','宋诗','song-poetry','','[]','欲窮幽勝遠紛華，頻向晴空漾釣槎。',64,'全唐诗/poet.song.97000.json','["欲窮幽勝遠紛華，頻向晴空漾釣槎。", "霞雜鳬群歸趁浦，雪飛鷺陣宿投沙。", "山連空秀嫌花雜，樹遠多圖怕霧遮。", "莫怪故園歸未得，爲貪入手好煙霞。"]'),
('b6521aef-1c40-49b0-b378-e1e4bd1a3088','餘干見游存誠','王洋','宋','宋诗','song-poetry','','[]','世家兄弟久隨流，少不同嬉老宦游。',64,'全唐诗/poet.song.97000.json','["世家兄弟久隨流，少不同嬉老宦游。", "身似舟空長信浪，官如萍轉偶同州。", "論文共酌三斟酒，决勝公圍一局楸。", "三百里溪眀月夜，得心情處便相求。"]'),
('a2dfa7c9-fe01-49cb-b8ac-595e075ee01c','二月九日訪仰之聞德茂與婿鄧叔厚蚤作逍搖溪濱歎而成詩','王洋','宋','宋诗','song-poetry','','[]','貪閑心不受囂塵，六十年餘自在身。',64,'全唐诗/poet.song.97000.json','["貪閑心不受囂塵，六十年餘自在身。", "愛水愛山三益友，如冰如玉兩閑人。", "言無拘畏詩多健，酒借豪華力有神。", "聞說山中丞相語，與君心事最相親。"]'),
('dd5b5f45-1b42-46be-bce7-a93299400b36','德茂以兩小篇報聘再成一章','王洋','宋','宋诗','song-poetry','','[]','不著冠纓不洗塵，不将忙事擾閑身。',64,'全唐诗/poet.song.97000.json','["不著冠纓不洗塵，不将忙事擾閑身。", "舍前自舊存三徑，林下如今見一人。", "八節灘聲泉喚客，數枝墨戲竹傳神。", "前生定是張公子，一見相從意自親。"]'),
('c74ec808-ffca-4998-8b66-52116c7d420d','昭武舊同僚見過','王洋','宋','宋诗','song-poetry','','[]','半生辛苦路漫漫，八月樵川類破酸。',64,'全唐诗/poet.song.97000.json','["半生辛苦路漫漫，八月樵川類破酸。", "官事到時初覺易，人情別後始知難。", "苦無私惠違情重，儉用官錢得謗寬。", "聞說東園墻下柳，有時顰蹙念前官。"]'),
('d9b0d6b2-d889-4a54-886b-937ca696a193','祝舜俞拉希言見訪富春赤亭山居','王洋','宋','宋诗','song-poetry','','[]','巖腹紆盤一徑通，故勞都騎載郫筒。',64,'全唐诗/poet.song.97000.json','["巖腹紆盤一徑通，故勞都騎載郫筒。", "先生舊負連城價，校尉今煩一箭工。", "著雪老山清刻骨，添梅官路巧迎風。", "此身終觧渾無事，共樂郊原浩蕩中。"]'),
('aa84d9ff-9e68-47a4-a3ec-56c4d4d070e9','因同年見過有感','王洋','宋','宋诗','song-poetry','','[]','青似春袍色發榮，變移朱紫漸催成。',64,'全唐诗/poet.song.97000.json','["青似春袍色發榮，變移朱紫漸催成。", "琴因聲急弦難續，流爲池平水不鳴。", "神耗恐因驚寵辱，心閑請爲減經營。", "貧門二十年中夢，貴賤存亡歎友生。"]'),
('cd7233cf-5551-460f-b476-69e7d346f7be','喜仰之至','王洋','宋','宋诗','song-poetry','','[]','江東幕客江西吏，各是年過五十時。',64,'全唐诗/poet.song.97000.json','["江東幕客江西吏，各是年過五十時。", "一去塵中勞夢約，重来物外有心期。", "煙中艇子花前酒，竹裏棋聲月下詩。", "景物不妨俱是舊，只添須髪白如絲。"]'),
('70987028-92b8-47b9-8f55-afa336f2115c','喜二曾一鄭歸','王洋','宋','宋诗','song-poetry','','[]','木葉黄時拂兩輪，馬前同看蚤梅春。',64,'全唐诗/poet.song.97000.json','["木葉黄時拂兩輪，馬前同看蚤梅春。", "舊游踏徧千山月，新歲迎歸三老人。", "梳洗樓前酬鵲語，琴書案上掃蛛塵。", "只愁鳯詔聯翩下，又指天邉問去津。"]'),
('c2478424-6e9d-46a3-ab15-edf4cee0ae80','雪中赴季文集','王洋','宋','宋诗','song-poetry','','[]','會因率集轉殷勤，掃徑寬迎陌上春。',64,'全唐诗/poet.song.97000.json','["會因率集轉殷勤，掃徑寬迎陌上春。", "恩解訊書紅粉戀，寒消酒力玉花新。", "盤堆青菜春回律，甌泛瓊珠月借神。", "浮白自憐偏戶小，醉歸全是夢中人。"]'),
('0b5ebdc9-f041-432e-a81a-fc18d23b76a5','慈相寄居同院何子感寒僕已似安何尚未出似聞亦以冬至人事動搖疾困未觧亦成小詩','王洋','宋','宋诗','song-poetry','','[]','分僧半坐小僧圓，世故猶尋未了緣。',64,'全唐诗/poet.song.97000.json','["分僧半坐小僧圓，世故猶尋未了緣。", "小大不同俱示病，窮通有命只聽天。", "愁看藥裹推難去，願見香醪騁不前。", "比若扶頭卻因酒，甘言苦口定誰賢。"]'),
('a21c8607-36b9-4763-b9f4-84764bde3472','乞桃竹於令尹','王洋','宋','宋诗','song-poetry','','[]','小結幽棲事静便，爲無花竹不成村。',64,'全唐诗/poet.song.97000.json','["小結幽棲事静便，爲無花竹不成村。", "在君百里鳴弦地，成我一方濯錦園。", "按鼓威名知破膽，乞花詩句是招魂。", "桃溪竹徑如成趣，柳岸梅洲卻未論。"]'),
('8c1a544d-2d30-4f51-b440-7aa6af4f30bc','還許推詩軸','王洋','宋','宋诗','song-poetry','','[]','好在東安解戍瓜，歸懷珠璧慰生涯。',64,'全唐诗/poet.song.97000.json','["好在東安解戍瓜，歸懷珠璧慰生涯。", "翰林詞伯夢中草，粉署仙郎筆下花。", "已間簫韶還政俗，未持旌節自光華。", "邦人故眼應回首，詩律傳芳又一家。"]'),
('5b0fb97d-0e99-4655-9365-c6586cfc932d','德茂晨起折花花葉中眼上横衝痛楚因詩戲之','王洋','宋','宋诗','song-poetry','','[]','幽事相關略未衰，蚤乘芳露折鮮枝。',64,'全唐诗/poet.song.97000.json','["幽事相關略未衰，蚤乘芳露折鮮枝。", "如何引惹傷殘處，莫是喜歡攀折時。", "人見花容如苦愛，花隨人意亦相欺。", "須知恩愛成煩惱，將命拚花欲怨誰。"]'),
('8c83f599-c191-4294-9bb7-42bbcc9e1d28','近聞直學馮子容以家産中丘乘之賦作詩戲之','王洋','宋','宋诗','song-poetry','','[]','千古茫茫不可攀，仲尼日月照儒關。',64,'全唐诗/poet.song.97000.json','["千古茫茫不可攀，仲尼日月照儒關。", "生前冷竈七日火，身後遺基十萬間。", "寧許富兒通市籍，只求賢士共歡顔。", "那知等級輸邦計，亦許顔原見一班。"]'),
('3264750f-6605-4f23-a601-8fafc5c830e0','萬席仰之許酒以詩戲之','王洋','宋','宋诗','song-poetry','','[]','花色芳菲酒力醲，坐中上客索千鍾。',64,'全唐诗/poet.song.97000.json','["花色芳菲酒力醲，坐中上客索千鍾。", "朱陳繾綣論前契，子婿牽聯本一宗。", "獨爲棋髙能假借，衆同酒伴不阿容。", "歸来醉倒終無怨，此會心知不易逢。"]'),
('0acc9c6f-c83f-417b-b63b-8ea45487c35f','中春二十四日集仰止書室德茂仰止何彦亨彦發鄧叔度與僕凡六人至夜格夫自外歸就邀同飲仰之是日對棋屢敗德茂任直時出罵坐語叔厚謂子可以詩紀事否翌日戲成長句','王洋','宋','宋诗','song-poetry','','[]','朱何王鄧偶婆娑，晚喚寒甥共笑歌。',64,'全唐诗/poet.song.97000.json','["朱何王鄧偶婆娑，晚喚寒甥共笑歌。", "煩惱少因知事少，吃拳多爲打人多。", "竹間豪逸多酣暢，斗下文章競拂摩。", "好是花時省風雨，勸人沈醉是天和。"]'),
('0bea1eee-87d2-458f-8573-531aabc2ecfd','飲葉氏園亭不覺大醉欹側詩呈德茂仰之幷簡二何','王洋','宋','宋诗','song-poetry','','[]','步入青冥路渺賒，嵐光四面照流霞。',64,'全唐诗/poet.song.97000.json','["步入青冥路渺賒，嵐光四面照流霞。", "相公未許歸旄節，旅客還来看物華。", "不獨衰腸難勝酒，自緣饑眼乍看花。", "醒来知免汙茵席，端爲勤勞不駕車。"]'),
('79acf7d5-b070-41fe-9b7e-80a2ab70f86b','葉雲仰之謂予有隨軒人作無真詩誚仰之用前韻','王洋','宋','宋诗','song-poetry','','[]','方外參軍語太賒，文茵萋斐錦成霞。',64,'全唐诗/poet.song.97000.json','["方外參軍語太賒，文茵萋斐錦成霞。", "齊王國印封韓信，古戰場文識李華。", "不醉而狂烏變白，以無爲有舌生花。", "嚇燕書自何人計，只問軍中李左車。"]'),
('54dab0fa-c077-425f-a369-e50fcf4c01cd','詩去得仰之報云旦夕必有風雨可速相過走筆以詩報之','王洋','宋','宋诗','song-poetry','','[]','幕下郎君發醉吟，多如年少惜花心。',64,'全唐诗/poet.song.97000.json','["幕下郎君發醉吟，多如年少惜花心。", "預排尊俎當長日，不遣韶華負寸陰。", "種竹澗邉排坐石，讀書窗下聽鳴禽。", "草堂更要添顔色，剩借鄰花酒淺斟。"]'),
('08292ef9-8974-4dd2-b9e8-08f8c094ba3d','葉伯宇和霞字韻詩再作一篇','王洋','宋','宋诗','song-poetry','','[]','全似襄陽隱士家，只添靈照减丹霞。',64,'全唐诗/poet.song.97000.json','["全似襄陽隱士家，只添靈照减丹霞。", "晚山寒後猶疑遠，古木春来亦好華。", "酒似竹光仍鬬綠，人如錦面更添花。", "了知衰病輕成醉，不但流涎向麴車。"]'),
('73fa719f-6466-4a2c-8b07-c5ce9b415a3a','慶吉父七十作詩叙事','王洋','宋','宋诗','song-poetry','','[]','里有仁賢慶壽祺，不辭沽酒典春衣。',64,'全唐诗/poet.song.97000.json','["里有仁賢慶壽祺，不辭沽酒典春衣。", "年髙且作尋常看，身健須誇七十稀。", "頰火欲燒雙鬢白，心閑時笑昔年非。", "誰誇八座天人貴，丞相星垣動紫薇。"]'),
('89f99ffc-5b61-48e1-9b17-39d3b8cb3117','帥相生日二首  其一','王洋','宋','宋诗','song-poetry','','[]','季管吹灰木落洲，天邉初獻鷫鸘裘。',64,'全唐诗/poet.song.97000.json','["季管吹灰木落洲，天邉初獻鷫鸘裘。", "邦家襲慶因前續，嶽瀆儲精自幾秋。", "秦晉君臣三晝接，安危將相百年求。", "休論辟穀功成後，只恐功名卒未休。"]'),
('e4bd4990-05ca-4d3d-a57b-34b6c14a71da','帥相生日二首  其二','王洋','宋','宋诗','song-poetry','','[]','整頓乾坤不作難，指間造化自多端。',64,'全唐诗/poet.song.97000.json','["整頓乾坤不作難，指間造化自多端。", "恩回春色華風暖，氣接秋天絕塞寒。", "勛爵已增彛鼎重，功名長入畵圖看。", "錫公難老無他騐，但覺斯民欲再安。"]'),
('8b2946d4-b026-41be-a1f8-b727c0e30c38','贈吉父得女孫','王洋','宋','宋诗','song-poetry','','[]','兩兩星階協泰符，爲嘉瑞雪勝維旟。',64,'全唐诗/poet.song.97000.json','["兩兩星階協泰符，爲嘉瑞雪勝維旟。", "果如靈照翁何恨，若比倉公數有餘。", "慰眼臘娘能剪綵，他年楊惲競傳書。", "斷無豪客窺籬落，爲自從前免破除。"]'),
('3d5981a0-1581-4a68-bf46-ae09a94cf52e','賀張帥  其一','王洋','宋','宋诗','song-poetry','','[]','日邉春早帝王州，花滿黄堂壽醑浮。',64,'全唐诗/poet.song.97000.json','["日邉春早帝王州，花滿黄堂壽醑浮。", "世有忠嘉扶社稷，天教勳業紹箕裘。", "稀鳴枹鼓無偷市，屢敞圜扉罷慮囚。", "已佩荷囊簉鴛鷺，徑将名姓覆金甌。"]'),
('861ee75d-9261-473e-861e-29f04763f5ac','賀張帥  其二','王洋','宋','宋诗','song-poetry','','[]','門弧瑞靄曉氤氲，天錫熙朝社稷臣。',64,'全唐诗/poet.song.97000.json','["門弧瑞靄曉氤氲，天錫熙朝社稷臣。", "京兆赭裾多譽久，甘泉紫櫜眷恩新。", "一城和氣仁風晝，萬口歡聲壽語春。", "端有泮宫蓮幕士，願隨綠水泛通津。"]'),
('fccfe48b-9b8b-4054-9768-2632201e182a','喜楊致平登第','王洋','宋','宋诗','song-poetry','','[]','寄隱湖頭知幾年，聊城一箭自家傳。',64,'全唐诗/poet.song.97000.json','["寄隱湖頭知幾年，聊城一箭自家傳。", "便須結組隨鴛鷺，暫捨銜杯樂聖賢。", "鶴到九霄方展翅，驥行萬里可加鞭。", "隔江阻預金錢會，夢到君家社甕邉。"]'),
('9cccbc52-efc3-4726-87f1-a163a889a2e9','得周朋詩云方爲秘府書石渠二字作詩美之','王洋','宋','宋诗','song-poetry','','[]','斡地排天力有餘，倚空金榜稱華胥。',64,'全唐诗/poet.song.97000.json','["斡地排天力有餘，倚空金榜稱華胥。", "快兼長史三杯酒，優重中郎六體書。", "字向雲門增瑞彩，思從天陛聽傳臚。", "集賢學士相驚顧，應道揮毫古不如。"]'),
('c3f86c13-ac91-4a63-82ea-08747c0d526a','李叔飛以僕遷官遠貺長牋而僕在江亭無以報謝因寄小詩','王洋','宋','宋诗','song-poetry','','[]','知君才氣本無雙，拭目曾看古戰場。',64,'全唐诗/poet.song.97000.json','["知君才氣本無雙，拭目曾看古戰場。", "華蕚風流今不墜，文章光焰自應長。", "詩從古錦傳家法，身□花塼是故鄉。", "它日萬錢供日費，更期粟賤致時康。"]'),
('74e4a7d6-86e4-4311-aa8a-62fde17959da','舊聞邵叟名今識面目於詩句字畫中輙取二詩賡之他日會面亦舊相識也  其一','王洋','宋','宋诗','song-poetry','','[]','平生髙士苦交疏，今見音容向一書。',64,'全唐诗/poet.song.97000.json','["平生髙士苦交疏，今見音容向一書。", "輸子一籌吟未足，加人數等盍分餘。", "供陪應覺山勞費，捃拾不教春自如。", "詩社便宜張客館，莫教游士嘆無魚。"]'),
('fa89ac52-19f9-415f-883a-262c4bbce701','舊聞邵叟名今識面目於詩句字畫中輙取二詩賡之他日會面亦舊相識也  其二','王洋','宋','宋诗','song-poetry','','[]','曾參古佛問忘情，可笑初孩尚未名。',64,'全唐诗/poet.song.97000.json','["曾參古佛問忘情，可笑初孩尚未名。", "自刻肺肝誠定誓，時牽耳目又寒盟。", "苦無藉在書窗冷，賴有知憐風竹聲。", "好是鼻端消息在，夜堂流水夢初成。"]'),
('4ec74303-c107-4c46-aefb-453c9aae2482','送猶子之官武昌','王洋','宋','宋诗','song-poetry','','[]','旅情傷別意何如，霜打枯茄雪未除。',64,'全唐诗/poet.song.97000.json','["旅情傷別意何如，霜打枯茄雪未除。", "門戶難成攻事業，殷勤暇日讀詩書。", "須憐白髪親今晚，莫恃朱顔氣有餘。", "要使仇香非醉尉，定知不負武昌魚。"]'),
('4d5d0574-7206-4b7d-9df5-ff4b12b64bd0','孫叔誠宰南峰過信道諸暨舊事往往能記拙詩因以送之','王洋','宋','宋诗','song-poetry','','[]','身是前身念已非，相逢喜誦昔年詩。',64,'全唐诗/poet.song.97000.json','["身是前身念已非，相逢喜誦昔年詩。", "心情似舊知無日，兒女成行能幾時。", "政事便須書竹帛，功名何必問蓍龜。", "旴江風月時分寄，免隔關河費夢思。"]'),
('dd7c1341-98a1-476f-ad4a-142c27920534','送蒋推官歸宜興','王洋','宋','宋诗','song-poetry','','[]','陽羡溪頭蟹正肥，三年客盡拂征衣。',64,'全唐诗/poet.song.97000.json','["陽羡溪頭蟹正肥，三年客盡拂征衣。", "一川秋色背人去，滿路黄花迎子歸。", "未用解裝榮故里，少須通籍扣天扉。", "紅粧莫作離凰怨，自有鵷鶵接翅飛。"]'),
('dc36259d-3ec8-4874-bc62-587e6cce8f29','庸齋薛微之里居時與僕爲莫逆交亂後寓洛西時来關中每相見必詫郝婿之爲人歲辛未秋紹先沿檄至長安始得因杯酒接殷勤觀其氣概知庸齋之不予欺也今因其歸詩以餞之','王洋','宋','宋诗','song-poetry','','[]','玉潤冰清久著名，長安一見眼增眀。',64,'全唐诗/poet.song.97000.json','["玉潤冰清久著名，長安一見眼增眀。", "笑談已了關中事，慷慨還成灞上行。", "桑落酒邉還適意，渭城歌裏莫傷情。", "寄身琴鶴堂中相，早爲皇家致太平。"]'),
('528ba200-c6d1-42c3-86b1-35be98396462','送錢顯道赴臨安學宫','王洋','宋','宋诗','song-poetry','','[]','紛紛獄市如棼絲，與子共事西江湄。',64,'全唐诗/poet.song.97000.json','["紛紛獄市如棼絲，與子共事西江湄。", "地連遠近多雜俗，事出衆口無同辭。", "文章幸子老益壮，蒲柳怪我秋前衰。", "從今斫額望天路，十年莫放攻多遲。"]'),
('209130e6-d3a0-487d-a36b-476a2d88bcc5','送章眀章善觧官奉親還吴中二首  其一','王洋','宋','宋诗','song-poetry','','["\u8861\u5c71"]','了知天意貴生全，南嶽夫人奉化權。',64,'全唐诗/poet.song.97000.json','["了知天意貴生全，南嶽夫人奉化權。", "當日論功門戶重，至今傳澤子孫賢。", "聊書鬲上三年課，最愛杯中一百篇。", "君寵母恩如已報，暮雲春樹約他年。"]'),
('45e06ca8-aed6-4494-8abc-343e646daf8b','送章眀章善觧官奉親還吴中二首  其二','王洋','宋','宋诗','song-poetry','','[]','病臥江城五見秋，惟君向我用青眸。',64,'全唐诗/poet.song.97000.json','["病臥江城五見秋，惟君向我用青眸。", "廩人白粟長相續，官簿青錢不用求。", "向日傾心今得意，犯嚴薦口昔徒羞。", "期君通籍金閨後，喚我松江共釣舟。"]'),
('2967b44f-6270-4e5a-81ee-3d7a79b6908a','送魏滁州','王洋','宋','宋诗','song-poetry','','[]','惠政從来到處寬，民心歡喜吏心寒。',64,'全唐诗/poet.song.97000.json','["惠政從来到處寬，民心歡喜吏心寒。", "醉翁亭畔霜初肅，釀酒泉邉菊未乾。", "紫綬繡衣催傳送，黄童白叟挽車看。", "今君已是滁陽守，父老猶稱魏長官。"]'),
('a80e01d8-4c21-45cf-85af-2ce05f4f6e3e','寄朱德茂','王洋','宋','宋诗','song-poetry','','[]','生涯非富亦非貧，恰好容君放曠身。',64,'全唐诗/poet.song.97000.json','["生涯非富亦非貧，恰好容君放曠身。", "種竹種松須傍水，有花有酒不求人。", "功名夢幻吾無與，豁達襟懷德有鄰。", "半醉捋須天地窄，玲瓏峰頂看紅塵。"]'),
('9b2aa28d-5ff5-47ba-a8e5-ad8b4aa0d91a','寄丁求安','王洋','宋','宋诗','song-poetry','','[]','鬰密林巒十丈餘，包羅萬象徧方隅。',64,'全唐诗/poet.song.97000.json','["鬰密林巒十丈餘，包羅萬象徧方隅。", "吳王劍沼連巴峡，廬阜飛泉貫具區。", "賈老華夷分寸尺，輞川花柳較錙銖。", "別来不恨江湖遠，只在君家聚米圖。"]'),
('3c918cf4-e432-46f6-bcd3-75bb6c31b245','寄朱仰之','王洋','宋','宋诗','song-poetry','','[]','年齊甲子性同宜，相見論文更不疑。',64,'全唐诗/poet.song.97000.json','["年齊甲子性同宜，相見論文更不疑。", "小約同行先具酒，且推獨步放君棋。", "庭前雁鷺能堪否，堂下龜魚暫付誰。", "好向藍田報消息，多栽松竹待哦詩。"]'),
('4bb008e1-4203-4ed6-8cc0-92942fa355ff','寄劉行簡','王洋','宋','宋诗','song-poetry','','[]','西来有客解歸装，先說東臺白首郎。',64,'全唐诗/poet.song.97000.json','["西来有客解歸装，先說東臺白首郎。", "顔貎宛如周柱史，鬚眉皆是漢馮唐。", "百年未覺强弓滿，新歷還添漏箭長。", "欲寄平安恐煩報，桃花川裏漾舟忙。"]'),
('718456a3-4818-4cfa-a91a-85ea0b4717bd','寄丁執中','王洋','宋','宋诗','song-poetry','','[]','米鹽煎蹙意何如，盡日逍搖不費書。',64,'全唐诗/poet.song.97000.json','["米鹽煎蹙意何如，盡日逍搖不費書。", "債作拘留身莫贖，詩成困痼力難除。", "事錢不謹兄移愛，與世留心客有餘。", "幸各身閑好同伴，相思如許卻相疏。"]'),
('42da5dbc-e298-4602-9aa1-b773e673901d','寄糜公範','王洋','宋','宋诗','song-poetry','','[]','塵滿簪纓緇滿衣，幾人真解棄如泥。',64,'全唐诗/poet.song.97000.json','["塵滿簪纓緇滿衣，幾人真解棄如泥。", "水方流急收驚檝，籓自無心看觸羝。", "陶令縱教貪漉酒，謝公寧不念烝黎。", "也知雅意人難會，笑對西山是指迷。"]'),
('c7fa1b81-3b3e-4be4-b907-dc8d574c447f','寄李元叔','王洋','宋','宋诗','song-poetry','','[]','北臺御史共推貧，饑走三吴幾閲春。',64,'全唐诗/poet.song.97000.json','["北臺御史共推貧，饑走三吴幾閲春。", "繻袴遠聞歌政績，江山應復助詩神。", "鄉尊耆舊多遺事，地有神山得近鄰。", "料得新篇滿中箧，好分風月寄閑人。"]'),
('bdc08b48-88b2-4806-92f1-3935a494bb80','寄何子楚','王洋','宋','宋诗','song-poetry','','[]','冬餘春晚未收書，一棹相過兩日餘。',64,'全唐诗/poet.song.97000.json','["冬餘春晚未收書，一棹相過兩日餘。", "久擬從容来語舊，豈期盟約未尋初。", "風隨雙鹿樵中隱，人似三閭澤畔居。", "櫻筍廚煙茶焙火，從来心事不相疏。"]'),
('9559be0f-7296-4ab7-b267-2d0a727e63a5','寄鄭公老','王洋','宋','宋诗','song-poetry','','[]','一投魚目得雙珠，恍覺光寒照坐隅。',64,'全唐诗/poet.song.97000.json','["一投魚目得雙珠，恍覺光寒照坐隅。", "郡政已知先歲課，高文何不副時須。", "法官屬籍忠勞久，弔死傷孤里俗蘇。", "已分漂流寄江海，甘從父老啖蒸壺。"]'),
('92dddd08-3889-40f7-899f-ad9612866582','寄徐稚山','王洋','宋','宋诗','song-poetry','','[]','曾攬軺軒一整冠，江西吏膽至今寒。',64,'全唐诗/poet.song.97000.json','["曾攬軺軒一整冠，江西吏膽至今寒。", "疲民仰德方爲貴，野老言公不似官。", "身必静休猶是病，心無揀擇始知安。", "髙情未得真消息，試仗詩筒一問看。"]'),
('623fd6aa-3c8c-4bd5-9156-576544829307','寄張文彦','王洋','宋','宋诗','song-poetry','','[]','掃葉林間一夢回，別来秋物已驚催。',64,'全唐诗/poet.song.97000.json','["掃葉林間一夢回，別来秋物已驚催。", "書通意外殷勤語，詩寄閑中氣味来。", "花木成陰如結幄，庭除自轉不蠲埃。", "俱生北地俱流落，誰得楊枝送一杯。"]'),
('98bc128a-b14b-45e0-916a-aec28719c6fa','寄李叔飛見振叔云叔飛嘗見訪不遇','王洋','宋','宋诗','song-poetry','','[]','難逢易別景如梭，戀戀思君可奈何。',64,'全唐诗/poet.song.97000.json','["難逢易別景如梭，戀戀思君可奈何。", "煩捨朱黄曲尋訪，偶穿城市直經過。", "簪朋恨阻陪吟嘯，文會知難聽琢磨。", "何處恰如長對面，遇心無事便髙歌。"]'),
('15e33258-ac32-49db-b3db-a656c3774a0b','寄李叔飛','王洋','宋','宋诗','song-poetry','','[]','襟懷犖犖久沈淪，念子令人白髪新。',64,'全唐诗/poet.song.97000.json','["襟懷犖犖久沈淪，念子令人白髪新。", "蘇季揣摩雖未試，陳平容貎不長貧。", "要須業履能追古，不信儒冠解誤身。", "早達才名未爲貴，王楊盧駱愧前人。"]'),
('918756ad-18ed-48ad-8352-7c48e50ec084','贈曾谹父雪中歸','王洋','宋','宋诗','song-poetry','','[]','趁得君侯解珮時，平臯千里散瑤巵。',64,'全唐诗/poet.song.97000.json','["趁得君侯解珮時，平臯千里散瑤巵。", "来時馬上寒休問，歸日蘭房夢已知。", "不獨吴娘誇舊事，重教江上聽新詩。", "鳯書恐逐春風到，催起車輪不放遲。"]'),
('706e2dfc-7eb8-4c6d-ad2e-ed1a855204fa','谹父望日欲載酒過南池且云已得潘風酒鄭顧道亦作詩再叙南池風物以酬曾使君吟賞之意','王洋','宋','宋诗','song-poetry','','[]','盡意粧成出曉窗，燕脂頰淺綠雲長。',64,'全唐诗/poet.song.97000.json','["盡意粧成出曉窗，燕脂頰淺綠雲長。", "水僊鹵簿三千女，瓦影龜魚一味凉。", "雞舌舊傳僊客句，芬陀長带梵天香。", "使君玩物無留物，爲爾臨流欲泛觴。"]'),
('c6e79e15-f02b-46fa-8971-038303449e06','贈鄭吏部','王洋','宋','宋诗','song-poetry','','[]','春草牽吟費夢思，一杯相屬重熙怡。',64,'全唐诗/poet.song.97000.json','["春草牽吟費夢思，一杯相屬重熙怡。", "誰知道路添新歷，只覺精神勝舊時。", "鳯子即今車接翼，議曹他日政無私。", "春風吹轂還催起，從此愁添五路棋。"]'),
('2f9e9c9e-8f88-438d-b962-10c89177048b','雨中贈尹少稷','王洋','宋','宋诗','song-poetry','','[]','滯雨昏風漲野田，旅亭猶幸竊髙眠。',64,'全唐诗/poet.song.97000.json','["滯雨昏風漲野田，旅亭猶幸竊髙眠。", "閉門不爲辭賓客，開卷端如揖聖賢。", "夢裏荘周花裏蝶，醉中徐邈酒中僊。", "老来此興非吾事，静識東君意自傳。"]'),
('cc170a69-ceff-446e-b99d-3d9693933487','和伯氏韻贈王元眀元眀舊親予叔行也今死於賊矣  其一','王洋','宋','宋诗','song-poetry','','[]','十分佳處限長淮，人在空眀静□猜。',64,'全唐诗/poet.song.97000.json','["十分佳處限長淮，人在空眀静□猜。", "水北結茅真好去，袖中漫刺爲誰来。", "因嗟翳日塵凝榭，更弔沈槍臥綠苔。", "多少平崗遶淮路，分眀逐處是池臺。"]'),
('cc123d05-0b58-4484-a83b-d23af03bbc6f','和伯氏韻贈王元眀元眀舊親予叔行也今死於賊矣  其二','王洋','宋','宋诗','song-poetry','','[]','野樹霏煙不傍城，還知髙士欲逃名。',64,'全唐诗/poet.song.97000.json','["野樹霏煙不傍城，還知髙士欲逃名。", "倦投芒屩春隨處，笑起孤帆潮又生。", "曾宿客来門不掩，無心人住鳥忘情。", "郊原盛事知多少，出郭當朝共眼眀。"]'),
('2d724bc6-6422-45c7-8393-cd8ccd1c6f12','贈鄭季洪季洪屢以詩文見示','王洋','宋','宋诗','song-poetry','','[]','近無鄰曲雜塵氛，遠有聲名海內聞。',64,'全唐诗/poet.song.97000.json','["近無鄰曲雜塵氛，遠有聲名海內聞。", "白雪兩眉誰顧我，青銅三百擬邀君。", "波濤入筆潮千尺，義勇横胸士六軍。", "早辦林間茅一把，與君分坐看晴雲。"]'),
('59bf3008-cb7e-49b2-96a2-786a51b9b2a0','贈何著作','王洋','宋','宋诗','song-poetry','','[]','净名梵行宰官身，跡似空花意自真。',64,'全唐诗/poet.song.97000.json','["净名梵行宰官身，跡似空花意自真。", "豈爲世間呈伎倆，正緣物外長精神。", "牎横午榻籧篨静，日上朝盤苜蓿新。", "誰與塵寰說消息，不争好惡莫疑人。"]'),
('40cc159f-a103-495c-a9c6-34af25c2fa1e','送法榮師歸吴興榮自清江退院而歸','王洋','宋','宋诗','song-poetry','','[]','又作三年一夢回，浮雲何地是根栽。',64,'全唐诗/poet.song.97000.json','["又作三年一夢回，浮雲何地是根栽。", "身隨東土因緣去，袖带西江風月来。", "碧眼已傳胡相具，白頭誰問故人猜。", "與君別後同參處，雪裏梅花次第開。"]'),
('e37586c3-d26a-454c-a980-b76e37229c9d','贈聞老','王洋','宋','宋诗','song-poetry','','[]','給孤園下化叢林，堂上雷音振海音。',64,'全唐诗/poet.song.97000.json','["給孤園下化叢林，堂上雷音振海音。", "十六師兄同本願，三千法界一慈心。", "有時去作人間雨，無事不聞齋後禽。", "悵望四年留五日，自知清濁易分襟。"]'),
('714bc835-55f5-49ce-b21f-742cf9b31919','留贈道場老慧苦眼疾','王洋','宋','宋诗','song-poetry','','[]','雲中白鶴塔千尋，爲衆同南古到今。',64,'全唐诗/poet.song.97000.json','["雲中白鶴塔千尋，爲衆同南古到今。", "五百年来一聲錫，四禪天外百花林。", "長眉白黑歸宗眼，苦口因緣黄蘖心。", "方見道場多勝境，盡情呈現付知音。"]'),
('283ee506-b102-402b-be3c-8209920e15c2','游純房見李叔穎郎中詩因思叔穎聊繼其韻贈淳化禪師','王洋','宋','宋诗','song-poetry','','[]','衲衣處處逐浮雲，法乳何妨長子孫。',64,'全唐诗/poet.song.97000.json','["衲衣處處逐浮雲，法乳何妨長子孫。", "室有巾缾留祖意，門無車馬露苔痕。", "名髙楚澤多新侣，夢入苕溪有舊言。", "誰與隱峰居士說，曾參一句是同門。"]'),
('02ab99f7-5940-4c5a-983b-387ace8b408f','遊天聖邂逅正師知藏作詩贈之','王洋','宋','宋诗','song-poetry','','[]','乘流自謂不得死，生意逢師聊具論。',64,'全唐诗/poet.song.97000.json','["乘流自謂不得死，生意逢師聊具論。", "無心已盡世間義，舉足不隨天上尊。", "本源了了眀月觀，餘事袞袞洪瀾翻。", "我生流落勢未已，期師盡老依僧園。"]'),
('02bc464a-1cfd-49e1-9839-3d639ba7094b','贈開先悟老悟老述情三頌自持淡泊不事化緣夜坐舉枯木話二首  其一','王洋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','放懷澹泊省拘持，應物無方自不疑。',64,'全唐诗/poet.song.97000.json','["放懷澹泊省拘持，應物無方自不疑。", "我國晏然君莫問，他心通處我爲誰。", "静無淮浦他年夢，老與廬山宿命期。", "到了百年俱任運，世間屈曲自推移。"]'),
('f2a6eeb2-9fe7-40a9-8d8b-f2a1b5f630e3','贈開先悟老悟老述情三頌自持淡泊不事化緣夜坐舉枯木話二首  其二','王洋','宋','宋诗','song-poetry','','[]','身如枯木了生涯，那更迎春競物華。',64,'全唐诗/poet.song.97000.json','["身如枯木了生涯，那更迎春競物華。", "金粟病中猶示衆，如来到處不須誇。", "毗盧法藏無心供，兜率陀天自散花。", "比似出門千萬事，何如豐儉且隨家。"]'),
('b8e42a11-7241-4655-b89d-c0bfcd3c0979','天池贈回老','王洋','宋','宋诗','song-poetry','','[]','平地相逢已二年，重尋勝處少留連。',64,'全唐诗/poet.song.97000.json','["平地相逢已二年，重尋勝處少留連。", "千峰拱足煙霞表，飛鳥啣花几席前。", "白雪擁窗齋竈冷，春風吹谷野芳妍。", "四時坐斷閑消息，古佛心燈萬古傳。"]'),
('ed0ee869-5bbf-404c-a31e-5ff3764d4450','贈後庵顯裕僧','王洋','宋','宋诗','song-poetry','','[]','壞色寒惟破面藤，寄情顯裕一孤僧。',64,'全唐诗/poet.song.97000.json','["壞色寒惟破面藤，寄情顯裕一孤僧。", "花天捧日朝分供，山鬼呼風夜撲燈。", "何日庵居同兀兀，羡君身外只騰騰。", "是非不到争多少，前寺經山只一層。"]'),
('90d754cf-af15-4138-a689-13e482181929','元日倦臥書齋聞僧食未敢歌鼓聲作繼以清唱感而戲作','王洋','宋','宋诗','song-poetry','','[]','蚤鶯聲轉雜危弦，驚散書窗午枕眠。',64,'全唐诗/poet.song.97000.json','["蚤鶯聲轉雜危弦，驚散書窗午枕眠。", "大法鼓聲胡部曲，摩登伽戲野狐禪。", "眼中顛倒迷情事，世上縱横使鬼錢。", "爛煮瓠壺鍾鼎食，山堂誰道獨翛然。"]'),
('95d5f6ad-2bd6-4e4e-9e98-c391a38d7fc4','伯氏自儀真招寶覺師住持以詩促行','王洋','宋','宋诗','song-poetry','','[]','白沙太守性多能，儒業箕裘祖佛燈。',64,'全唐诗/poet.song.97000.json','["白沙太守性多能，儒業箕裘祖佛燈。", "酒减三分留待客，草髙一丈遠招僧。", "見成齋飯非長計，創立叢林是大乘。", "好住溈山十年後，牯牛爛欑不須繩。"]'),
('3a46a262-abba-4164-8833-d87edbc541b9','送寶覺禪師','王洋','宋','宋诗','song-poetry','','[]','夏淺春餘宇宙清，溪山千里送君行。',64,'全唐诗/poet.song.97000.json','["夏淺春餘宇宙清，溪山千里送君行。", "今宵柳岸半輪月，何處花村飛錫聲。", "衣挽嶺雲猶带濕，鶴隨杯渡不須驚。", "江頭一線輕帆急，穏壓鯨波氣自平。"]'),
('b8850a52-ecaf-4937-826a-cb87b7003bee','過慈感知古闍黎爲童行落髪留飯偶已食不果留','王洋','宋','宋诗','song-poetry','','[]','曉衝輕浪遠煙迷，聞道方爲訓導師。',64,'全唐诗/poet.song.97000.json','["曉衝輕浪遠煙迷，聞道方爲訓導師。", "綠髪小童辭俗日，白頭老子泛舟時。", "自緣旅客蔬盤早，不是闍黎鐘飯遲。", "欲別殷勤更留客，逢君知是舊相知。"]'),
('e7b89a1b-3cc6-4384-a3c1-ace8a7b30286','和伯氏別元老贈行','王洋','宋','宋诗','song-poetry','','[]','相見還如相別時，杖頭眀月舊相隨。',64,'全唐诗/poet.song.97000.json','["相見還如相別時，杖頭眀月舊相隨。", "五亭溪下西風静，六合沙邉夏日曦。", "洗鉢又辭香積飯，傳衣仍是雪山兒。", "要須桑下無三宿，不爲淮南塞草衰。"]'),
('26da2471-8261-4a6c-b317-64ef46b14c9d','留贈太平劉道士','王洋','宋','宋诗','song-poetry','','[]','早歲希夷合道真，八年静默已全神。',64,'全唐诗/poet.song.97000.json','["早歲希夷合道真，八年静默已全神。", "收還赤子無爲境，留得丹霄自在身。", "獨與老荘談妙理，不分儒釋是殊倫。", "有時醉露真消息，流水桃花不誤人。"]'),
('085955a1-b826-428d-b8f0-2bdfd159472c','和贈鄭法師','王洋','宋','宋诗','song-poetry','','[]','僊翁八十保純精，自解真符不送迎。',64,'全唐诗/poet.song.97000.json','["僊翁八十保純精，自解真符不送迎。", "信是虚閑能卻老，從教草木不知名。", "交鄰有興開三徑，只用無求度一生。", "聞說嵌巖雲石路，翁能行處我能行。"]'),
('9da88bfb-eecf-4c03-b958-3122825aa19e','和贈知宫','王洋','宋','宋诗','song-poetry','','[]','洞門九鎖是天關，出世那知在世間。',64,'全唐诗/poet.song.97000.json','["洞門九鎖是天關，出世那知在世間。", "行客衝煙排洞戶，主人失足到人寰。", "飽餐蔬筍充朝暮，便與孤雲結往還。", "因爲群仙作家主，卻應我到勝君閑。"]'),
('58647620-8bf2-4885-a2eb-e30b4fa702e1','元夕夜與戎琳殊三老僧對棋琳請作詩賦之','王洋','宋','宋诗','song-poetry','','[]','白布衫韝時節新，嬌鬟豐口綺羅春。',64,'全唐诗/poet.song.97000.json','["白布衫韝時節新，嬌鬟豐口綺羅春。", "滿城菡萏官同樂，午夜簫歌社降神。", "繼晝尋棋三净侣，聞燈堅坐一閑身。", "不須强學行春客，兒女多應不要人。"]'),
('f1e53008-a58d-471e-8c35-41f146a495b7','與長老夜話出故人俞宋護書予至山之日俞書適至書中又相問訊感而賦詩二篇俞郊居婺源草堂蔬圃教子讀書鄉人重之聞近苦目疾殊可念  其一','王洋','宋','宋诗','song-poetry','','[]','三十年餘病作魔，相思長恨隔關河。',64,'全唐诗/poet.song.97000.json','["三十年餘病作魔，相思長恨隔關河。", "僧窗開讀君書至，丈室分龕我暫過。", "憶爾音容如會合，感懷踪跡念蹉跎。", "兩篇價有千金重，若比千金更不磨。"]'),
('688531e9-195c-431e-a173-95f8b3189f51','與長老夜話出故人俞宋護書予至山之日俞書適至書中又相問訊感而賦詩二篇俞郊居婺源草堂蔬圃教子讀書鄉人重之聞近苦目疾殊可念  其二','王洋','宋','宋诗','song-poetry','','[]','法海空門老伏波，婺源槐市病維摩。',64,'全唐诗/poet.song.97000.json','["法海空門老伏波，婺源槐市病維摩。", "道無同異要當爾，命有窮通可奈何。", "兩目再清張籍在，一經傳子鳯毛多。", "飽聞行業書鄉社，得失功名付浩歌。"]'),
('87bbe201-eb60-4c36-a0e0-954987b8f273','得小兒書寄二陳學顔字有楷法','王洋','宋','宋诗','song-poetry','','[]','前代風流顔太師，英風烈烈動朝儀。',64,'全唐诗/poet.song.97000.json','["前代風流顔太師，英風烈烈動朝儀。", "危身已著當時節，正筆猶開百世疑。", "兒作此書真識路，翁因憶汝念臨岐。", "殷勤莫改平原腳，慶及門閭會有時。"]'),
('c083b7d8-f3bc-4eff-8b4f-39ac00f8dd30','酒熟未酌鄉人次第固未及伯氏伯氏因失酒以詩謫之謹繼韻解嘲','王洋','宋','宋诗','song-poetry','','[]','滿盎濃薰靄綠雲，可憐珍韻不長存。',64,'全唐诗/poet.song.97000.json','["滿盎濃薰靄綠雲，可憐珍韻不長存。", "病妻功罷初嘗液，壯士酣餘更破樽。", "千日留春傳古昔，一宵遺愛有缾盆。", "明朝試榜揚雄宅，恐有壺車忽到門。"]'),
('cdd1d1b3-18ed-426b-9619-0a007e3ad12f','謙仲好古攜酒見過伯氏以詩謝之次韻','王洋','宋','宋诗','song-poetry','','[]','我生南北本殊津，邂逅相逢若聚蘋。',64,'全唐诗/poet.song.97000.json','["我生南北本殊津，邂逅相逢若聚蘋。", "故納破愁成一笑，應憐對影只三人。", "居嫌共邑猶分袂，醉覺同心只異身。", "送客溪邉一惆悵，新歡過眼又前塵。"]'),
('e28d2392-c552-42e1-a315-06d6861a3c47','次蘋字韻即事','王洋','宋','宋诗','song-poetry','','[]','飄零何處是通津，陸有飛蓬水有蘋。',64,'全唐诗/poet.song.97000.json','["飄零何處是通津，陸有飛蓬水有蘋。", "賦稟但隨升斗祿，姓名常後百千人。", "趨炎未肯施先足，耐冷何須便曲身。", "祗有鳴塤恐難繼，此心端欲避芳塵。"]'),
('2afca48a-bd31-4791-966a-e0945e1e2fbd','伯氏再以前韻即事復繼韻','王洋','宋','宋诗','song-poetry','','[]','問宅無成復問津，青衫長是照青蘋。',64,'全唐诗/poet.song.97000.json','["問宅無成復問津，青衫長是照青蘋。", "生涯異日知何地，性命如今正屬人。", "螻蟻命輕難報國，蟲魚買絕拙謀身。", "五年湖海成何事，只得冠纓不染塵。"]'),
('af2ee305-11e8-4739-939f-daffa39cab53','伯氏以詩投郭謙仲叙未相過之意次韻','王洋','宋','宋诗','song-poetry','','[]','相過何日買輕舠，十里思君奈鬰陶。',64,'全唐诗/poet.song.97000.json','["相過何日買輕舠，十里思君奈鬰陶。", "莫謂遠煙迷野樹，且看飛絮舞江臯。", "難追競病傳清晝，且合亡何引濁醪。", "除卻醉鄉岐路穩，人間無處不風濤。"]'),
('39f4eea7-597e-4ca1-abd7-a0d18e0f9a37','髙民瞻以前韻作詩因酬','王洋','宋','宋诗','song-poetry','','[]','釣叟生涯止一舠，興來猶復醉陶陶。',64,'全唐诗/poet.song.97000.json','["釣叟生涯止一舠，興來猶復醉陶陶。", "知君自欲營新築，繼世那聞有舊臯。", "野性素來便野趣，春山唯恐欠春醪。", "果能過我論文字，且擬張帆看怒濤。"]'),
('5ec4d419-9abb-4e9f-9a9c-209dd33f7141','民瞻再作詩復以前韻酬之','王洋','宋','宋诗','song-poetry','','[]','報我新詩疾轉舠，論文始信賴薰陶。',64,'全唐诗/poet.song.97000.json','["報我新詩疾轉舠，論文始信賴薰陶。", "追風定見驥千里，鳴野今聞鶴九臯。", "看劍爲君傾薄酒，張弓何日畏春醪。", "不煩更問珊瑚樹，舊繡年來拆海濤。"]'),
('70688417-a9be-4185-bb41-3d5937135d91','和伯氏德清道中','王洋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','解組歸尋梵釋宫，帆風舟轉疾飛蓬。',64,'全唐诗/poet.song.97000.json','["解組歸尋梵釋宫，帆風舟轉疾飛蓬。", "棠陰留付長江外，山色收來數筆中。", "聞說笑談供燕席，有時魚鳥襍籖筒。", "豈唯政譽歌襦袴，文字由來繼古風。"]'),
('8169768d-d514-456c-a0a2-a250e6b1bf26','伯氏臨江使君寄薌林次韻  其一','王洋','宋','宋诗','song-poetry','','[]','力盪橫空萬斛舟，一函酬唱紀川遊。',64,'全唐诗/poet.song.97000.json','["力盪橫空萬斛舟，一函酬唱紀川遊。", "篇篇秀潤東南竹，落落珠璣小大鄒。", "人物百年同富壽，客懷千里夢逡遒。", "主人合作鯨川楫，無奈髙情寄一邱。"]'),
('d19ac590-18e5-468d-98b8-1d235cf48039','伯氏臨江使君寄薌林次韻  其二','王洋','宋','宋诗','song-poetry','','[]','君王勸駕一輕舟，賜履西江飽勝遊。',64,'全唐诗/poet.song.97000.json','["君王勸駕一輕舟，賜履西江飽勝遊。", "井邑詩書今化魯，春秋盟會不書鄒。", "詩中侯印知無分，筆下尊拳勿太遒。", "快讀新章與神會，蠧關門掩夢經邱。"]'),
('2b6f4cbe-df05-4715-b788-5b6da0282123','和伯氏二首  其一','王洋','宋','宋诗','song-poetry','','[]','松竹窗邉拂簡書，芙蓉水伴戲龜魚。',64,'全唐诗/poet.song.97000.json','["松竹窗邉拂簡書，芙蓉水伴戲龜魚。", "雁行千里時一往，蜂得一房聊共居。", "千二百年形骨健，三十六計米鹽疏。", "齒牙缺落無衰病，慚愧當年謝幼輿。"]'),
('c3b3dc71-be0a-4c48-9ba2-04332ea96f04','和伯氏二首  其二','王洋','宋','宋诗','song-poetry','','[]','眼見群兒倦走書，明瓊忽報漲雙魚。',64,'全唐诗/poet.song.97000.json','["眼見群兒倦走書，明瓊忽報漲雙魚。", "造端萬緒自成室，迷路多岐要卜居。", "談氏龜兒門相在，微之道保曉星疏。", "願翁壽考貽孫子，文有千箱德有輿。"]'),
('c67bf141-9c3e-46ce-b4c0-a8ede7755aa7','次曾吉父韻','王洋','宋','宋诗','song-poetry','','[]','憔悴非同十載前，旅酬那復似初筵。',64,'全唐诗/poet.song.97000.json','["憔悴非同十載前，旅酬那復似初筵。", "蜜房羽客非無課，木局枯棋亦任緣。", "得酒且思陪笑語，著詩終欲共林泉。", "北壇居士新登拜，租得茶山又一年。"]'),
('e5aac3f7-2a6c-4e7b-b33a-aa55b996e1c8','曾吉父出示和鄭固道病中詩次韻','王洋','宋','宋诗','song-poetry','','[]','行藥蕭晨放步遲，嘯臺秋色飽秋時。',64,'全唐诗/poet.song.97000.json','["行藥蕭晨放步遲，嘯臺秋色飽秋時。", "樂天何意病爲伴，樊素不收春自隨。", "舊雨故人頻問疾，茅君使者净窺棋。", "拂衣身健丹楓路，積壓風光剩費詩。"]'),
('af29a80f-9c94-4eda-b257-c3aafb0ff5ca','吉父用晁恭道韻作詩謝同會次韻','王洋','宋','宋诗','song-poetry','','[]','蒲柳先衰祗自驚，静思前事似前生。',64,'全唐诗/poet.song.97000.json','["蒲柳先衰祗自驚，静思前事似前生。", "力侔元氣推先覺，醉打愁城堪一行。", "求援援暌緣富厚，鼓宫宫動亦虧成。", "會當載酒論奇字，日暮江天得細傾。"]'),
('74d73650-0120-435b-b843-a387660fec86','曾吉父以詩招客次韻','王洋','宋','宋诗','song-poetry','','[]','醉吟居士桃李曲，忠孝相家鸚鵡杯。',64,'全唐诗/poet.song.97000.json','["醉吟居士桃李曲，忠孝相家鸚鵡杯。", "情隨蘭畹碧香注，詩送茶山煙雨來。", "溪邉官柳意欲盡，枝上海棠紅半開。", "不應物色相攜手，驚喚南池春夢回。"]'),
('c8c99bcf-684c-4414-b4ff-fa3aef8e0bb4','和吉父賦隨字韻','王洋','宋','宋诗','song-poetry','','[]','此生休戚已前期，命薄天公不可移。',64,'全唐诗/poet.song.97000.json','["此生休戚已前期，命薄天公不可移。", "一飲且同今日醉，數篇曾見古人詩。", "青山招我成長計，白髪欺人亦太癡。", "莫與老翁疑甲子，當年猶記會沙隨。"]'),
('2a65cb0b-11d8-4736-9e4d-35aeaed03487','和吉父示送别七言','王洋','宋','宋诗','song-poetry','','[]','景物隨人也解愁，年來諼草不忘憂。',64,'全唐诗/poet.song.97000.json','["景物隨人也解愁，年來諼草不忘憂。", "微官自縳敢辭冷，倦鳥縱歸何處投。", "一歲又聞禾黍熟，百年惟喜甲兵休。", "人生佳節真難遇，莫惜重陽菊滿頭。"]'),
('c924d431-d49a-473e-9fc8-63778e0eee70','和吉父還谹父詩','王洋','宋','宋诗','song-poetry','','[]','病折丹心一寸灰，猶憐花月照雲罍。',64,'全唐诗/poet.song.97000.json','["病折丹心一寸灰，猶憐花月照雲罍。", "碧腴既許投交分，黄菊從教卻放開。", "上客醉時花婀娜，綺筵歌罷月遲徊。", "白頭賀監頻三請，好客從前招不來。"]'),
('7c506891-825d-43d7-8a4c-0e204ae78575','和吉父贈谹父詩','王洋','宋','宋诗','song-poetry','','[]','瘧有黎邱競出奇，操矛不報主人知。',64,'全唐诗/poet.song.97000.json','["瘧有黎邱競出奇，操矛不報主人知。", "問渠去處終無定，與我周旋便有期。", "貧似淵明猶愛酒，瘦如工部只緣詩。", "但教酒入無功社，何用詩稱國士爲。"]'),
('f376e3fc-9f3b-4a66-b2ab-d21a74009767','和曾谹父簡吉父伯南坡','王洋','宋','宋诗','song-poetry','','[]','柳徑桃蹊草色新，一年春半又侵尋。',64,'全唐诗/poet.song.97000.json','["柳徑桃蹊草色新，一年春半又侵尋。", "無情燕子疑巢冷，多怒鳴蛙互目禁。", "滿眼爲花留色艷，轉頭遺我是清陰。", "莫愁艇子芙蓉檝，且聽拏音作好音。"]'),
('3e207338-13fd-4980-9a29-c142995d69f6','和谹父小雨秋凉','王洋','宋','宋诗','song-poetry','','[]','時豐報祀拂黄收，共說金穰更幾秋。',64,'全唐诗/poet.song.97000.json','["時豐報祀拂黄收，共說金穰更幾秋。", "樹染烟濃山着色，月臨天迥水明樓。", "盈囷黍答三時力，七字詩銷萬斛愁。", "飽飯哦詩醉山月，不妨歸老一扁舟。"]'),
('4442ad3f-a724-46c7-887c-e21e294a05d1','和谹父攜家南坡期以招客','王洋','宋','宋诗','song-poetry','','[]','日日尋春春未休，髙情可是愜風流。',64,'全唐诗/poet.song.97000.json','["日日尋春春未休，髙情可是愜風流。", "詩如濯錦江波色，身在浣花流水頭。", "行想袿裳分襞積，晚因魚鳥得遲留。", "草堂費盡無人寄，悵望前溪獨自愁。"]'),
('7869ed66-a2c2-43c6-909b-2c2c4bf0c193','答秀實見招','王洋','宋','宋诗','song-poetry','','[]','此身初不敢圖安，老去偏憂行路難。',64,'全唐诗/poet.song.97000.json','["此身初不敢圖安，老去偏憂行路難。", "欲調舟車難用法，偕行僕從只宜寬。", "已持食節多虞病，嫌重装囊少慮寒。", "且替疲兵充守宅，詩成莫惜寄來看。"]'),
('be125f4e-b2e1-490b-b726-21c7cd270fb0','秀實監丞復寄二篇譏商彦不至亦微見及因次韻','王洋','宋','宋诗','song-poetry','','[]','折除官職是聲稱，利達文章不易幷。',64,'全唐诗/poet.song.97000.json','["折除官職是聲稱，利達文章不易幷。", "聯句每容分短韻，五言今始見長城。", "將軍莊畔傷沉甲，處士廬邉笑盗名。", "我欲抱鋤歸問婦，揶揄未許餉春耕。"]'),
('eb1f0e28-831d-4a9f-813b-9197180077d5','和嘉仲秀實九日詩','王洋','宋','宋诗','song-poetry','','[]','幸分微祿養閑身，杖策登髙擬令辰。',64,'全唐诗/poet.song.97000.json','["幸分微祿養閑身，杖策登髙擬令辰。", "貧愧减員招酒伴，閑多債數得詩人。", "不辭眼見黄花舊，卻恐花驚白髪新。", "人道二疏賢父子，我疑文采是天倫。"]'),
('54a11479-e91d-4aef-a663-3e6302443af8','次二兄韻','王洋','宋','宋诗','song-poetry','','[]','短莛投迹類蓬麻，何似差吟得當檛。',64,'全唐诗/poet.song.97000.json','["短莛投迹類蓬麻，何似差吟得當檛。", "藏跡豈期今脫死，迎軍幾處早分髽。", "池塘带雪猶涵溟，林谷先春已豁谺。", "莫謂寒荄更無分，春來也解露雙芽。"]'),
('46e8d08c-b636-4ca0-ae4f-749c4fa3230a','僕近還舍以一篇餉秀實蒙以兩篇見酢謹用前韻再酬一篇','王洋','宋','宋诗','song-poetry','','[]','春行日日度芳林，僧夢回看午轉陰。',64,'全唐诗/poet.song.97000.json','["春行日日度芳林，僧夢回看午轉陰。", "閑喜林塘多静態，忙輸蜂蝶見花心。", "三杯酒後逢人醉，幾首詩多取意吟。", "慚愧孟郊三百首，何人收拾薦薰琴。"]'),
('894315ec-5f17-4a23-bb03-6b66ae3c4770','和周秀實用前韻','王洋','宋','宋诗','song-poetry','','[]','老知白髪愧花林，望絕華筵繼晝陰。',64,'全唐诗/poet.song.97000.json','["老知白髪愧花林，望絕華筵繼晝陰。", "病與物疏鎖火性，貧知分薄更灰心。", "春收紅紫如辭客，風入松篁得伴吟。", "莫恨蔬盤欠何肉，文園病渇只因琴。"]'),
('874ec446-b5e6-49fd-9398-180c52b514f3','和周仲嘉再示三篇  其一','王洋','宋','宋诗','song-poetry','','[]','舊日衣冠說武林，風流曾不减山陰。',64,'全唐诗/poet.song.97000.json','["舊日衣冠說武林，風流曾不减山陰。", "百年人物千山秀，萬里功名天下心。", "族姓人人誇盛事，溪山處處稱髙吟。", "後生欲聽清商曲，莫學無弦只撫琴。"]'),
('80af8a36-1716-47a8-a224-3f4c188554b7','和周仲嘉再示三篇  其二','王洋','宋','宋诗','song-poetry','','[]','花有芳叢竹有林，春來各競趁光陰。',64,'全唐诗/poet.song.97000.json','["花有芳叢竹有林，春來各競趁光陰。", "妍媸等是目前事，冷淡方知異日心。", "十二里山長隔面，一帆風地每傳吟。", "髙山流水人知否，綠綺窗間自曉琴。"]'),
('01ba3e54-2cf6-4fd6-9cfe-79198a77cbea','和周仲嘉再示三篇  其三','王洋','宋','宋诗','song-poetry','','[]','長篇大軸勢如林，慰我窮愁正結陰。',64,'全唐诗/poet.song.97000.json','["長篇大軸勢如林，慰我窮愁正結陰。", "數首娯憂兼寓物，幾人對面便知心。", "多求筆吏供濡墨，剩買筠筒給浩吟。", "閑靜心情如此少，能聽賀若是知琴。"]'),
('f54782bd-3bc8-47f0-b41a-006a2af82783','秀實再用前韻惠詩再答 答見贈','王洋','宋','宋诗','song-poetry','','[]','身似鷦鷯寄遠林，仍將病骨卜晴陰。',64,'全唐诗/poet.song.97000.json','["身似鷦鷯寄遠林，仍將病骨卜晴陰。", "有情緣墮有情法，無處雲知無處心。", "棋對僧窗時自縱，詩傳人口不堪吟。", "感君裁鑒多清賞，收拾焦桐爨下琴。"]'),
('5763171c-7d65-4b03-9ff4-36b23ec4b81b','秀實再用前韻惠詩再答 答自述','王洋','宋','宋诗','song-poetry','','[]','聲馳南國秀千林，逸氣終疑困華陰。',64,'全唐诗/poet.song.97000.json','["聲馳南國秀千林，逸氣終疑困華陰。", "病任燒空不燒火，詩唯傳句不傳心。", "當年宗魯江西夢，異日睎顔洛下吟。", "直把風流付邱壑，真如封鎖匣中琴。"]'),
('35d74e80-cdd9-4318-b859-c3cef10f855a','和知字韻二篇 答解嘲','王洋','宋','宋诗','song-poetry','','[]','春來秋去鎖煙扉，此境人間不易知。',64,'全唐诗/poet.song.97000.json','["春來秋去鎖煙扉，此境人間不易知。", "强遣憂愁須藉酒，巧傳消息卻因詩。", "生緣有累難除藥，性本無爲不用醫。", "苦樂從來略相對，乘車須記飯牛時。"]'),
('03f2f012-3512-4784-93c3-092b6f156bc2','和知字韻二篇 答寄贈','王洋','宋','宋诗','song-poetry','','[]','全無客到掩庵扉，冷暖心腸袛自知。',64,'全唐诗/poet.song.97000.json','["全無客到掩庵扉，冷暖心腸袛自知。", "貧欠飯租難乞米，午虧睡課且裁詩。", "已傷刄自驚逢敵，多病人難更說醫。", "强半工夫付詩軸，獨慚騎吏立門時。"]'),
('0f185506-6cb1-4ae4-9e33-0f0df9939080','和秀實扉字韻','王洋','宋','宋诗','song-poetry','','[]','柴車朝出莫柴扉，麋鹿情通麋鹿知。',64,'全唐诗/poet.song.97000.json','["柴車朝出莫柴扉，麋鹿情通麋鹿知。", "寓目每因思舊約，破顔時幸讀新詩。", "妻兒債負真寃境，祖佛因緣即妙醫。", "救火抱薪還止火，只嫌虛幻沒休時。"]'),
('296ec64f-e7cc-48bf-82d8-fd8fc5d45263','奉酬秀實報章外以前韻示謔且聞灼艾次韻','王洋','宋','宋诗','song-poetry','','[]','早衝料峭别巖扉，惜别音容意自知。',64,'全唐诗/poet.song.97000.json','["早衝料峭别巖扉，惜别音容意自知。", "道上每因同客笑，篋中常恨少君詩。", "飽参靜定推先覺，苦炙虛空得下醫。", "菽韭盤空春睡起，伯仁還遇火攻時。"]'),
('ff5a9af7-6e53-4efa-afcf-1db3343ad4aa','和仲嘉示秀實','王洋','宋','宋诗','song-poetry','','[]','去秋九日失歸期，今度花前又過時。',64,'全唐诗/poet.song.97000.json','["去秋九日失歸期，今度花前又過時。", "喚客便宜傾鑿落，與誰同伴插酴醿。", "新甘未厭松江鱠，敏捷先酬季父詩。", "莫道野翁無食品，葵羹爛煑亦偏宜。"]'),
('9b425cdf-312b-4b05-8707-f96e5c868a61','和秀實答仲嘉','王洋','宋','宋诗','song-poetry','','[]','未春先以約春期，載酒如何卻負時。',64,'全唐诗/poet.song.97000.json','["未春先以約春期，載酒如何卻負時。", "搖想醉狂哦舴艋，也知歸客趁酴醿。", "阿瞞氣懾周瑜陣，樊素心貪白傳詩。", "橫槊賦詩俱占卻，據鞍矍鑠正相宜。"]'),
('d0b4b692-2ee1-40a7-903f-75e034a3a7e4','和秀實','王洋','宋','宋诗','song-poetry','','[]','十風九雨一春除，散綠留紅證夏初。',64,'全唐诗/poet.song.97000.json','["十風九雨一春除，散綠留紅證夏初。", "心事自應隨念遠，年華未省向人疏。", "欲開胸次猶須酒，泛若因緣卻爲書。", "飽滿盤天久無望，良規真恐在污渠。"]'),
('227b175b-6a01-477f-b422-6665ba15a113','和秀實寄尹商老見訪','王洋','宋','宋诗','song-poetry','','[]','二千里外命車輪，慰我言詞字字新。',64,'全唐诗/poet.song.97000.json','["二千里外命車輪，慰我言詞字字新。", "自向江西逢隱吏，方知物外有髙人。", "頻將篇什收風月，怠整形儀作搢紳。", "相對茅簷終日語，從教人道是沉淪。"]'),
('f3ea0bf8-b711-465e-a634-2b7948a1bae3','再和答秀實  其一','王洋','宋','宋诗','song-poetry','','[]','紅剝芳菲綠作叢，搖知惆悵兩心同。',64,'全唐诗/poet.song.97000.json','["紅剝芳菲綠作叢，搖知惆悵兩心同。", "結交舊燕多情語，消病殘花無用紅。", "獻計欲居塵境外，投名且向酒壺中。", "新來但覺多新様，不道襟懷盡古風。"]'),
('8394decf-3f4f-4724-9585-aa68c6053f26','再和答秀實  其二','王洋','宋','宋诗','song-poetry','','[]','老境看來亦悄然，方知世味有無邉。',64,'全唐诗/poet.song.97000.json','["老境看來亦悄然，方知世味有無邉。", "忙中受用非關我，静裏風光總是禪。", "易□常參饑後眼，酬有只有飽時眠。", "周翁百事多恬退，詩律從來不受憐。"]'),
('8956772b-1235-4b6d-ab26-27f2c8257975','和秀實别寄二篇  其一','王洋','宋','宋诗','song-poetry','','[]','世德聯綿自漢朝，元功當日說蕭曹。',64,'全唐诗/poet.song.97000.json','["世德聯綿自漢朝，元功當日說蕭曹。", "營分細柳威名重，笑指飛煙量度髙。", "文挾素勳誰與敵，詩推餘事尚稱豪。", "了知三阮逃名久，恐被名牽未可逃。"]'),
('92dc267b-83e0-4af8-8f4b-4f5b48c05e79','和秀實别寄二篇  其二','王洋','宋','宋诗','song-poetry','','[]','香火社閑棋度日，溪山伴靜酒爲年。',64,'全唐诗/poet.song.97000.json','["香火社閑棋度日，溪山伴靜酒爲年。", "碧霄鶴唳詩情遠，湖院僧知茶夢圓。", "常喜春鉏行佚老，每嫌棋路尚爭先。", "平湖草岸經行好，後夜延緣刺釣船。"]'),
('f2ae664a-0f15-4280-b59f-f7de5896009b','秀實惠簡問閑居消息有滴水滴凍之語以詩報之  其一','王洋','宋','宋诗','song-poetry','','[]','氣血扶輿夢幻身，用多補少不調匀。',64,'全唐诗/poet.song.97000.json','["氣血扶輿夢幻身，用多補少不調匀。", "如今滴水滴凍客，便是貪花貪酒人。", "髪白容衰爭早晚，官榮家富費精神。", "空花若解揩摩盡，方識人間一笑春。"]'),
('049e3b8e-cf7c-4e05-acb9-b05365c352be','秀實惠簡問閑居消息有滴水滴凍之語以詩報之  其二','王洋','宋','宋诗','song-poetry','','[]','晨鐘齋鼓住僧園，縱不陪堂已一般。',64,'全唐诗/poet.song.97000.json','["晨鐘齋鼓住僧園，縱不陪堂已一般。", "恐爲因緣略相似，若無消息自難安。", "樂爲苦本宜先戒，病是良醫要好看。", "爲問爐香經卷外，有無塵妄更相干。"]'),
('6fc30e9b-446d-4d74-8da9-ae364ec2757e','得丁執中書和前韻依用韻一首','王洋','宋','宋诗','song-poetry','','[]','履堅抱節有誰如，本爲書窮更買書。',64,'全唐诗/poet.song.97000.json','["履堅抱節有誰如，本爲書窮更買書。", "命欲問天何厚薄，貧多聞道是乘除。", "倉箱粟帛常虧課，庭戶芝蘭獨獻餘。", "氣味如君略相似，只論詩律愧空疏。"]'),
('9b13596d-77c3-4670-aac9-de6e3ffbac54','趙筠州惠書賀冬道予得宫觀訝久無書且勸滿泛壽杯及問老妻安否','王洋','宋','宋诗','song-poetry','','[]','筠陽太守舊知聞，筆力清新思不群。',64,'全唐诗/poet.song.97000.json','["筠陽太守舊知聞，筆力清新思不群。", "泰道自當隨紀歷，蹇塗何用慶書雲。", "杯中旨酒衰難盡，牀上愁妻病未分。", "故向琳宫同寂寞，一爐香火伴清芬。"]'),
('678a4f1d-0843-4a13-974f-ff19fdde3dfd','杜倅再示前韻繼之二首  其一','王洋','宋','宋诗','song-poetry','','[]','慚愧詩筒數往回，自嫌局促困駑材。',64,'全唐诗/poet.song.97000.json','["慚愧詩筒數往回，自嫌局促困駑材。", "塵蹤已挂舊官壁，妙語猶隨新雨來。", "好客共謀良夜醉，養花長得四時開。", "知君客裏猶行樂，端爲襟懷不染埃。"]'),
('1458bad7-7976-41d4-a409-f85ede7d0966','杜倅再示前韻繼之二首  其二','王洋','宋','宋诗','song-poetry','','[]','不惜分餘爲借光，情同結客少年場。',64,'全唐诗/poet.song.97000.json','["不惜分餘爲借光，情同結客少年場。", "誰知親拜六篇語，全勝搖聞十里香。", "自嘆滿頭頻獻白，敢言三俎欲懷黄。", "一缾一鉢煙波裏，徑入苕溪向水央。"]'),
('6652eb0c-c0ce-4126-8506-eead74d52a8c','再酬杜倅兩詩用前韻  其一','王洋','宋','宋诗','song-poetry','','[]','報道春風莫便回，少陵凖擬作詩材。',64,'全唐诗/poet.song.97000.json','["報道春風莫便回，少陵凖擬作詩材。", "公然背我堂堂去，略不隨人得得來。", "花占三春官已滿，河專一壑幕初開。", "已知風物長流轉，得舉朱弦且拂埃。"]'),
('a67272d9-50a5-4920-8077-b13d5453eafb','再酬杜倅兩詩用前韻  其二','王洋','宋','宋诗','song-poetry','','[]','昨朝珠玉已爭光，再轉旌旗再擅場。',64,'全唐诗/poet.song.97000.json','["昨朝珠玉已爭光，再轉旌旗再擅場。", "景物歲時俱婉娩，德人言語亦馨香。", "歌風燕子初爭語，藏柳鴉兒學畫黄。", "牽率賡酬無健句，鸞聲只合聽央央。"]'),
('938ecfe7-9992-46c2-8f1d-347ca0237cc6','楊先寄安仁因簡熊叔雅趙令幷次前韻','王洋','宋','宋诗','song-poetry','','[]','三年築冶困塵迷，且拂塵埃下錦溪。',64,'全唐诗/poet.song.97000.json','["三年築冶困塵迷，且拂塵埃下錦溪。", "客子雲山無定宅，令君桃李已成蹊。", "閑情聊賦籬邉菊，快意須分物外題。", "粉署仙郎臥江渚，相逢莫惜醉如泥。"]'),
('a1ae7fa8-80c1-46c7-90ea-2f761ee5788c','葛秘校和予關字韻詩兩篇再以一篇奉酬','王洋','宋','宋诗','song-poetry','','[]','數州形勝共鄉關，江浦淮堧一望間。',64,'全唐诗/poet.song.97000.json','["數州形勝共鄉關，江浦淮堧一望間。", "長恨崎嶇千里隔，那知邂逅兩身閑。", "稻粱要足幾時足，閭井欲還何日還。", "猶勝拘牽名利客，心無一事看春山。"]'),
('18970eff-6701-4a13-b5bd-78001aec9f31','沈大虛以丁求安韻寄兩篇次韻','王洋','宋','宋诗','song-poetry','','[]','長淮千里擁雙旌，攬轡曾聞志已清。',64,'全唐诗/poet.song.97000.json','["長淮千里擁雙旌，攬轡曾聞志已清。", "槐市早年先走譽，橋門多士羡蜚聲。", "山長靜默溪長綠，人有豪華物有英。", "早趁官閑剩尋賞，它年車騎不單行。"]'),
('398ea1c2-c5e7-4b8b-a600-33743758c5e3','子楚寄吏報章復用前韻再寄一篇','王洋','宋','宋诗','song-poetry','','[]','長須晨送一函書，語不周遮意有餘。',64,'全唐诗/poet.song.97000.json','["長須晨送一函書，語不周遮意有餘。", "雨滿一犂知過望，草開三逕喜如初。", "黄魚白酒江頭市，綠竹青蒲隱士居。", "病後世緣多懶惰，相逢詩酒未全疏。"]'),
('c988dd37-9902-4215-a0af-b702f9569aa5','和趙倅兼善觀徐園詩','王洋','宋','宋诗','song-poetry','','[]','雨闇長亭去驛賒，褰帷那免歎年華。',64,'全唐诗/poet.song.97000.json','["雨闇長亭去驛賒，褰帷那免歎年華。", "應緣問俗頒温詔，卻得名園看好花。", "晴入郊圻初浩蕩，春隨杖屨得津涯。", "仙郎不解收珠玉，别乘歸時載滿車。"]'),
('105a03f5-93fe-48ff-b77a-84eaf81b0919','再次前韻','王洋','宋','宋诗','song-poetry','','[]','堆案文書不用嗟，新詩字字說芳華。',64,'全唐诗/poet.song.97000.json','["堆案文書不用嗟，新詩字字說芳華。", "題輿事省時眠草，綸閣文髙合判花。", "莫待春歸空悵望，須知醉裏有生涯。", "如何爲向邦侯說，整頓清明載酒車。"]'),
('13294fd6-5f0f-4117-aeb8-8712ac8e4620','厚載王君求僕賦寄閑齋詩又欲僕作晚實此君二詩皆未果惠然枉佳篇甚厚非老鈍所及聊次韻奉酬','王洋','宋','宋诗','song-poetry','','[]','布鼓何堪付阿香，平生癡絕亦長康。',64,'全唐诗/poet.song.97000.json','["布鼓何堪付阿香，平生癡絕亦長康。", "曲成下里安知宋，疏就中郎不姓常。", "未許芳馨依杜若，搖窺光怪識干將。", "秋風一水空相望，留滯何時貢玉堂。"]'),
('d8768d8a-dd8a-4533-b90c-0d47848262d9','和徐思遠韻','王洋','宋','宋诗','song-poetry','','[]','幾葉文章開一花，布裘中句已名家。',64,'全唐诗/poet.song.97000.json','["幾葉文章開一花，布裘中句已名家。", "無心於世苦亡賴，生子如郎定可誇。", "行矣齋房思賈傳，莫將髙論詆王嘉。", "冥鴻一去自千里，寂寞沙村只望涯。"]'),
('c89be9e1-ceb9-4851-b715-63dc74702f4e','和滕宰與徐思遠','王洋','宋','宋诗','song-poetry','','[]','故國愁來有所思，那堪更讀四愁詩。',64,'全唐诗/poet.song.97000.json','["故國愁來有所思，那堪更讀四愁詩。", "令君術業輝千古，處士才名冠一時。", "醉後嘯歌爭氣焰，閑來履屐共追隨。", "詩豪酒俠方推重，野客何知但朵頥。"]'),
('c03e04b3-3029-4159-a126-fc30703fb5d7','和徐思遠歲除','王洋','宋','宋诗','song-poetry','','[]','節物催人莫自悲，開顔且喜看君詩。',64,'全唐诗/poet.song.97000.json','["節物催人莫自悲，開顔且喜看君詩。", "飯抛宿歲因輕棄，酒爲迎年故重違。", "照鏡不收寒鷺影，藏鈎新與少年期。", "何須直待東風醉，紅燭花前且滿枝。"]'),
('2d099d0a-d8ef-4ba5-a2b0-90d5aae88256','徐思遠出示月夜登樓詩句法甚髙不類平生語幸少卑之在我輩中自不失爲社頭且使時見一斑也','王洋','宋','宋诗','song-poetry','','[]','幾處澄輝幾處秋，好閑時上水明樓。',64,'全唐诗/poet.song.97000.json','["幾處澄輝幾處秋，好閑時上水明樓。", "誰憐老子風前興，爲遣中郎醉上舟。", "一带橫空長漠漠，時看飛棟影悠悠。", "今宵踏月歸時節，莫罵徐郎只暗遊。"]'),
('1462526c-509e-427b-a7aa-a591a56ee285','李尹叔知丞借華嚴于仙山子楚以詩道其事李有和詩因以次韻','王洋','宋','宋诗','song-poetry','','[]','與君淮浦接鄉關，聞道忙中也自閑。',64,'全唐诗/poet.song.97000.json','["與君淮浦接鄉關，聞道忙中也自閑。", "身似浮花真客宅，心歸實地是家山。", "窗明篤耨朝烟細，榻靜籧篨午夢殘。", "更問前生李居士，南行今到幾人間。"]'),
('f3046da2-571a-45a1-89fd-31a00ea58c7f','和張中大  其一','王洋','宋','宋诗','song-poetry','','[]','天作長綃玉作圖，恍然身世在冰壺。',64,'全唐诗/poet.song.97000.json','["天作長綃玉作圖，恍然身世在冰壺。", "歲期共飽如頒粟，瑞要均行勝得珠。", "未辦五湖揚短艇，且謀雙鯉喚長鬚。", "清朝不要培芝菌，正好稱觴頌正符。"]'),
('779e05ee-f7fa-43e2-9a1e-63f095eec1f6','和張中大  其二','王洋','宋','宋诗','song-poetry','','[]','憶昔開元夜宴圖，錦爲方丈玉爲壺。',64,'全唐诗/poet.song.97000.json','["憶昔開元夜宴圖，錦爲方丈玉爲壺。", "但誇北里樓吹笛，誰問長安米勝珠。", "事去牽連難雪耻，愁來陪奉長霜鬚。", "兔園巖穴皆時彦，一斗青精過刻符。"]'),
('2d2f4c88-f45a-4486-bf5d-b7b35b51c0e1','楊仲承秘書蹉跎三年今得榮州文學冬日貽書以詩答之','王洋','宋','宋诗','song-poetry','','[]','昔年曾嘆小差池，官带榮名自有時。',64,'全唐诗/poet.song.97000.json','["昔年曾嘆小差池，官带榮名自有時。", "二火並光君有漸，一茅覆屋兩相宜。", "心田自樂緣知足，世路無求亦少思。", "好是一丘藏曲折，也無鄰里共追隨。"]'),
('e736db66-182b-4a39-845b-0e8dadbcfb88','節日同兒女小集倅有詩見戲答之','王洋','宋','宋诗','song-poetry','','[]','白首相看一病妻，也能舉桉與眉齊。',64,'全唐诗/poet.song.97000.json','["白首相看一病妻，也能舉桉與眉齊。", "誨兒共織龎翁竹，養氣多慚紀渻雞。", "作惡不須嗟室罄，驚魂長幸脱征鼙。", "團欒欲說無生話，試借先生刮眼鎞。"]'),
('e1bc034c-c1b6-4183-8fec-df484f71e2b0','和江如晦  其一','王洋','宋','宋诗','song-poetry','','[]','蕭寺姑分一日光，人生同調穩相當。',64,'全唐诗/poet.song.97000.json','["蕭寺姑分一日光，人生同調穩相當。", "空齋夜語規前哲，带酒論文恐老狂。", "三獻三休真琬琰，一前一卻笑螳蜋。", "君家江左才名舊，會向長塗一振驤。"]'),
('491436d7-2749-4a3e-b18d-bfd9648df75f','和江如晦  其二','王洋','宋','宋诗','song-poetry','','[]','婦未生兒先製名，人生適意但隨情。',64,'全唐诗/poet.song.97000.json','["婦未生兒先製名，人生適意但隨情。", "有無何預它人事，輪奐當期異日成。", "收拾功名須義勇，較量得失是心兵。", "鄙文不用量輕重，久已無心羡世榮。"]'),
('a39a7b30-3933-4c8d-afa5-36476a7bf992','和黄朝請  其一','王洋','宋','宋诗','song-poetry','','[]','謀身學業愧淵雲，急退還慚谷口真。',64,'全唐诗/poet.song.97000.json','["謀身學業愧淵雲，急退還慚谷口真。", "可是有生同冗長，真成無補費精神。", "抽簪早覺宏圖遠，側席時聞妙語新。", "共道徵君似顔子，升堂今日見詩人。"]'),
('3a277640-867c-403e-87e0-396053f6458a','和黄朝請  其二','王洋','宋','宋诗','song-poetry','','[]','極目關山不斷雲，嶺梅開處若爲真。',64,'全唐诗/poet.song.97000.json','["極目關山不斷雲，嶺梅開處若爲真。", "沈迷簿領政無術，展拓詩章筆有神。", "夜市鬻茶如訪舊，曉粧吹頰自爭新。", "長溪西畔煙霞遠，聞有風光屬主人。"]'),
('c9f40584-15ee-4994-a7bf-4b678fa7e56a','和方丞觀棋詩兼戲戎琳二僧','王洋','宋','宋诗','song-poetry','','[]','會得頭頭理趣微，此如未會即傾欹。',64,'全唐诗/poet.song.97000.json','["會得頭頭理趣微，此如未會即傾欹。", "試看一路爭先着，何異三乘占上機。", "但使無心須百勝，多因弄巧陷重圍。", "條條白黑分明路，苦被旁觀指是非。"]'),
('aa1e3a65-361c-4ca4-8fd8-68a1e2f8b8e7','和呂令見寄','王洋','宋','宋诗','song-poetry','','[]','莫話艱難徧九區，門前咄咄尚堪沽。',64,'全唐诗/poet.song.97000.json','["莫話艱難徧九區，門前咄咄尚堪沽。", "眼中寒暑頻傷雁，閑裏心情要憶鱸。", "政似釣璜歸大老，詩能引士愧非夫。", "暄風暖日明年事，共樂烘春造化爐。"]'),
('4ac20ced-a071-4c06-b1d5-fa2406ddbaa1','和平甫','王洋','宋','宋诗','song-poetry','','[]','八節灘頭老醉吟，年來愁也不勝禁。',64,'全唐诗/poet.song.97000.json','["八節灘頭老醉吟，年來愁也不勝禁。", "須知到處難忘酒，有意來時且抱琴。", "欲與君游忘世慮，若非吾事莫關心。", "相期早晚塵緣外，共訪毗耶聽梵音。"]'),
('66e7ef8e-c214-4ecd-bdc0-d00dfcda4517','和謝方智善','王洋','宋','宋诗','song-poetry','','[]','瀟湘十畝弄柔猗，獨染啼斑事已奇。',64,'全唐诗/poet.song.97000.json','["瀟湘十畝弄柔猗，獨染啼斑事已奇。", "但愛波聲鳴犖确，不須蠅翅避琉璃。", "莫疑山路崎嶇險，解脱繩橋性命危。", "慚愧平生竹上座，得相隨處每相持。"]'),
('d2ef64b5-23a7-4cd0-8e53-a3f71d9b92fb','和聖求','王洋','宋','宋诗','song-poetry','','[]','桃花人面共春風，人去桃花自笑紅。',64,'全唐诗/poet.song.97000.json','["桃花人面共春風，人去桃花自笑紅。", "撩亂絮飛春物後，依稀雲散夢魂中。", "鶯遷是處皆良友，蝶化知誰是主翁。", "莫訝求仙杳無信，賣花人過小橋東。"]'),
('045c354b-e0a8-43de-a1de-60748a2ddf1c','和叔穎楮衾','王洋','宋','宋诗','song-poetry','','[]','自顧生來骨相屯，不容强覓綵衣輕。',64,'全唐诗/poet.song.97000.json','["自顧生來骨相屯，不容强覓綵衣輕。", "榮華地位無多子，寂寞因緣已半生。", "我擁素衾方自喜，君貽組句遂兼榮。", "書窗對榻仍搖腹，誰道挑燈夢不成。"]'),
('d59982b6-8cab-4c6b-b8a5-471b4da5371c','酬凌季文過楊仲誠','王洋','宋','宋诗','song-poetry','','[]','慢綠遲紅靜不爭，小梯斜倚上空明。',64,'全唐诗/poet.song.97000.json','["慢綠遲紅靜不爭，小梯斜倚上空明。", "日篩竹影花奴睡，人度禾場吠犬驚。", "散帙未甘書效晚，攜笻獨喜病骸輕。", "排芳穿密多幽處，後日相期子細行。"]'),
('02c0eeaf-b283-4e45-9e62-205d1a428062','和朱秘校惠詩二首  其一','王洋','宋','宋诗','song-poetry','','[]','了了臞儒說舊章，三鍾初試楚金良。',64,'全唐诗/poet.song.97000.json','["了了臞儒說舊章，三鍾初試楚金良。", "當年尚老君方壯，此道催人意已忘。", "懶逐肥塵規冷炙，甘同貧女借餘光。", "誰家春草能終惠，惆悵還同病乘黄。"]'),
('894bee47-2c92-47e5-b2b7-409790c6bb01','和朱秘校惠詩二首  其二','王洋','宋','宋诗','song-poetry','','[]','短檠燈火幾經秋，古遠人疏道不侔。',64,'全唐诗/poet.song.97000.json','["短檠燈火幾經秋，古遠人疏道不侔。", "可惜詩書架三萬，不如奴婢橘千頭。", "顔回賦祿唯簞食，林類當春亦破裘。", "見說老人懷舊事，夢中吹笛更能不。"]'),
('486da7ea-68dc-40d8-a254-c8c167398f51','和吳朝議  其一','王洋','宋','宋诗','song-poetry','','[]','小說風烟已自佳，前峰矗矗爲盤牙。',64,'全唐诗/poet.song.97000.json','["小說風烟已自佳，前峰矗矗爲盤牙。", "千重巖壑名卿宅，一簇樓臺刺史家。", "自愧虛涼無物望，難將術業向人誇。", "所聞政績刊金石，刻畫無鹽學篆沙。"]'),
('3500d63c-3a5d-4a3e-ba68-08782a93c29b','和吳朝議  其二','王洋','宋','宋诗','song-poetry','','[]','自是天公亦厭艱，十年戰士好休閑。',64,'全唐诗/poet.song.97000.json','["自是天公亦厭艱，十年戰士好休閑。", "胡兒弓射燕陲月，漢將心馳海上山。", "慶事頻聞輸帝府，好音傳落到人間。", "丈人自是朝廷舊，早趁鵷鸞入近班。"]'),
('453aa261-894a-497e-a31a-9dd741b11003','謝運屬秘書惠詩','王洋','宋','宋诗','song-poetry','','[]','雪撲征鞍岸漲沙，不辭天闕去程賒。',64,'全唐诗/poet.song.97000.json','["雪撲征鞍岸漲沙，不辭天闕去程賒。", "江梅笑處人爲客，仙桂香時雁到家。", "秦地少年應辦酒，江南詞客好酬花。", "錦衣綵仗還鄉路，欲訪萍蹤問釣槎。"]'),
('3d7f5773-2cc1-4b36-a93e-52425a7f9e73','謝邵武危秀才惠長牋','王洋','宋','宋诗','song-poetry','','[]','須知秋日勝春朝，一鶴凌空振羽毛。',64,'全唐诗/poet.song.97000.json','["須知秋日勝春朝，一鶴凌空振羽毛。", "滿軸文章慰衰病，十年燈火困英豪。", "良醫先爲肱三折，合負終看釣六鼇。", "鄭老襟期幸同調，新詩時與寄亭臯。"]'),
('34ea0626-7af1-4dd6-bde4-659eacd2d6b9','以越箋與三四弟有詩次韻','王洋','宋','宋诗','song-poetry','','[]','無復花生拙筆頭，一生長負剡藤羞。',64,'全唐诗/poet.song.97000.json','["無復花生拙筆頭，一生長負剡藤羞。", "過門多是陳驚坐，得句誰憐趙倚樓。", "社友書來頻寄語，山翁鬢已不禁秋。", "老干仙去吾宗冷，有繼華星一字不。"]'),
('9a1bb3a6-c9c4-4e25-ba63-28d5d6347efb','謝呂令子卿雪中遣人惠酒初令人置酒于祝舜俞呂令以酒爲惠云','王洋','宋','宋诗','song-poetry','','[]','也知謀醉勝謀閑，戶小都忘滿腹慳。',64,'全唐诗/poet.song.97000.json','["也知謀醉勝謀閑，戶小都忘滿腹慳。", "晚得麴生投老伴，長邀玉友訪空山。", "初貪雪裏香宜倍，忽報缾中酒自還。", "全勝朱提雙飲盞，親教從事送酡顔。"]'),
('4e99f321-88ff-4133-960c-139f339b97c1','王提幹送雲安春色以詩還酒尊','王洋','宋','宋诗','song-poetry','','[]','萬里關河未說長，亡何鄉是醉中鄉。',64,'全唐诗/poet.song.97000.json','["萬里關河未說長，亡何鄉是醉中鄉。", "客居江館當炎熱，春日雲安逸色香。", "沽水童奴思給酒，乞錢司業更傳觴。", "藍橋不用鴛鴦語，只合壺中貯玉漿。"]'),
('7f94f124-1adb-4c52-85cc-cbf584a71054','陳長卿凌季文自弋陽寄酒麴以詩謝之','王洋','宋','宋诗','song-poetry','','[]','六十行年兩鬢蒼，興來猶愛引杯長。',64,'全唐诗/poet.song.97000.json','["六十行年兩鬢蒼，興來猶愛引杯長。", "黄翁壚下山河遠，酒母車來驛傳香。", "碧落侍郎燒鼎訣，粉闈仙客駐顔方。", "三斟卯飲心無事，一枕亡何是故鄉。"]'),
('a3144706-ad79-492d-8696-8dcab644b70f','曾法師嘗寄蒲萄追作一篇','王洋','宋','宋诗','song-poetry','','[]','自分蔬腸甘苜蓿，那煩遠騎送蒲萄。',64,'全唐诗/poet.song.97000.json','["自分蔬腸甘苜蓿，那煩遠騎送蒲萄。", "青條自有悠揚勢，甘液多因灌溉勞。", "坐見滿盤堆馬乳，全勝千里惠鵝毛。", "病來苦不勝杯杓，今日思君飲濁醪。"]'),
('af7fd11d-e1af-4e1b-98fa-8fda9a22f098','曾谹父惠黄龍菜','王洋','宋','宋诗','song-poetry','','[]','朝日團團上碧峰，蔬盤牢饌四時同。',64,'全唐诗/poet.song.97000.json','["朝日團團上碧峰，蔬盤牢饌四時同。", "園供小摘添幽事，雨打寒菘带晚濃。", "可但拈香參玉版，直須進步禮黄龍。", "溪堂炊甑容千客，不打闍黎飯後鐘。"]'),
('91390069-036c-4ecc-aa89-5ac00c4740bf','挽向伯恭  其一','王洋','宋','宋诗','song-poetry','','[]','十里林花带月蘿，壠頭車馬斷經過。',64,'全唐诗/poet.song.97000.json','["十里林花带月蘿，壠頭車馬斷經過。", "可憐人物今如此，試問天公事若何。", "籬下淵明惟酒菊，舟中范子任煙波。", "璇題金榜垂霄漢，千古榮名定不磨。"]'),
('1802532e-1373-49a2-86cf-4a71d27cb696','挽向伯恭  其二','王洋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','絕代風流世所希，如公真是命難推。',64,'全唐诗/poet.song.97000.json','["絕代風流世所希，如公真是命難推。", "三辭令尹髙前哲，兩挂儒冠當盛時。", "丞相耐官天語貴，左師習禮楚人知。", "試看流慶當何似，滚滚長江不盡期。"]'),
('9822b4f1-440f-4aab-afff-1e7072ae1c4e','挽徐次翁  其一','王洋','宋','宋诗','song-poetry','','[]','仁義功髙澤子孫，衣冠由是古王門。',64,'全唐诗/poet.song.97000.json','["仁義功髙澤子孫，衣冠由是古王門。", "位升五品鵷鸞貴，政在三州民社尊。", "一旐豈期江漢遠，千年惟有德風存。", "了知大末淵源在，功業臯夔付後昆。"]'),
('0b4b9035-5781-4c75-97ac-e5d647e2fa6d','挽徐次翁  其二','王洋','宋','宋诗','song-poetry','','[]','自想溫容耳誨詞，他鄉已恨重分違。',64,'全唐诗/poet.song.97000.json','["自想溫容耳誨詞，他鄉已恨重分違。", "送人作守乘軒去，結草爲靈象俑歸。", "會合只如風過燭，花陰何異月澄輝。", "相門子婿諸侯服，除卻清名百事非。"]'),
('ba47dc53-e506-41de-ab04-c227fe76a753','挽喬民瞻','王洋','宋','宋诗','song-poetry','','[]','楚鄉槐市憶當年，錦繡文章六藝先。',64,'全唐诗/poet.song.97000.json','["楚鄉槐市憶當年，錦繡文章六藝先。", "朱紱哀憐應有在，白頭故舊各淒然。", "修文地下埋英骨，遺愛江城付綵編。", "造化於公意良厚，不教丹旐涉長川。"]'),
('7caf38f5-9176-448c-b03b-325dff54f9fe','挽向倅','王洋','宋','宋诗','song-poetry','','[]','耐官丞相山河業，靖國簾帷社稷勳。',64,'全唐诗/poet.song.97000.json','["耐官丞相山河業，靖國簾帷社稷勳。", "四姓風流傳學問，三朝潤澤慶來雲。", "重車折軸人何力，積閥傳家子有文。", "史筆它時汗青簡，左師家譜紹清芬。"]'),
('7c904ca7-8e41-46cd-b046-64f3c4f4e93d','王侍郎挽章','王洋','宋','宋诗','song-poetry','','[]','當年幕府拜英遊，十載烏絲換白頭。',64,'全唐诗/poet.song.97000.json','["當年幕府拜英遊，十載烏絲換白頭。", "城郭俱非前日夢，關山如舊一天愁。", "詩人已作潭移影，往事休論江自流。", "物色佳城閉何許，西山凝望不勝秋。"]'),
('973c8dbc-a34d-413a-a07d-6e7c15603771','挽玉山詹教授','王洋','宋','宋诗','song-poetry','','[]','鶴髪雙親歲月殘，既霑三釜即心歡。',64,'全唐诗/poet.song.97000.json','["鶴髪雙親歲月殘，既霑三釜即心歡。", "廣文未脱一官冷，范叔寧忘昔日寒。", "文中八科名益重，魂歸千里命尤難。", "後生它日思風範，只向傳銘石上看。"]'),
('e6209e25-c418-4768-a1d1-5d2c8cb11eca','哭周秀實  其一','王洋','宋','宋诗','song-poetry','','[]','餘英初約轉舡蓬，二載廬陵郡課同。',64,'全唐诗/poet.song.97000.json','["餘英初約轉舡蓬，二載廬陵郡課同。", "官簿縱居時俊後，詩名舊列昔賢中。", "三斟屢酌前溪月，一瞬曾帆下渚風。", "千里音容從此絕，夢隨江水遠朝東。"]'),
('4d765f35-f0bd-46a2-89c8-258e62f571a0','哭周秀實  其二','王洋','宋','宋诗','song-poetry','','[]','翁來謂有世間情，翁棄人寰一葉輕。',64,'全唐诗/poet.song.97000.json','["翁來謂有世間情，翁棄人寰一葉輕。", "白玉樓成金闕峻，步虛章就紫霄清。", "笑談烈焰懷飛壁，寂寞空潮自打城。", "大筆如椽石似玉，何人爲與說平生。"]'),
('91758029-6682-463c-a394-10d724f70d87','哭宋文淵  其一','王洋','宋','宋诗','song-poetry','','[]','清懷凛凛古人風，尚憶當年語意同。',64,'全唐诗/poet.song.97000.json','["清懷凛凛古人風，尚憶當年語意同。", "開口劍鋒初論事，歸林弱羽已傷弓。", "累朝因革襟懷內，四海悲歡指顧中。", "寂寞門闌感恩客，曾將頑質謝磨礱。"]'),
('5d67efc5-3627-4459-a5c0-bf96abc966a2','哭宋文淵  其二','王洋','宋','宋诗','song-poetry','','[]','藹藹聲華動帝宸，一時車馬走芳塵。',64,'全唐诗/poet.song.97000.json','["藹藹聲華動帝宸，一時車馬走芳塵。", "文如屈宋才仍富，心似皋夔道已醇。", "身後功名因報主，生前勛業爲憂民。", "知公本意安劉氏，不許身危更累親。"]'),
('6ea287b0-e400-490e-9691-28b2ac2a73ff','哭沈行彦宫教','王洋','宋','宋诗','song-poetry','','[]','氣迥神清形骨立，藍綬紆腰垂四十。',64,'全唐诗/poet.song.97000.json','["氣迥神清形骨立，藍綬紆腰垂四十。", "年侵運櫛髪蒙絲，日晚煮黎羹不粒。", "教司胄子祿方來，日薄西山風已急。", "平生失意固多端，忽向幽泉猶飲泣。"]'),
('c09c9a3a-b4d5-45fc-a523-b4bb6d673822','挽黄夫人','王洋','宋','宋诗','song-poetry','','[]','官棲枳棘莫消魂，身託絲蘿在德門。',64,'全唐诗/poet.song.97000.json','["官棲枳棘莫消魂，身託絲蘿在德門。", "三后姻聫門戶重，貳卿閲閥德名尊。", "傷心結蟻靈轜遠，保室鳴鳩道化存。", "爲問如何慰冥漠，飽聞中外有蘭孫。"]'),
('8c4e5db1-a3f9-4b7b-8f1b-81ae7fbd373d','挽楊承事幷夫人詩二首  其一','王洋','宋','宋诗','song-poetry','','[]','除卻家傳教子經，世間百事不營營。',64,'全唐诗/poet.song.97000.json','["除卻家傳教子經，世間百事不營營。", "自應藝學推前輩，故得風流勸後生。", "疏傅揮金終足食，徐卿有子自成名。", "後来若不流餘慶，真享千鍾亦未榮。"]'),
('d8fa40c8-e6d3-4d99-96d2-99434b5a0d4d','挽楊承事幷夫人詩二首  其二','王洋','宋','宋诗','song-poetry','','[]','夢協幽蘭故可誇，來從君子更宜家。',64,'全唐诗/poet.song.97000.json','["夢協幽蘭故可誇，來從君子更宜家。", "疏恩自合開新邑，比德還應副六珈。", "解使威儀同詁訓，聊隨輕薄事鈆華。", "自從瑤瑟初扃後，檻外春風懶放花。"]'),
('be540ac0-83f4-4099-b557-0266e4160514','哭孀嫂  其一','王洋','宋','宋诗','song-poetry','','[]','文章夫子才難盡，孝弟人言報自賒。',64,'全唐诗/poet.song.97000.json','["文章夫子才難盡，孝弟人言報自賒。", "四事先生俱擅世，一塗後裔不傳家。", "歲當豐暖偏寒餒，朝正歡娛獨歎嗟。", "報施若教長似此，幾人守道不回邪。"]'),
('c75beecb-23fb-49d6-b237-ba98c8df2ef9','哭孀嫂  其二','王洋','宋','宋诗','song-poetry','','[]','雙眼失明二十載，一身病臥四週年。',64,'全唐诗/poet.song.97000.json','["雙眼失明二十載，一身病臥四週年。", "俱生孤女眼前死，諸御四兒姑幸全。", "徧歷人間真苦惱，略無身後好因緣。", "靜思四十六年事，一夢三生業夢圓。"]'),
('d1df579e-d758-4ce8-8c7e-7e4b32ea6c80','目疾','王洋','宋','宋诗','song-poetry','','[]','天公嗔我眼長白，故著昏埃阿堵中。',64,'全唐诗/poet.song.97000.json','["天公嗔我眼長白，故著昏埃阿堵中。", "不怪參軍談瞎馬，但妨中散送飛鴻。", "著籬令惡誰能對，損讀方奇定有功。", "九惱從來是佛種，會如那律證圓通。"]'),
('d04ac5b1-a5a1-4aaf-af5f-43351f4b6974','和李商隱賦紅梅  其一','王洋','宋','宋诗','song-poetry','','[]','公主簷間睡起時，勻紅行繞大安池。',64,'全唐诗/poet.song.97000.json','["公主簷間睡起時，勻紅行繞大安池。", "北人未識春迷眼，妃子偏憐酒入肌。", "更若施朱疑太赤，不須生女白如脂。", "由來風骨都相似，豈爲丹青别賦詩。"]'),
('86a3495d-0cd3-4578-b833-f60b02811919','和李商隱賦紅梅  其二','王洋','宋','宋诗','song-poetry','','[]','梅蘂年年破臘時，玉花飛舞集鸞池。',64,'全唐诗/poet.song.97000.json','["梅蘂年年破臘時，玉花飛舞集鸞池。", "獨将艷色添真色，任爾冰肌映雪肌。", "带恨不妨紅作淚，洗粧終見白凝脂。", "可憐渠有風流句，只作歌詞不作詩。"]'),
('6dd79c9b-25fa-469f-87bc-0e17f9c0f878','和方智善兩色梅','王洋','宋','宋诗','song-poetry','','[]','春到冬餘去住間，玉樓無處不輕寒。',64,'全唐诗/poet.song.97000.json','["春到冬餘去住間，玉樓無處不輕寒。", "鮮鮮魏女履下履，粲粲真妃冠上冠。", "眼亂互搖歌扇羽，心驚添著粉闈幱。", "東君厚薄非無意，一種馨香兩眼看。"]'),
('94259797-a362-4156-9d9c-d9ff39810de1','書窗梅花數枝病起再見缾中盛開因作','王洋','宋','宋诗','song-poetry','','[]','書堂籬落冷如灰，十日相忘亦自猜。',64,'全唐诗/poet.song.97000.json','["書堂籬落冷如灰，十日相忘亦自猜。", "初訝凍枝無艷脈，那知寒室自花開。", "銅缾結實元非種，蔀屋迎春似有媒。", "方信陽和滿天地，不須人力費根栽。"]'),
('95c195ca-b7eb-429f-b0e4-fba226ff2360','貴溪尉廳黄梅盛開濃香豐艷非凡品可及尉坐此速招客因成小詩戲之','王洋','宋','宋诗','song-poetry','','[]','歌酬花意醉酬春，笑口相逢可厭頻。',64,'全唐诗/poet.song.97000.json','["歌酬花意醉酬春，笑口相逢可厭頻。", "不飲正疑花怨客，典衣莫聽婦傷貧。", "天生尤物非爲福，蚌有明珠亦累身。", "墻裏佳人墻外笑，冶容招悔豈無因。"]'),
('ccd04ace-d20a-496f-acf3-430dc5881e0f','觀瑞香杏花二首 瑞香','王洋','宋','宋诗','song-poetry','','[]','陌上春風已半酣，薰籠院靜怯輕寒。',64,'全唐诗/poet.song.97000.json','["陌上春風已半酣，薰籠院靜怯輕寒。", "織成花錦傳香密，養就嬌羞對客難。", "山路不知清夢遠，宫衣猶惜舊花殘。", "若将品第分髙下，須向芝蘭格外看。"]'),
('6e27f7c8-eb89-405c-b980-0839f3685acd','觀瑞香杏花二首 杏花','王洋','宋','宋诗','song-poetry','','[]','絳萼紅顋带露肥，燒林長近禁烟期。',64,'全唐诗/poet.song.97000.json','["絳萼紅顋带露肥，燒林長近禁烟期。", "且容北郭通鄰徑，若比南枝較發遲。", "曲水岸邉尋舊事，賣花擔上揀繁枝。", "香韉一色垂楊路，何似吳王宫裏時。"]'),
('7949810f-fb5c-4f72-9ad9-eeedf00fbac9','和陳長卿賦芭蕉二首  其一','王洋','宋','宋诗','song-poetry','','[]','落落虚懷好自珍，一番舒展一番新。',64,'全唐诗/poet.song.97000.json','["落落虚懷好自珍，一番舒展一番新。", "搖風捲起窗鋪月，滴雨驚回夢愴神。", "荔子丹時陪獻豆，丁香結處共愁塵。", "本無顔色爭韶艷，野老由來不怨春。"]'),
('edc54eb3-491d-4ce1-b8ca-7aa589acb375','和陳長卿賦芭蕉二首  其二','王洋','宋','宋诗','song-poetry','','[]','一幅青天世外珍，詩人得句共清新。',64,'全唐诗/poet.song.97000.json','["一幅青天世外珍，詩人得句共清新。", "書生几上側理紙，巫女廟中巴峽神。", "長恐天寒憑日暮，不将翠袖染緇塵。", "世間荷葉幷蕉葉，不與紅芳競占春。"]'),
('bb22a22a-cb4a-44fa-bcd0-dd815703756e','賦洞庭柑','王洋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','兩潮船上别蘇台，歲歷侵人鶴化胎。',64,'全唐诗/poet.song.97000.json','["兩潮船上别蘇台，歲歷侵人鶴化胎。", "霜實可憐今入眼，佳人何日問重來。", "黄金丸逐驚飛肉，白露團凝别恨腮。", "重待扁舟落吾手，爲君先報柳郎回。"]'),
('d4ff36fe-d1ae-453c-a22a-6ff9d1035c15','谹父得洞庭柑分送往往難遇賞者因成小詩','王洋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','綠玉波心聳絳台，丹霞道士日傳胎。',64,'全唐诗/poet.song.97000.json','["綠玉波心聳絳台，丹霞道士日傳胎。", "仙人不惜黄金貴，海蜃搖驚驛使來。", "玉食光輝天著力，主家春色雪融顋。", "手中三日香猶在，不是吳姬乞打回。"]'),
('b5cb0ee6-d22a-414a-ace8-61e047618242','谹父出示趙倅木犀詩次韻','王洋','宋','宋诗','song-poetry','','[]','黄姑斸月種文犀，落向三秋月滿時。',64,'全唐诗/poet.song.97000.json','["黄姑斸月種文犀，落向三秋月滿時。", "巖邑疏封兄弟國，銅缾分派子孫枝。", "漢宫明艷塗嬌額，仙鼎珍丹散漉籬。", "好趁燈花同報喜，黄間金粟正相宜。"]'),
('91f85ad6-b8d8-4f88-bd9b-fe8ef84e5258','趙倅兼善再用前韻賦木犀','王洋','宋','宋诗','song-poetry','','[]','物外家風本自奇，人間獨步九秋時。',64,'全唐诗/poet.song.97000.json','["物外家風本自奇，人間獨步九秋時。", "誰登月姊青霄露，折得郄詵丹桂枝。", "韞玉巖扉通戶牖，蘂珠花殿徹藩籬。", "淵明不共真香醉，只與黄花作便宜。"]'),
('28b2ad2b-4e30-41bc-afb3-99a95e7fcbad','茶荈','王洋','宋','宋诗','song-poetry','','[]','蠧關草掩日蕭疏，自汲寒缾煮澗蔬。',64,'全唐诗/poet.song.97000.json','["蠧關草掩日蕭疏，自汲寒缾煮澗蔬。", "早愧空腸添雪乳，何須雜珮列瓊琚。", "往陪雪繭千重貴，顧試鈆刀一割如。", "風露滿樓人未散，小窗應爲賦歸歟。"]'),
('28a94d3a-ad9a-48aa-bc47-bc9299dc5a7c','龍涎香','王洋','宋','宋诗','song-poetry','','[]','搴露紉荷楚澤舷，未參南海素馨仙。',64,'全唐诗/poet.song.97000.json','["搴露紉荷楚澤舷，未參南海素馨仙。", "大門當得桂花酒，小様時分寶月圓。", "詩挾少陵看妙手，犀通神物爲垂涎。", "使君少住幽蘭曲，時傍顰山照鬢邉。"]'),
('3d20c57a-57d0-43f2-aa23-e1be656a4521','得丁求安書云叠石境于溪心嵲然如江上之磯作二詩戲之  其一','王洋','宋','宋诗','song-poetry','','[]','心重吳山老，天教閑許長。',24,'全唐诗/poet.song.97000.json','["心重吳山老，天教閑許長。", "事多因醉遣，心半爲山忙。"]'),
('9d8a7c0f-5e98-4829-817f-99b43159af6a','得丁求安書云叠石境于溪心嵲然如江上之磯作二詩戲之  其二','王洋','宋','宋诗','song-poetry','','[]','立石標溪界，疏荷限水香。',24,'全唐诗/poet.song.97000.json','["立石標溪界，疏荷限水香。", "此翁三十載，看了幾人忙。"]'),
('4eb42778-0490-4947-adb0-d96d46275a83','梅二首  其一','王洋','宋','宋诗','song-poetry','','[]','隔闊已經歲，相逢不置辭。',24,'全唐诗/poet.song.97000.json','["隔闊已經歲，相逢不置辭。", "情如淡交久，處士合吟詩。"]'),
('4825d4f5-9aa9-4609-861d-60b0502888fe','梅二首  其二','王洋','宋','宋诗','song-poetry','','[]','勝韻難齊俗，清流不受渾。',24,'全唐诗/poet.song.97000.json','["勝韻難齊俗，清流不受渾。", "豈應踐期約，獨自愛黄昏。"]'),
('19b5182d-4195-4c7f-9321-1c8b3225188d','和固道韻問谹父小疾  其一','王洋','宋','宋诗','song-poetry','','[]','木落亭皋遠思，疏簾清簟棋聲。',28,'全唐诗/poet.song.97000.json','["木落亭皋遠思，疏簾清簟棋聲。", "閉門十日知否，風月愁人敗盟。"]'),
('977fa578-974b-40ef-9342-dce3ee42c364','和固道韻問谹父小疾  其二','王洋','宋','宋诗','song-poetry','','[]','舊傳傳箭聊城，海內群工舊名。',28,'全唐诗/poet.song.97000.json','["舊傳傳箭聊城，海內群工舊名。", "况有文章老伴，朱顔碧落仙卿。"]'),
('c7edbddb-3e1d-4ea6-9bc7-275773a03047','和固道韻問谹父小疾  其三','王洋','宋','宋诗','song-poetry','','[]','惆悵休尋舊事，酣歌且數前山。',28,'全唐诗/poet.song.97000.json','["惆悵休尋舊事，酣歌且數前山。", "待君蒼蘚重拂，相逐寧論興闌。"]'),
('b6ff4791-048e-410b-a456-d8804d1aea0a','幽園即事四首  其一','王洋','宋','宋诗','song-poetry','','[]','屋頭積雨漲春雪，舍北夭桃堆暮霞。',32,'全唐诗/poet.song.97000.json','["屋頭積雨漲春雪，舍北夭桃堆暮霞。", "細雨斜風妨病起，窗間把玩數枝花。"]'),
('b56d0eaa-4afc-423b-9651-23d611b53921','幽園即事四首  其二','王洋','宋','宋诗','song-poetry','','[]','籬邊楊柳似羅敷，裊裊娉娉十五餘。',32,'全唐诗/poet.song.97000.json','["籬邊楊柳似羅敷，裊裊娉娉十五餘。", "無賴風光相料理，忽看柯葉可藏烏。"]'),
('b8e48c7f-d4b6-43e9-b218-c5241f4a861e','幽園即事四首  其三','王洋','宋','宋诗','song-poetry','','[]','殘梅依草遣愁盡，細草緣階滿意生。',32,'全唐诗/poet.song.97000.json','["殘梅依草遣愁盡，細草緣階滿意生。", "莫道中年春思少，每逢佳處眼偏明。"]'),
('34b29db0-8cb4-409d-829b-cfa9c3cd2c3e','幽園即事四首  其四','王洋','宋','宋诗','song-poetry','','[]','曉窗晴哢丁寧語，晚樹幽花委曲香。',32,'全唐诗/poet.song.97000.json','["曉窗晴哢丁寧語，晚樹幽花委曲香。", "散策尋春不知遠，片雲作雨度回塘。"]'),
('0f74377d-839a-41a3-9205-10bb30dcb1a3','遣興','王洋','宋','宋诗','song-poetry','','[]','老如認老應無病，貧要安貧可免憂。',32,'全唐诗/poet.song.97000.json','["老如認老應無病，貧要安貧可免憂。", "貧病欺人須服弱，嗔拳笑面卻應休。"]'),
('464f1ac8-ea52-4d96-b3ab-c327dda7ce75','遷學','王洋','宋','宋诗','song-poetry','','[]','闕里荆榛一掃除，文明猶是舊規模。',32,'全唐诗/poet.song.97000.json','["闕里荆榛一掃除，文明猶是舊規模。", "要令多士充庭賦，能識邦君此意無。"]'),
('cff90641-2027-420f-9b67-c34081c09307','聞詔下示兒姪','王洋','宋','宋诗','song-poetry','','[]','一封丹詔聘儒林，裋褐書生競拂衿。',32,'全唐诗/poet.song.97000.json','["一封丹詔聘儒林，裋褐書生競拂衿。", "發憤正須先賈勇，莫教空望狀元心。"]'),
('0b3b5460-4f35-4579-a96d-a8d81908042b','焚黄誥','王洋','宋','宋诗','song-poetry','','[]','伶俜族緒不堪論，兄弟相持老僅存。',32,'全唐诗/poet.song.97000.json','["伶俜族緒不堪論，兄弟相持老僅存。", "方信有生同造化，君恩猶得賁丘園。"]'),
('182973c3-4d41-4ced-9f13-64fc7961972b','徐氏幼婦以花獻几筵婦髙甥也','王洋','宋','宋诗','song-poetry','','[]','前徐愛孝世相傳，日薦珍嘗不計年。',32,'全唐诗/poet.song.97000.json','["前徐愛孝世相傳，日薦珍嘗不計年。", "便合一生成婦順，旅酬今始見初筵。"]'),
('ec0fe28a-b36f-49a7-a843-428b65da6be9','近陋室以斗升釀家婦謂予未飲不以見告昨夜偷兒入室挈二壺去自此室中又復索寞今後酒熟便呼近鄰痛飲遇夜守視庻大家着力也呈諸兄兼簡士修思遠三首  其一','王洋','宋','宋诗','song-poetry','','[]','斗米蒸炊入小罌，未應消息到比鄰。',32,'全唐诗/poet.song.97000.json','["斗米蒸炊入小罌，未應消息到比鄰。", "靜思懷璧真成罪，恐是糟牀夜滴聲。"]'),
