('1e6d9774-3b50-43cd-be69-87ba065ca400','瓊花','王洋','宋','宋诗','song-poetry','','[]','愛奇造物剪瓊瑰，爲鎮靈祠特地栽。',64,'全唐诗/poet.song.97000.json','["愛奇造物剪瓊瑰，爲鎮靈祠特地栽。", "事紀揚州千古勝，名居天下萬花魁。", "何人斵却依然在，甚處移來不肯開。", "浪說八仙模樣似，八仙安得有香來。"]'),
('0c4c8883-d916-4cd8-a0dc-a9344f047663','觀中芙蓉盛開','王洋','宋','宋诗','song-poetry','','[]','秋木日動搖，秋容日脩整。',144,'全唐诗/poet.song.97000.json','["秋木日動搖，秋容日脩整。", "況復白琳宮，焚香事幽屏。", "胡爲彼美人，犯此清凈境。", "仙官儼環珮，注目朝倒景。", "豈容正法眼，泛愛冶色靚。", "得非葉太清，宿念未灰冷。", "北斗春已足，三山夢初醒。", "曰鱗貴女子，俗目未可騁。", "慣聽步虛詞，生便浮館靜。", "那知羽衣人，文成僞心猛。", "記語東方兒，偷桃不可幸。", "共待月滿除，蕭蕭散疏影。"]'),
('a52f2f1d-9551-4f91-9e9a-e352f7abfee4','句','僊上人','宋','宋诗','song-poetry','','[]','男兒三十未有立，人世百年徒自勞。',16,'全唐诗/poet.song.97000.json','["男兒三十未有立，人世百年徒自勞。"]'),
('a4e053b4-e412-4a4c-908e-b51e95bcd020','修修窗前蘆','鄭剛中','宋','宋诗','song-poetry','','[]','修修窗前蘆，孤瘦倚青玉。',84,'全唐诗/poet.song.97000.json','["修修窗前蘆，孤瘦倚青玉。", "心虚知夜凉，風葉亂相觸。", "使我入幽夢，如在江湖宿。", "方兹困炎曦，愛爾眼中綠。", "奈何柔脆姿，行犯秋氣肅。", "霏霏霜露中，菱荷等摧覆。", "大抵無勁節，不及歲寒竹。"]'),
('0506caf6-d950-4a8e-a6ff-c7532017b624','砌下兩修竹','鄭剛中','宋','宋诗','song-poetry','','[]','砌下兩修竹，翠色含烟新。',96,'全唐诗/poet.song.97000.json','["砌下兩修竹，翠色含烟新。", "盡日肯相對，蕭然如可人。", "清風動搖虚，亦不厭我貧。", "時時一相過，吹拂席上塵。", "二物有嘉意，慰我窮悴身。", "常觀有道者，尚與鹿豕群。", "奚必廣團聚，鬨鬨如飛蚊。", "清風與修竹，吾不失所親。"]'),
('220ba109-d246-4f4d-a2f7-6f7d2071660d','讀坡詩','鄭剛中','宋','宋诗','song-poetry','','[]','公詩如春風，著物便新好。',84,'全唐诗/poet.song.97000.json','["公詩如春風，著物便新好。", "春風常自然，初不費雕巧。", "又如荆山玉，不問多與少。", "傳流落人間，皆作希世寶。", "吾獨恨造物，生我殊不早。", "不得拜堂下，朝夕事洒埽。", "追扳邈難及，清淚出幽抱。"]'),
('0fc28364-73e2-4015-9eb4-786c52a1558c','書齋夏日','鄭剛中','宋','宋诗','song-poetry','','[]','五月困暑濕，衆謂如蒸炊。',84,'全唐诗/poet.song.97000.json','["五月困暑濕，衆謂如蒸炊。", "惟我坐幽堂，心志適所怡。", "開窗面西山，野水平清池。", "菱荷間蒲葦，秀色相因依。", "幽禽蔭嘉木，水鳥時翻飛。", "文書任討探，風靜香如絲。", "此殆有至樂，難令俗子知。"]'),
('a4387188-a5ca-4575-b43f-4ca012b23e0a','寄别左與言','鄭剛中','宋','宋诗','song-poetry','','[]','寒生坐孤窮，浪迹遠羈寓。',120,'全唐诗/poet.song.97000.json','["寒生坐孤窮，浪迹遠羈寓。", "千金買卜龜，所用良失措。", "如聞過瓜期，騫揚引雄翥。", "放直州縣腰，闊作臺省步。", "念欲拜公别，心往足不赴。", "銘肌荷恩知，癡坐乖禮數。", "可但顔甲厚，頗亦背芒負。", "梅雨五月寒，洄洄綠烟樹。", "二嶺遮夢魂，不到船行處。", "安得赴雙槳，翩翩若鷗鷺。"]'),
('398fb7ea-3763-4ae4-b83b-6e9ced0e37f4','寄贈張叔靖','鄭剛中','宋','宋诗','song-poetry','','[]','堂堂張侯好眉宇，照人冰玉無塵土。',192,'全唐诗/poet.song.97000.json','["堂堂張侯好眉宇，照人冰玉無塵土。", "憶初解後共杯盤，姓字未通心已許。", "參商别後各天涯，屈指流年不勝數。", "何知策馬忽東來，扣我柴扉叙寒暑。", "相親顔色愈敷腴，不俗胸懷細傾吐。", "使人頻歲饑渴心，如飲甘泉餉腵脯。", "吾生寒苦衆所知，眼髙無人人不與。", "技窮漸覺蒲柳衰，進取一塗方首鼠。", "有心斸治土田園，束手抽身事農圃。", "荷鉏今亦粗成趣，頗有嘉蔬待春雨。", "所恨松根長茯苓，僻寂無人堪共煮。", "安得溪霜素月高，促膝與公長夜語。"]'),
('dfbda168-f8e1-42e6-a9be-e3d06604dd9d','謝潘令衛惠松木','鄭剛中','宋','宋诗','song-poetry','','[]','子美欲得廣厦千萬間，大庇天下寒士俱歡顔。',180,'全唐诗/poet.song.97000.json','["子美欲得廣厦千萬間，大庇天下寒士俱歡顔。", "嗟我一室久疏陋，風飄雨剝堵不環。", "欲具茅茨小編葺，斤斧四顧家無山。", "誰謂潘郎坐華屋，肯爲湫隘興永嘆。", "惠以南山好松柏，翦伐既就皆丸丸。", "我今樸斵遂有日，居處可望庵冗寬。", "方知廣厦庇寒士，子美之論非髙談。", "古人骨朽髙義盡，習爲鄙吝風俗慳。", "皆使如公眼青白，古人風義當復還。", "吾聞淵明謝主人，冥報止謂因盤餐。", "公今飯我德何啻，淵明詩來猶可攀。"]'),
('33f488db-5118-4a88-9078-4f694bd683aa','觀溪漲','鄭剛中','宋','宋诗','song-poetry','','[]','入夏天不雨，溪流僅成派。',132,'全唐诗/poet.song.97000.json','["入夏天不雨，溪流僅成派。", "一夜漲梅霖，拍岸輒澎湃。", "衝犯無隄防，奔騰起湍瀨。", "鷗鷺驚以翔，蝦魚鼓而快。", "聒耳如殷雷，聲勢殊未怪。", "曉風吹亂雲，日出陰氣退。", "所謂暴集者，縈紆已如带。", "浩浩北海若，遐想見尊大。", "溟漠函萬象，吞吐容百怪。", "小哉此溪流，其涸可立待。", "是以古君子，德量戒褊隘。"]'),
('80a19e14-8cfc-4382-9370-72c2bc729cbd','家有小園比他處果蓏倍登或問鄭子何術致此告之曰漢武帝使海上縣官親漁魚皆不出其後捐以予民則魚復來因知天之生物本以惠濟窮民彼富足者不可兼而得也吾貧甚矣安知造物者不以是少私之耶戲爲一詩','鄭剛中','宋','宋诗','song-poetry','','[]','吾聞縣官漁海魚不出，捐以予民魚乃復。',146,'全唐诗/poet.song.97000.json','["吾聞縣官漁海魚不出，捐以予民魚乃復。", "天之生物豈無意，殆欲憐貧補不足。", "吾家元無二頃田，卒歲何人分半菽。", "小園自幸有餘地，背負經書刀鋤斸。", "年來種植類櫜駝，隨手髙低便新綠。", "魁然瓜芋塞區肥，無數桃梅壓枝熟。", "既收弄暖開鬚麥，又摘多穰過拳粟。", "雖無蓄積累瓶盎，采掇猶能飫腸腹。", "天於此圃非偶然，坐作山居野人祿。"]'),
('ef991f42-3739-45d0-acf8-a8eeb4df11bd','罪回祿','鄭剛中','宋','宋诗','song-poetry','','[]','回祿爲火神，威權尤貴重。',120,'全唐诗/poet.song.97000.json','["回祿爲火神，威權尤貴重。", "年來何失職，權爲盜所弄。", "此盜假爾威，蜂蟻聚徒衆。", "煌煌萬炬光，灼燎隨所縱。", "烟氛障白日，烘炙盛騷動。", "老幼哭無家，禍虐人所共。", "使人不見此，聰明欲何用。", "神而審其然，可得亡制控。", "忍使盜意滿，生民負焦痛。", "爾過不可文，反躬當自訟。"]'),
('c9b260be-cc38-4f53-8f28-143987c9b0aa','辨畢方','鄭剛中','宋','宋诗','song-poetry','','[]','比屋皆良民，爲盜豈無以。',108,'全唐诗/poet.song.97000.json','["比屋皆良民，爲盜豈無以。", "富足義所生，貧窮盜之始。", "凍餓家無儲，追呼官不已。", "妖幻隨鼓之，安得不群起。", "縱火資盜威，勢固自應爾。", "可笑說者愚，輙欲效柳子。", "赤文而白章，召禍豈其理。", "東南瓦礫墟，所向輒千里。", "如何好事者，逐此不逐彼。"]'),
('5eaec83e-35c2-4933-88ee-964545bcd76e','前山尋蘭','鄭剛中','宋','宋诗','song-poetry','','[]','眼債未全無，惜春心尚有。',132,'全唐诗/poet.song.97000.json','["眼債未全無，惜春心尚有。", "喜聞幽蘭臭，尋過東山口。", "披叢見孤芳，正似得佳友。", "小鍤破蒼蘚，護致歸座右。", "秀色逼塵埃，清芳動窗牖。", "愛媚固無厭，嗟惜亦云久。", "今爲花木者，貴重無與偶。", "第能吐青紅，貢獻率奔走。", "官舟塞古汴，往往載蒲柳。", "爾何守幽林，國香空自負。", "所幸無改芳，可使名不朽。"]'),
('4a6f5be6-0c9c-476e-bdd5-791c11892169','簡潘義榮','鄭剛中','宋','宋诗','song-poetry','','[]','高槐記得綠陰垂，見公承詔趨丹墀。',224,'全唐诗/poet.song.97000.json','["高槐記得綠陰垂，見公承詔趨丹墀。", "今兹疏梅弄香粉，公坐鯁切還棲遲。", "甘辭軟暖定速售，此獨難使壯者爲。", "苦言瞑眩上所急，出林之木風摧之。", "嗟吁世路每如此，我常感激横涕洟。", "賈生妙論逮伊管，絳灌之屬猶可移。", "長孺忠言豈真戅，其如御史能飾非。", "到頭至始天所惜，未肯容易登臯夔。", "且今投置在閑散，藥傷補敗終見思。", "公還故鄉掃一室，古書名畫四壁圍。", "賓客相過具杯酒，一笑萬事榮辱齊。", "雖然公豈忘世者，終念后稷由己饑。", "吾皇嘗膽愈思治，宣室賜對行可期。", "當有今時張萬福，懽呼再拜迎公歸。"]'),
('768684c2-bcd5-416d-b2df-12f324af7936','酩酊且飲酒','鄭剛中','宋','宋诗','song-poetry','','[]','料峭社日寒，酩酊且飲酒。',84,'全唐诗/poet.song.97000.json','["料峭社日寒，酩酊且飲酒。", "中原困干戈，黠虜未授首。", "鄰邦復蟻聚，傷殺官吏走。", "使者部民兵，經月但斂手。", "豺狼群小心，伺隙欲嘷吼。", "吁嗟一身多，况復家數口。", "信如古人言，天地在杯斗。"]'),
('02588030-85c3-420d-947b-891c56d54bf3','建炎丁未自中夏徂秋不雨七夕日戲成一詩簡牛郎織女云','鄭剛中','宋','宋诗','song-poetry','','[]','今夕知何夕，織女逢牽牛。',120,'全唐诗/poet.song.97000.json','["今夕知何夕，織女逢牽牛。", "雲軿擁高漢，仙事傳風流。", "人間適焦窘，龜兆生田疇。", "當時大軍後，皆抱糠籺憂。", "我勸二星者，鵲橋無謾遊。", "曷不攀天河，駕浪鞭龍頭。", "共化油然雲，白雨淋九州。", "無庸事機巧，下副兒女求。", "良宵幸款曲，願爾深自謀。", "無令一年中，虚煩天地秋。"]'),
('a40eb48c-a1e8-40fa-be95-96ac2f8e5b0a','代答','鄭剛中','宋','宋诗','song-poetry','','[]','高才沐新詩，筆力回萬牛。',120,'全唐诗/poet.song.97000.json','["高才沐新詩，筆力回萬牛。", "諷我挽河漢，溥將膏澤流。", "吾聞天甚仁，愛民頒九疇。", "人間失彝叙，乃有偏毗憂。", "列星但隨旋，一氣同浮遊。", "詎敢弄天柄，私恩回旱頭。", "胡不自修德，和氣浹九州。", "奚煩雕腎腸，詩章遠相求。", "君其諭鄉鄰，此外無良謀。", "尚幾駐車駢，俯爲觀有秋。"]'),
('1e13bc7c-ade5-461c-8b8b-8d663b66ebc4','巨濟弟書夢求詩爲賦古風云','鄭剛中','宋','宋诗','song-poetry','','[]','稽首叩微妙，下筆書符若風雨。',206,'全唐诗/poet.song.97000.json','["稽首叩微妙，下筆書符若風雨。", "又復沃之瓊丘泉，過口腹腸如火煮。", "臨行戒以食腥穢，轉首蘧然成栩栩。", "吾聞有夢皆想成，此夢怪奇非想取。", "良由夙業種根凈，故此通玄受真語。", "會當役使三足烏，倒景乘風見王母。", "惟予墮入世網中，非孔非顔莫知祖。", "獨知抱正禦魑魅，符篆常疑不吾補。", "但留真火固臍下，每視丹砂賤於土。", "饑來得飽即快意，荼薺羶臊等甘苦。", "那知好慕長生人，保練形神乃如許。", "因觀侯夢悟昔非，嘆恨此身殊椎魯。", "便尋金篦去眼膜，爲汝他年看輕舉。"]'),
('73308791-89a4-482e-b3b9-425d9bee492e','送林懿成解兵掾','鄭剛中','宋','宋诗','song-poetry','','[]','公喻如龍媒，秋游身有神。',168,'全唐诗/poet.song.97000.json','["公喻如龍媒，秋游身有神。", "暫此地上行，氣壓凡馬群。", "我喻如麋鹿，野性不受馴。", "逼迫到城市，邇邇常畏人。", "自知兩相懸，無以追後塵。", "故其拜典謁，曠廢不及頻。", "時於清夜夢，論議容相親。", "公今瓜過期，行色催車輪。", "窮達稍異趣，細歡復何辰。", "悔不忘鄙陋，日爲門下賓。", "周旋奉誨語，藥此傷敗身。", "追念已無及，扳緣寧有因。", "但能側兩耳，聽公登要津。", "上固知倪寬，俗吏徒云云。"]'),
('64cf4e99-133d-4ab3-9701-39bae32f0033','午睡','鄭剛中','宋','宋诗','song-poetry','','[]','藜羹飯脱粟，窮達未須計。',84,'全唐诗/poet.song.97000.json','["藜羹飯脱粟，窮達未須計。", "日中困炎曦，到枕即昏睡。", "營營百爲擾，合眼盡遺棄。", "翛然一榻間，爛熟見真意。", "欲識太古風，去此不多地。", "我願四海平，圭竇永無事。", "夏臥法曹簟，冬夢公孫被。"]'),
('6efa00a0-6ac2-4990-a34e-ac466ef67fd9','寄姚文發','鄭剛中','宋','宋诗','song-poetry','','[]','芳蓀小綉肩相拍，拍初同作江湖客。',352,'全唐诗/poet.song.97000.json','["芳蓀小綉肩相拍，拍初同作江湖客。", "夢裏春風三十年，青銅照我頭都白。", "與公常日話瀟湘，恨不此身生兩翼。", "何如附驥得千里，再此搜尋舊踪跡。", "荷公覩物能我念，小字密書盈一尺。", "報言扶膝所經由，興廢存亡皆歷歷。", "吾家甘棠人所憐，今不見鸞空枳棘。", "至如叙述所知友，但若前生略相識。", "恍然沈痛念平生，讀盡寄書清淚滴。", "自嗟顦悴百憂身，慘慘中腸常感激。", "去年邂逅見中都，我正蹶蹄遭棄斥。", "相隨扶病出幽巷，買酒歸來款顔色。", "懷書亦復清渡灞，從此參商遠暌隔。", "公今館置得賢府，厚禮温顔同古昔。", "車魚足意長鋏閑，越聲不用思莊舄。", "果能援筆賦鸚鵡，自可使人皆辟易。", "他時依倚就聲價，疏蹻何由不離釋。", "惟予投置奥渫中，轉轉窮愁滿胸臆。", "春蠶未繭官督之，捋穗輸租瓶盎窄。", "誓将斸治十畝園，竹徑柴門閉聲寂。", "聲名雖不暫羶香，不願埋頭如李赤。", "爲公書此報東風，一夜楓林關塞黑。"]'),
('d6404770-d206-41f8-a2dc-9560edbe0158','天寒','鄭剛中','宋','宋诗','song-poetry','','[]','清寒作新雪，玉花僅堆積。',72,'全唐诗/poet.song.97000.json','["清寒作新雪，玉花僅堆積。", "雲破煦朝曦，數霤忽消釋。", "餘陰變小雨，頗似煙羃羃。", "時見庭前槐，枯梢水珠滴。", "破愁無尊酒，慰眼有書籍。", "涵泳度窮年，所得固清適。"]'),
('59923a46-49b3-4d4e-a71d-e7fa528110ca','自笑','鄭剛中','宋','宋诗','song-poetry','','[]','他人將錢買田園，尚患生財不神速。',64,'全唐诗/poet.song.97000.json','["他人將錢買田園，尚患生財不神速。", "我今貸錢買僻書，方且貪多懷不足。", "較量緩急堪倒置，安得瓶中有儲粟。", "自笑自笑笑我愚，笑罷頑然取書讀。"]'),
('f1bd886f-142d-405c-8a5c-e80331d2f2e2','歲暮','鄭剛中','宋','宋诗','song-poetry','','[]','頑風動高空，陰雲壓平野。',84,'全唐诗/poet.song.97000.json','["頑風動高空，陰雲壓平野。", "霰雪跳珠璣，歷亂擊疏瓦。", "袖手對寒窗，寂寞如噤啞。", "良朋莫相過，誰可慰懷者。", "豈不念得醉，傾壺絕餘瀉。", "火銷燈燼殘，一被不踰踝。", "天道無私窮，其窮則命也。"]'),
('50890df9-ace0-4ae1-a524-052dc25657fc','家旁有廟其巫每歲旦必鳴角作法以觴其神鄰里聞角聲則知其將曉矣','鄭剛中','宋','宋诗','song-poetry','','[]','村巫吹角天將曉，里巷拜年爭欲早。',80,'全唐诗/poet.song.97000.json','["村巫吹角天將曉，里巷拜年爭欲早。", "我驚節物懶下床，眼看屠蘇心恅愺。", "未能免俗出門去，禮數乖煩無所考。", "春風堂堂不顧人，自向池塘綠春草。", "誰知此髮不堅牢，一回如此一回老。"]'),
('78298ae3-205e-4323-81cb-f56bfc1a000c','浦江書院中','鄭剛中','宋','宋诗','song-poetry','','[]','弱雲障陰黑，疏雨弄纖細。',132,'全唐诗/poet.song.97000.json','["弱雲障陰黑，疏雨弄纖細。", "寒燈不生花，庭戶起愁吹。", "蟲話已停聲，夜半亦何啻。", "失手置書卷，撫心自驚悸。", "念此十年間，分明隨夢寐。", "一從雙鶴飛，顧影亦顦悴。", "病添女子愁，貧喪丈夫志。", "遠去松楸旁，團聚類兒戲。", "千金買卜龜，所用良失計。", "孤悲愈綢繆，萬感集腸胃。", "捲被拂空床，斑斑落清淚。"]'),
('a6c3c5e0-78f6-48b2-b8c3-b349f0b536dc','六月初八義榮司諫自福慶山見過奉陪遊西巖以新茶享石佛抵暮出山明日成古詩一章爲謝云','鄭剛中','宋','宋诗','song-poetry','','[]','窮巷絕輿馬，衡門翳蒿萊。',180,'全唐诗/poet.song.97000.json','["窮巷絕輿馬，衡門翳蒿萊。", "煩公赤墀步，踏我幽徑苔。", "念舊昔云有，此道今微哉。", "俗薄風義重，稍壓萬古回。", "衣冠冒暑至，笑語带凉來。", "愧無一尊酒，臨風相對開。", "乃得陪杖履，崎嶇訪巖隈。", "野寺生網蟲，長廊闃顛摧。", "晬容守孤殿，坐對寒爐灰。", "公獨屑瓊草，芬馨薦中懷。", "但念石佛古，豈顧多塵埃。", "妙語入幽隱，髙情肆徘徊。", "良覿若易奪，半規忽西頹。", "溪分隔流水，歸途恨難偕。", "獨立久瞻望，烟林綠洄洄。"]'),
('0f77fdbf-7a71-4031-b022-cb253d195578','晚村','鄭剛中','宋','宋诗','song-poetry','','[]','暑雨霽餘飛，翻溝水鳴玉。',72,'全唐诗/poet.song.97000.json','["暑雨霽餘飛，翻溝水鳴玉。", "半規入嵐霧，平疇愈新綠。", "時有牧歸牛，一笛過山曲。", "吾廬附幽深，四面蔭修竹。", "垂雲下林梢，驚鳥自爭宿。", "夜色迫書卷，呼童具燈燭。"]'),
('6237b41e-bb25-4404-8ef0-fea1864c4f65','始生之日石子壽我以詩所以相屬之意再三甚厚飲其酒歌其詩既至于醉也援筆爲十韻報之','鄭剛中','宋','宋诗','song-poetry','','[]','五月居山晝清永，槐度微風舞疏影。',160,'全唐诗/poet.song.97000.json','["五月居山晝清永，槐度微風舞疏影。", "兒童喜我懸弧辰，洒掃庭除具盤皿。", "烹鳬雋鵠未易辦，肴核隨時享桃杏。", "頗當杯杓念吾親，每歲在旁珠炯炯。", "今兹坐席小暌異，便覺親朋歡意冷。", "遠煩濃粉砑蠻牋，細寫親書過修嶺。", "堂中久闕起予論，遽此讀之雙眼醒。", "遐年厚福定由天，囑我既勤當謹領。", "永懷嘉意不能休，少慰蓼莪心耿耿。", "爲君儘放酒杯深，搔首浩歌成酩酊。"]'),
('619a82c9-fd45-49c5-a458-6de1056eefcc','讀蘇子美文集','鄭剛中','宋','宋诗','song-poetry','','[]','嗟乎，吾不及識子美，誦讀遺文淚如洗。',135,'全唐诗/poet.song.97000.json','["嗟乎，吾不及識子美，誦讀遺文淚如洗。", "公文意氣何所似，猛虎負山蛟得水。", "或如秋風入松竹，或如春温煦桃李。", "文章乃爾人可知，何事亨衢半途止。", "定應豪氣壓凡夫，不學持圓媚脣齒。", "孤芳獨寄叢林中，安得飄風不狂起。", "一盃失舉强名之，包裹鋒芒扼而死。", "天乎天乎庸可問，如子美者使作滄浪之釣民爾。"]'),
('39c791af-eb8a-4efa-96c2-18c252795232','招潘文虎','鄭剛中','宋','宋诗','song-poetry','','[]','親朋數日聞，俯仰作禮數。',108,'全唐诗/poet.song.97000.json','["親朋數日聞，俯仰作禮數。", "既事還書齋，妙畫倚庭柱。", "春蚓細縈紆，知子常我顧。", "坐此塵俗因，顔色阻良晤。", "遲疑負中心，恍若失所遇。", "新詩今鼎來，車馬審留駐。", "撥置或少間，尚幾枉前步。", "别來胸腹奇，彼此欲呈吐。", "當爲掃中庭，柏子香一炷。"]'),
('c41092cc-7d10-44b0-9a72-dd41f4facbad','感秋時寓龍德寺前','鄭剛中','宋','宋诗','song-poetry','','[]','西風吹澹雲，小雨送殘熱。',84,'全唐诗/poet.song.97000.json','["西風吹澹雲，小雨送殘熱。", "負砌兩梧桐，黄落下一葉。", "中宵暗燈火，冏冏窗前月。", "孤懷掛清愁，誰此伴心折。", "自顧欲何似，幽巷在窮穴。", "感動發悲鳴，啾唧夜不絕。", "曉起對青銅，兩鬢生華髮。"]'),
('83068b82-2c77-4108-b3de-c4bacc5836eb','辛丑正月十三飲南廳','鄭剛中','宋','宋诗','song-poetry','','[]','小槽瀝瀝流香乳，玉壺注入金鸚鵡。',64,'全唐诗/poet.song.97000.json','["小槽瀝瀝流香乳，玉壺注入金鸚鵡。", "甘脆鋪陳薦肴俎，環爐數客不停舉。", "酒酣耳熱燈前舞，呼嗚不作兒女語。", "未到山頹且撐拄，窗外濛濛正春雨。"]'),
('5024d115-720c-4f99-9fb3-c17555e48126','寓靈峰寺感懷','鄭剛中','宋','宋诗','song-poetry','','[]','遙風入林篠，淅瀝生夜愁。',276,'全唐诗/poet.song.97000.json','["遙風入林篠，淅瀝生夜愁。", "明月過窗牖，照此虚室幽。", "念從出懷綳，志在承箕裘。", "唯知業書卷，何嘗識戈矛。", "去年妖寇興，盡破東南州。", "烟來走官吏，火過成墟丘。", "豺虎恣搏噬，鼯鼪嘯朋儔。", "碪俎血忠義，罝網羅善柔。", "皇皇勢窘急，有罅即願投。", "挈妻負幼子，敢謂生可偷。", "潛遁得幽僻，如魚初脱鈎。", "妥尾定驚膽，餘魂漸能收。", "今者王師來，元兇已拘囚。", "巢窟有餘類，尚此稽討搜。", "參商隔弟妹，阻塞無書郵。", "家在北山口，煙林裹滄洲。", "更此亂離後，當無一椽留。", "何但一堂廬，最苦悲松楸。", "使我思歸夢，枕邊清淚流。", "嗟嗟廟堂客，爲國須早謀。", "積薪從下燃，誰云無後憂。", "願令弄兵者，依舊操鋤耰。", "勿俾太平世，蟣蝨生鞮鍪。"]'),
('f5c658a3-c084-4264-a694-18821f9d2255','靈峰聞秋雨','鄭剛中','宋','宋诗','song-poetry','','[]','夜靜荷池葉翻翻，聲如珠璣落冰盤。',96,'全唐诗/poet.song.97000.json','["夜靜荷池葉翻翻，聲如珠璣落冰盤。", "小窗客夢忽驚破，知是秋雨來池間。", "清曉陰雲壓前山，凉風飄蕭起林端。", "病身便覺衣袂薄，蒲葵已作無情看。", "田家喧呼各相勸，年豐可望糠籺寬。", "更願朝廷念東南，吾儕自勉加盤餐。"]'),
('88d1c09e-2a5a-445a-9854-b0fad1b87b82','宿長安閘口','鄭剛中','宋','宋诗','song-poetry','','[]','天寒雲氣陰，地闊江岸敞。',72,'全唐诗/poet.song.97000.json','["天寒雲氣陰，地闊江岸敞。", "鼓動風勢狂，掀簸浪頭長。", "單繩纜扁舟，避雨宿深港。", "上有阿蘭若，危鈴作孤響。", "一夜魂夢寒，鄉國勞遠想。", "清霜作朝晴，舟師動帆槳。"]'),
('bdb36fd2-7b8f-4e4f-82ae-5d8c2ed43539','安之叔盜後爲素求詩以此寄之','鄭剛中','宋','宋诗','song-poetry','','[]','青黄固非瞽者事，五色亦解盲人目。',144,'全唐诗/poet.song.97000.json','["青黄固非瞽者事，五色亦解盲人目。", "皆知鬼瞰高人家，爭欲相夸造華屋。", "吾門今已似參元，更喜吹簫有名叔。", "樞蓬牖甕編此居，憎視紛華如桎梏。", "凝塵滿席一爐香，不以色界爲可欲。", "自非純白不受垢，脱洗安能異流俗。", "我方草草排數椽，隨分鷦鷯一枝足。", "簷前但許風月到，門外不妨松竹綠。", "其他世幻何足云，自古賢人在巖谷。"]'),
('5bb8a6ad-45d9-48eb-9a3c-3315223bc6cc','憶書','鄭剛中','宋','宋诗','song-poetry','','[]','先子晚漂泊，家藏無全書。',252,'全唐诗/poet.song.97000.json','["先子晚漂泊，家藏無全書。", "屋壁零落者，雨壞鼠竊餘。", "余生苦嗜古，葺治十載逾。", "上自大父來，手澤之霑濡。", "下自予從學，筆力之傳留。", "蓄積稍浩浩，籖牌漸疏疏。", "去門聞盜興，烈炬燃通衢。", "反覆竊自計，蕭然一先廬。", "茅茨蓋空壁，下無金與珠。", "盜當知我貧，肯爲留此居。", "方更埋書帙，顯號緘鎖魚。", "誰知妖焰來，一燎鄰里墟。", "家雖託南巷，屋火書亦無。", "萬古聖賢語，隨烟入空虚。", "所聚忽消散，腸熱唯驚呼。", "吾憐衰蹇身，視人百無如。", "每幸對黄卷，白日聊自娱。", "今者坐窮寂，頓覺雙眼孤。", "夜夢亦驚枕，憂心梗難舒。", "大慮廢文字，寖久成頑疏。", "未免伴畦丁，冥然荷犂鋤。"]'),
('aa5d1ab2-e349-4bf0-a19e-176c359c0dd4','壬寅年南遊離白沙','鄭剛中','宋','宋诗','song-poetry','','[]','木杪日未升，四野落寒霧。',96,'全唐诗/poet.song.97000.json','["木杪日未升，四野落寒霧。", "昏濛失岡巒，咫尺見行路。", "我獨何區區，犯此寒色去。", "重傷寄蹇身，百事已遲暮。", "既不早衝躍，要津先自據。", "又無二頃田，林泉閉門戶。", "方此念友朋，升斗活車鮒。", "行行乖素心，芒刺欲誰負。"]'),
('61e6d535-d500-460b-93fe-1eb06b88a45f','至金谿與康功','鄭剛中','宋','宋诗','song-poetry','','[]','客子遠羈棲，天寒夜幽獨。',156,'全唐诗/poet.song.97000.json','["客子遠羈棲，天寒夜幽獨。", "擁被薦孤枕，感嘆不自足。", "念與公平時，書卷共燈燭。", "事業志遠大，可但慕爵祿。", "騕褭頭不垂，果此先噴玉。", "駸駸官職場，意氣已神速。", "我方坐困苦，一命綫相續。", "盜雖哀王粲，屢作碪上肉。", "屋廬化飛烟，瓶盎無儲粟。", "豈不鄰北阮，分者誰半菽。", "今兹尋友朋，慚甲生面目。", "波濤歲云暮，正作垂翅鵠。", "公無遂獨笑，忍聽窮途哭。"]'),
('c9ef3206-49a8-4cd5-baf0-bb2f9b80e202','宣和壬寅仲冬二十六日留别臨川陳泰穎','鄭剛中','宋','宋诗','song-poetry','','[]','江南浙東千里搖，雁聚沙汀無定跡。',96,'全唐诗/poet.song.97000.json','["江南浙東千里搖，雁聚沙汀無定跡。", "偶然握手如平生，祗恐前身已相識。", "不然安得一羈旅，披露煩君出金石。", "我今漂泊又西去，草草分襟實堪惜。", "孤舟漾水如輕葉，何處烟村倚灘磧。", "明朝横枕清浪頭，夢破霜風正相憶。"]'),
('f68ee5df-702c-4115-a6cc-3c21b2c67dc6','至豫章茂直座上戲書','鄭剛中','宋','宋诗','song-poetry','','[]','憶與故人分此袂，倒指數年今不啻。',64,'全唐诗/poet.song.97000.json','["憶與故人分此袂，倒指數年今不啻。", "天涯何意得相逢，一笑向君聊破涕。", "靜垂雙耳聽韶頀，濯洗凡襟無鄭衛。", "頻将短燭翦寒花，正恐今宵如夢寐。"]'),
('3573b26a-92d1-4ea0-a6e7-2a834ae57fe0','别茂直','鄭剛中','宋','宋诗','song-poetry','','[]','故人官江濱，藹藹起清望。',108,'全唐诗/poet.song.97000.json','["故人官江濱，藹藹起清望。", "因漂似木偶，千里遠相向。", "窮達懷異趣，雅故恐遺忘。", "暨我即門墻，公喜不可狀。", "握手問辛苦，容我細伸吭。", "凛然高義生，開懷出雲上。", "銜恩在雙腮，圖報心愈諒。", "歲暮天益寒，江湖足波浪。", "篋中乃得詩，安流反門巷。"]'),
('c9493c6b-4366-4f01-b2b9-02b355921a42','盜焚浦江龍德寺經藏與卷軸化爲玉諸公談禈論佛指真畫僞如泥中洗泥余竊不取且火之焚物無所不壞獨經卷不隨土木灰燼者理固灼然豈俟多談因戲爲一詩然不可以付寺僧也','鄭剛中','宋','宋诗','song-poetry','','[]','盜火阿蘭若，一燎無餘屋。',288,'全唐诗/poet.song.97000.json','["盜火阿蘭若，一燎無餘屋。", "獨此龍宫書，入火變爲玉。", "琤然斷甓中，幖帙猶可目。", "衆謂有哲匠，秘願發心腹。", "提斧入崑山，雕鐫作奇福。", "不然紙墨灰，委地安可觸。", "或謂刻楮者，一葉尚難速。", "誰能俄頃間，就此千萬軸。", "吾聞一切法，萬物皆具足。", "法存形豈忘，法壞形乃覆。", "彼既自斷壞，智者莫能續。", "是書佛所傳，法性妙含蓄。", "無盡如虚空，生滅自興伏。", "貞嘗無動搖，堅固莫摧辱。", "文字遂因依，清凉逼炎酷。", "吾又稽儒書，如彼莊周屬。", "亦謂忠信人，水火不能毒。", "矧此微妙語，天人共歸宿。", "豈容輕破壞，一槩隨土木。", "想當妖焰燃，人驚鬼神哭。", "烟消火力寒，撥灰開韞匵。", "告爾緇衣流，營修愈宜篤。", "當求琅玕類，刳以函其牘。", "勿謂字畫泯，不可事觀讀。"]'),
('ee94ad70-4bdc-4f6b-8428-8065ffab45c9','玉女泉以招提孤僻而名高華清泉坐天寶荒淫而取誚元章寺丞作古詩一章廣坡公之意爲抱器適用而不擇所處者之戒鄭子竊謂天下之邪正美惡分明如黑白其有失所處者非知而爲之蓋見善不明而自以爲是也自以爲是則雖有先生之辨將奈之何哉次韻作玉女泉','鄭剛中','宋','宋诗','song-poetry','','[]','安陸玉女泉，寒流隱叢薄。',288,'全唐诗/poet.song.97000.json','["安陸玉女泉，寒流隱叢薄。", "驪山華清泉，顯貴頗昭焯。", "二泉仙所留，暖氣注潺灂。", "後世入山人，塵垢賴疏瀹。", "詩翁道眼明，賢否善商擢。", "以謂驪山泉，有過不可藥。", "其他雖寂寥，清譽未衰落。", "都由天寶時，淫侈正乖錯。", "山水濫榮遇，譏誚亦難濯。", "出自安陸者，于今澹如昨。", "耕樵資滌弄，巖竇不扃鑰。", "地僻號幽窮，名高等河洛。", "猶人抱材器，戒在羞寂寞。", "詭笑事權豪，温顔捧杯杓。", "豈不暫羶香，遺臭非略略。", "噫嘻此誠然，但可付談噱。", "趣向如東西，岐路本來各。", "君子有顧藉，小人無愧怍。", "營營在聲名，遑恤墮溝壑。", "如古李赤者，章句頗能作。", "溷鬼豈不汙，自謂得所託。", "清都與鈞天，盛事咤揮霍。", "諂面就椒蘭，挽救不可縛。", "萬有一如赤，其肯在窮約。"]'),
('28713c9a-d907-456f-8d6b-2e20b618b096','臨刈旱苗','鄭剛中','宋','宋诗','song-poetry','','[]','我懷高臥心，而爲貧所迫。',120,'全唐诗/poet.song.97000.json','["我懷高臥心，而爲貧所迫。", "挽我赴塵賤，動與幽趣隔。", "磽田能幾何，旱穂正容摘。", "豈便得收斂，半屬租種客。", "分爭既不賢，烈日仍暴炙。", "勞生可羞嘆，皆爲糠籺窄。", "使得二頃肥，凶年不相厄。", "豈復論錙銖，驅馳在阡陌。", "自當杜衡門，清坐對書册。", "餘粟釀醇醪，笑似雙鬢白。"]'),
('6033e992-42a1-43eb-a2bb-29db962f9530','即事','鄭剛中','宋','宋诗','song-poetry','','[]','夏木垂嘉陰，中夜微雨集。',60,'全唐诗/poet.song.97000.json','["夏木垂嘉陰，中夜微雨集。", "晨興涉西園，爽氣衣外入。", "側身過幽林，葉上見餘濕。", "菰蒲暗池塘，有鷺如玉立。", "樂哉吾此居，時平足堪葺。"]'),
('89a3fdff-8ee9-4968-8c9b-0df2cab4bb5d','丁未四月與李叔佩還錢塘道浦江井坑嶺賦此詩','鄭剛中','宋','宋诗','song-poetry','','[]','扁舟絕驚濤，芒履陟修嶺。',156,'全唐诗/poet.song.97000.json','["扁舟絕驚濤，芒履陟修嶺。", "躋攀雖小勞，窈窕豈人境。", "巨石開雙關，有道細如綆。", "其中漸寬虚，闊步隨所逞。", "古木垂嘉陰，一覆餘里頃。", "寂寂艷山花，沈沈晦龍井。", "時有飛泉落，噴薄珠玉冷。", "毛骨皆清凉，反顧發深省。", "麋鹿聞人聲，駭去山之頂。", "春禽正對弄，决起不留影。", "豈知道上翁，甚愛幽獨景。", "如何蒙鄙外，一笑不相領。", "負負出前山，遲疑夢初醒。"]'),
('ea6822fd-b9a4-4433-8159-05237020ca82','王倅生辰','鄭剛中','宋','宋诗','song-poetry','','[]','日馭駕輪入東尾，望後黑月將浹旬。',224,'全唐诗/poet.song.97000.json','["日馭駕輪入東尾，望後黑月將浹旬。", "惟時十月二十四，積慶高門生異人。", "霏霏霜華翦寒梢，天地嚴肅無妖氛。", "秘藏和氣付賢者，粹然不受世俗塵。", "觀其玉潤得嘉耦，羲之正恐爲前身。", "自從平步官職場，事業磊落難具陳。", "東陽古郡號富壤，寇火之後風俗貧。", "征財榷利日擾擾，藉公獨與人爲春。", "坐令七邑再生育，此德重大無比倫。", "吾聞造物甚昭爽，報公以壽當如椿。", "我公骨相已奇艾，道氣日日生精神。", "他時雍容入廊廟，端以黄髮爲甫申。", "題輿雖此暫留滯，隨分亦可酬佳辰。", "庭前香霧欲雲起，可無一醉歡邦民。"]'),
('23be828f-1122-402b-a981-ee95a4fd5cb2','暑雨','鄭剛中','宋','宋诗','song-poetry','','[]','結廬在深寂，芳簷蔭松蘿。',48,'全唐诗/poet.song.97000.json','["結廬在深寂，芳簷蔭松蘿。", "天晴風日温，時有燕雀過。", "今兹夏暑雨，衡門可張羅。", "永嘆復自慰，幽興吾亦多。"]'),
('1a141451-bbfd-4007-8a69-bc5c259416be','和何元章','鄭剛中','宋','宋诗','song-poetry','','[]','持此樽中酒，試共評韓柳。',84,'全唐诗/poet.song.97000.json','["持此樽中酒，試共評韓柳。", "高才鳴道奥，俱是希世有。", "宗元失所依，論者微謂醜。", "退之甘窮約，名字全不朽。", "至今雌黄言，流落書生口。", "大抵貴致遠，成者未爲首。", "遑暇議古人，吾其御所守。"]'),
('01ae69e2-8b9b-4df4-bd2d-345a68e0f406','潘叔愚詩有歸家更讀萬卷書之語義榮司諫爲其未切於道也則作詩以警之而其序乃有終日談禪之語鄭子聞而笑之且書既不必讀則禪亦何必談乎復作一詩呈司諫公用前韻也','鄭剛中','宋','宋诗','song-poetry','','[]','弟見兄賢文學飽，意欲書卷窮探討。',128,'全唐诗/poet.song.97000.json','["弟見兄賢文學飽，意欲書卷窮探討。", "兄知紙上道不真，爲弟談禪說枯槁。", "弟兄遊戲作三昧，妙語生風洗煩惱。", "頭鑽故紙大是癡，口祗談禪癡不少。", "冥冥道妙不容聲，口語文書俱未了。", "雖然公豈不解此，慧力絕人先洞曉。", "暫借北山葛藤話，誘引群生入深渺。", "雲堂齋散歸時想，自把萬緣俱一掃。"]'),
('be8954ac-6188-433f-834a-a274d7f550fe','題赤松','鄭剛中','宋','宋诗','song-poetry','','[]','世謂仙易得，漢武吾所知。',124,'全唐诗/poet.song.97000.json','["世謂仙易得，漢武吾所知。", "終老坐迷妄，海上求安期。", "世謂仙難得，二王等兒嬉。", "安期自來顧，一笑相與歸。", "難易詎能詰，戃恍誰復窺。", "千古赤松事，話者君勿疑。", "凌遐與倒景，物外非無之。", "要須功行滿，乃可超塵泥。", "無懷輕誕心，鶴鹿浪欲騎。", "安期寄語謂世人，初平不是牧羊兒。"]'),
('1d80f4ae-57e1-47c1-a541-2a20a8852557','覽鏡','鄭剛中','宋','宋诗','song-poetry','','[]','短髮不盈梳，年來半斑白。',96,'全唐诗/poet.song.97000.json','["短髮不盈梳，年來半斑白。", "吾今四十二，敢望能滿百。", "負郭苦無田，安居未成宅。", "况復世路艱，國步日侵迫。", "未必松楸旁，常得看書冊。", "區區抱短見，貧賤中外隔。", "寄此鄉國間，踪跡亦如客。", "覽鏡酒杯空，浩歌天地窄。"]'),
('70626eb3-a80d-411c-8890-a2d84c2c6f48','代上傅帥十二月二十三日生辰','鄭剛中','宋','宋诗','song-poetry','','[]','牙城霜月紅，稚耋擁晴晝。',288,'全唐诗/poet.song.97000.json','["牙城霜月紅，稚耋擁晴晝。", "百拜黄堂前，共上太守壽。", "皆謂去年時，黠虜已深寇。", "一砲驚江南，衢婺幾失守。", "徬徨千里心，竄逸欲相蹂。", "公以活人手，銜金力營救。", "信賞激忠勇，厚禮羅傑秀。", "坐回虜馬頭，遁去如驚獸。", "邦人未遑息，鼠輩復狂嗾。", "郡兵無奇畫，轍亂失領袖。", "閉關守孤城，惴慄鹿在囿。", "我公登高墉，威德即下覆。", "仰見吾父者，歡舞悉解胄。", "一犂春雨耕，樂業遂如舊。", "生成荷終始，銘刻念前後。", "公之所常活，庸可億萬究。", "吾聞天地間，禍福靡虚授。", "陰功滿東吳，冥報豈容繆。", "當能壽我公，炯炯如列宿。", "下吏聞此言，喜躍倒冠綬。", "中興須鉅人，理亦天所祐。", "矧復有厚德，福祿宜愈茂。", "自恨如漂萍，孤跡太冗陋。", "邑佐雖賤役，不許久奔走。"]'),
('4d21fc10-dfab-4e69-af36-d9ad46468f16','石季平題李南畫石之傍曰叠石爲山已是一重公案况畫者耶鄭子見而笑之明日戲成伽佗問隨緣云隨緣居士即季平道號也','鄭剛中','宋','宋诗','song-poetry','','[]','筆畫與石叠，二者均是假。',52,'全唐诗/poet.song.97000.json','["筆畫與石叠，二者均是假。", "惟彼此間山，如叠亦如畫。", "要當論真空，萬物同一馬。", "隨緣判此公案時，不知筆作麽生下。"]'),
('38eee2f2-8c1a-4d45-90d7-9c3bf1eff40c','每年家釀留一器以奉何元章今年持往者輒酸黄不可飲再以二尊贖過仍爲此詩云','鄭剛中','宋','宋诗','song-poetry','','[]','吾廬託窮巷，有酒無佳客。',204,'全唐诗/poet.song.97000.json','["吾廬託窮巷，有酒無佳客。", "年年家釀香，延首定攀憶。", "分持遠相遺，豈問杯杓窄。", "所貴明月前，共此一尊色。", "去年冬苦寒，雪水填四澤。", "甕面蟻不浮，弱糟無勁力。", "瓶罌貴潔清，而器不親滌。", "泥封意雖勤，審視頗無則。", "如聞近所往，惡味同食檗。", "恨無醇德將，非緣踰日昃。", "大類獻空籠，報賜煩雙璧。", "想當設肴餌，清興隨太白。", "流涎不及味，顧我豈逃責。", "我貧如陶侃，每蒙鄰舍德。", "墻頭有餘惠，不敢自專得。", "今復再分獻，庶以補前慝。", "願公領微衷，畢此無餘瀝。"]'),
('d5bde6c0-738c-46cb-b455-68f0dbdbcf01','對竹','鄭剛中','宋','宋诗','song-poetry','','[]','勞生分素定，大患天所辱。',96,'全唐诗/poet.song.97000.json','["勞生分素定，大患天所辱。", "時於塵埃中，許我對修竹。", "此君風味高，瘦骨不生肉。", "烟梢墮新籜，當面變蒼玉。", "風邀嘉月過，衆葉亂相觸。", "寒光下照之，到地影猶綠。", "誰能相從飲，莫聽人間曲。", "細響侑孤斟，洗卻一生俗。"]'),
('24dc9880-70f1-49bb-85d6-1a26d1f11120','擬和','鄭剛中','宋','宋诗','song-poetry','','[]','馬瘦未爲病，不仁人乃辱。',96,'全唐诗/poet.song.97000.json','["馬瘦未爲病，不仁人乃辱。", "樂哉仁者居，更對蕭然竹。", "何曾不解此，日食萬錢肉。", "寧如祗藜藿，卻有階前玉。", "影亂鄴侯書，顛倒手都觸。", "清風過餘凉，散作酒尊綠。", "疏金忽瑣碎，天際一鈎曲。", "婆娑觀此身，要俗不得俗。"]'),
('703ec85d-cffd-4542-8cf0-dde679752282','北山會飲','鄭剛中','宋','宋诗','song-poetry','','[]','四圍明窗香霧塞，酒射玻璃成琥珀。',96,'全唐诗/poet.song.97000.json','["四圍明窗香霧塞，酒射玻璃成琥珀。", "無多酌我先有言，須識次公爲惡客。", "長鯨豈問湖海寬，偃鼠定知胸次窄。", "後園雜花如錦拆，風雨顛狂那可測。", "主人娱賓寧愛酒，勿以杯計當以石。", "君圖繼晷膏可燃，若欲留春古無策。"]'),
('48ca7893-04db-4dc4-aa96-74e949db0ac1','南陔五章二章章八句三章章四句  其一','鄭剛中','宋','宋诗','song-poetry','','[]','陟彼南陔，有風惟薰。',40,'全唐诗/poet.song.97000.json','["陟彼南陔，有風惟薰。", "曷念劬勞，華髪盈巾。", "彼髮之華，尚可翦也。", "嗟嗟吾親，不可見也。"]'),
('bcde85ad-6d88-47a7-87ca-ee4a8af2b203','南陔五章二章章八句三章章四句  其二','鄭剛中','宋','宋诗','song-poetry','','[]','陟彼南陔，其薰遠兮。',40,'全唐诗/poet.song.97000.json','["陟彼南陔，其薰遠兮。", "慨我功名，今亦晚兮。", "功名之晚，尚可爲也。", "嗟嗟吾親，不可追也。"]'),
('788f8a4f-7279-4280-a864-a059f74d828e','南陔五章二章章八句三章章四句  其三','鄭剛中','宋','宋诗','song-poetry','','[]','彼居之子，庭闈休休。',20,'全唐诗/poet.song.97000.json','["彼居之子，庭闈休休。", "愛日之念，胡弗省修。"]'),
('a14647e3-3b2a-454b-85c6-e89e9db70e7d','南陔五章二章章八句三章章四句  其四','鄭剛中','宋','宋诗','song-poetry','','[]','瞻彼禽鳥，亦哺其母。',20,'全唐诗/poet.song.97000.json','["瞻彼禽鳥，亦哺其母。", "養而弗驩，於孝奚取。"]'),
('69c1c84d-2560-4b46-a115-883650e5c713','南陔五章二章章八句三章章四句  其五','鄭剛中','宋','宋诗','song-poetry','','[]','敬爾身矣，懌其親矣。',20,'全唐诗/poet.song.97000.json','["敬爾身矣，懌其親矣。", "逮其暮矣，云何吁矣。"]'),
('7d86382d-ac41-45c8-bdb1-6cd189a69238','贈范茂直','鄭剛中','宋','宋诗','song-poetry','','[]','范君才力信超群，與我暌離未十春。',64,'全唐诗/poet.song.97000.json','["范君才力信超群，與我暌離未十春。", "脱體文章都換骨，從頭宦業便通神。", "不應蓮幕淹餘刃，莫只花磚臥此身。", "好傍玉皇香案立，放教膏澤下斯民。"]'),
('060f709f-644a-4fd4-b92e-282ec9b1146d','壬寅年南遊至衢州','鄭剛中','宋','宋诗','song-poetry','','[]','分開平綠渡寒溪，溪外垂空日腳低。',64,'全唐诗/poet.song.97000.json','["分開平綠渡寒溪，溪外垂空日腳低。", "城郭重重隨望遠，峰巒處處與雲迷。", "窮通默定非難識，勞逸時閑太不齊。", "又向孤村烟樹下，見他烏鳥一番栖。"]'),
('5a68df11-ddfb-4fe5-89e2-c746287ae755','入信州','鄭剛中','宋','宋诗','song-poetry','','[]','郵亭方此越三衢，已是江南十里逾。',64,'全唐诗/poet.song.97000.json','["郵亭方此越三衢，已是江南十里逾。", "幽谷日來禽對語，平沙霜重雁相呼。", "溪旁障水横魚網，竹下開門出酒壺。", "物態人情隨處好，不煩客子嘆羈孤。"]'),
('b619d320-e7c8-449f-87c3-ad402209def2','此心','鄭剛中','宋','宋诗','song-poetry','','[]','金華山下赤松鄉，何日横門杜短墻。',64,'全唐诗/poet.song.97000.json','["金華山下赤松鄉，何日横門杜短墻。", "皮几鶉衣甘淡泊，竹陰花徑任徜徉。", "雨餘靜聽溪流激，風過時聞稻米香。", "緘負此心剛未遂，羨渠陶子傲羲皇。"]'),
('e60a9723-06ac-4d34-9c0a-a1f4d4f3890e','甲辰年得男子經道以詩相賀因報之','鄭剛中','宋','宋诗','song-poetry','','[]','兩夢嘗占女子祥，偶懸弧矢亦非常。',64,'全唐诗/poet.song.97000.json','["兩夢嘗占女子祥，偶懸弧矢亦非常。", "渥洼方合生騏驥，枳棘安能出鳳凰。", "自顧此身無遠業，所期前世有遺芳。", "新詩相賀來何晚，湯餅惟公不在堂。"]'),
('0b98b2a3-43ae-4215-9ff0-450982c8cc12','越江之岸人家皆臨水種竹叠石作逕其屋蕭然嗟今齒髮踰壯方坐兵火驚焚安得一居如此見之不勝饞慕','鄭剛中','宋','宋诗','song-poetry','','[]','何人此地得幽居，竹石中間宅一區。',64,'全唐诗/poet.song.97000.json','["何人此地得幽居，竹石中間宅一區。", "可意江山千百里，有情花木兩三株。", "應無俗客驚吠犬，時有輕船過賣魚。", "卜築他年期效此，更添數架古人書。"]'),
('b23f9a5f-9de8-43a6-970e-0c327b63773f','和吳唐輔雪中同遊西湖之作','鄭剛中','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生聞說西湖好，眼礙紅塵未得看。',64,'全唐诗/poet.song.97000.json','["平生聞說西湖好，眼礙紅塵未得看。", "款奉親朋今始到，俯臨波浪不知寒。", "異鄉把盞人都醉，同道論情我最歡。", "莫向人頭聽傳漏，且將燈燭照更闌。"]'),
('717476d6-5276-447c-82b8-604f835562f6','和仲模梅花','鄭剛中','宋','宋诗','song-poetry','','[]','亭亭清瘦出塵埃，高格端從物外來。',64,'全唐诗/poet.song.97000.json','["亭亭清瘦出塵埃，高格端從物外來。", "先對雪霜含素艷，任教桃杏作紅腮。", "芬芳多向閑中得，孤寂偏尋靜處開。", "長願一枝横夜月，春風謾誕莫相催。"]'),
('e8731892-783d-4574-90a7-d8b98078f031','用韻寄仲模','鄭剛中','宋','宋诗','song-poetry','','[]','又暖屠蘇入酒杯，可憐年去復年來。',64,'全唐诗/poet.song.97000.json','["又暖屠蘇入酒杯，可憐年去復年來。", "但能雕琢愁肝腎，豈慣縱横强頰腮。", "先子丘園荒不理，故人懷抱遠難開。", "行藏事業皆前定，祗恐吾儕鬢髮催。"]'),
('a508b412-c4d8-482f-99e4-a146c43e3597','和王才鼎懷錢塘','鄭剛中','宋','宋诗','song-poetry','','[]','錢塘叛卒又嬰城，報至令人失意驚。',64,'全唐诗/poet.song.97000.json','["錢塘叛卒又嬰城，報至令人失意驚。", "天子於今猶自將，藩臣何以不知兵。", "官無良吏因循致，廟有成謨次第平。", "所惜湖山辛丑後，至今澄洗未曾清。"]'),
('3603cc9a-81f1-4d7e-a547-3c82e5c3cc8a','再和','鄭剛中','宋','宋诗','song-poetry','','[]','我雖巖谷豈其卿，多壘于郊亦可驚。',64,'全唐诗/poet.song.97000.json','["我雖巖谷豈其卿，多壘于郊亦可驚。", "徒有丹心思報國，無因緩頰得論兵。", "跳梁狐怪今方逞，奮角狼星久未平。", "盍亦付之公子繡，慨然持斧爲澄清。"]'),
('1872c86b-9b4e-4035-a60c-daa30504f82f','臨刈旱苗二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','黄梅雨斷水如湯，百日連秋苦亢陽。',64,'全唐诗/poet.song.97000.json','["黄梅雨斷水如湯，百日連秋苦亢陽。", "所在自應知孝婦，孰云今尚有弘羊。", "沛然天澤因誰靳，蠢爾黎民重可傷。", "罪已佇聞須聖詔，中興仰首望君王。"]'),
('84725dc9-e52e-44bf-9d9f-299c238aaf3d','臨刈旱苗二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','可怪書生命分窮，頻年荒歉苦天公。',64,'全唐诗/poet.song.97000.json','["可怪書生命分窮，頻年荒歉苦天公。", "枯陂盡作龜紋裂，旱穂渾如雀啄空。", "佃客腰鐮癡不割，長官受狀遠難通。", "歸來笑向兒童道，定是今年餓殺儂。"]'),
('d220ce8a-a5a1-426a-a29f-a26c544eaa0f','己酉正月大風寒米價騰踴菜色之民皇皇于道感而作是詩','鄭剛中','宋','宋诗','song-poetry','','[]','昏昏日影有還無，謾誕春風勢力粗。',64,'全唐诗/poet.song.97000.json','["昏昏日影有還無，謾誕春風勢力粗。", "品物固知春用意，細民其奈米如珠。", "未相秦越嘗憂國，不再臯夔愧服儒。", "骨髓有奇深自負，緘封無路薦區區。"]'),
('7f0f8222-72cd-4e1a-89b8-756f9afcbba1','義榮見示和禪月山居詩盥讀數過六根洒然但余素不曉佛法今以受持孔子教中而見於窮居之所日用者和成七首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','世態欹危轉覺難，年來宜我面西山。',64,'全唐诗/poet.song.97000.json','["世態欹危轉覺難，年來宜我面西山。", "高情不出窗几內，至樂亦非文字間。", "願得好風常款款，不妨流水自潺潺。", "箇中有味誰同享，俗子卑陬莫强攀。"]'),
('cc876a75-f70d-4bc9-84e9-0b2e16aa6bf5','義榮見示和禪月山居詩盥讀數過六根洒然但余素不曉佛法今以受持孔子教中而見於窮居之所日用者和成七首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','不曾貪進不曾休，俯仰人間今白頭。',64,'全唐诗/poet.song.97000.json','["不曾貪進不曾休，俯仰人間今白頭。", "一切有爲皆妄幻，十方無礙足浮遊。", "誰言學佛須披衲，頗笑求仙唯造樓。", "只有隨緣是真諦，穏憑舟楫濟安流。"]'),
('ae66d5c3-960c-4eed-b247-8748d499eb64','義榮見示和禪月山居詩盥讀數過六根洒然但余素不曉佛法今以受持孔子教中而見於窮居之所日用者和成七首  其三','鄭剛中','宋','宋诗','song-poetry','','[]','陋屋三間草蓋成，四時蘭菊薦芳馨。',64,'全唐诗/poet.song.97000.json','["陋屋三間草蓋成，四時蘭菊薦芳馨。", "但知後圃多栽橘，何必陽山獨采苓。", "破睡雪花茶滿盌，慰懷春色酒盈瓶。", "與人無怨亦無德，自覺長年心自寧。"]'),
('68223fe7-1972-404b-ad00-e241b6266a5d','義榮見示和禪月山居詩盥讀數過六根洒然但余素不曉佛法今以受持孔子教中而見於窮居之所日用者和成七首  其四','鄭剛中','宋','宋诗','song-poetry','','[]','官不追求盜不窺，得閑終日閉荆扉。',64,'全唐诗/poet.song.97000.json','["官不追求盜不窺，得閑終日閉荆扉。", "有時斸圃趁春事，幾度荷鋤隨月歸。", "酒裏最思陶靖節，江邊時憶謝玄暉。", "自知此外無他障，一任蕭然鬢髮稀。"]'),
('952ba96d-1bcd-4efc-ad00-8269584a2089','義榮見示和禪月山居詩盥讀數過六根洒然但余素不曉佛法今以受持孔子教中而見於窮居之所日用者和成七首  其五','鄭剛中','宋','宋诗','song-poetry','','[]','松林竹塢雨冥冥，對坐焚香一縷青。',64,'全唐诗/poet.song.97000.json','["松林竹塢雨冥冥，對坐焚香一縷青。", "掃壁靜開摩詰象，研朱閑點太玄經。", "愚癡我豈能無漏，警悟人皆誚不靈。", "允願凉風吹酗毒，要令舉世得醒醒。"]'),
('b277c943-3614-4f10-ab02-781d69b654a3','義榮見示和禪月山居詩盥讀數過六根洒然但余素不曉佛法今以受持孔子教中而見於窮居之所日用者和成七首  其六','鄭剛中','宋','宋诗','song-poetry','','[]','瓜滿前疇菜滿畦，赤松屋北寺居西。',64,'全唐诗/poet.song.97000.json','["瓜滿前疇菜滿畦，赤松屋北寺居西。", "不村不郭常安穏，非律非禪自整齊。", "靜見游魚潭底樂，任從幽鳥葉間啼。", "此心得趣知誰解，一月寒光印碧溪。"]'),
('93bb9017-29d8-47dd-b73f-c2617fa14676','義榮見示和禪月山居詩盥讀數過六根洒然但余素不曉佛法今以受持孔子教中而見於窮居之所日用者和成七首  其七','鄭剛中','宋','宋诗','song-poetry','','[]','經史何須萬卷開，書多方朔反詼諧。',64,'全唐诗/poet.song.97000.json','["經史何須萬卷開，書多方朔反詼諧。", "能言正恐迷難出，絕學方知進有階。", "角逐英雄都掃地，留傳功業謾磨崖。", "若無反照觀心術，永墮諸塵萬事乖。"]'),
('3a7471a6-11bd-4080-93fa-6e16f7a0ee4d','石季平嘗爲于仲模詩改二字後仲模有詩來復用韻報之且慶朋友間漸能琢磨責善追復古風焉','鄭剛中','宋','宋诗','song-poetry','','[]','趙璧微瑕豈易攻，抉磨深賀得良工。',64,'全唐诗/poet.song.97000.json','["趙璧微瑕豈易攻，抉磨深賀得良工。", "古人規誨有餘樂，近世交朋無此風。", "二字相禆何預我，一篇兼報重煩公。", "新吟若掛高門外，價比千金迥不同。"]'),
('7f612048-d4de-41f9-9ee8-1973d2fa8d9a','寺前書院中寄季平','鄭剛中','宋','宋诗','song-poetry','','[]','已投幽僻避塵坌，更向簷頭著小門。',64,'全唐诗/poet.song.97000.json','["已投幽僻避塵坌，更向簷頭著小門。", "滿案韋編供白晝，一爐柏子對黄昏。", "後生秀爽慚無補，舊學荒凉喜再温。", "此外清愁是何許，杜詩韓筆少人倫。"]'),
('5d6942ad-c04c-4f27-a856-00771be9e6a2','後圃石榴初爲夏日所暴得秋雨所爛易落雀又從而竊之樹間日以彫疏顧其餘尚可侑吾小飲因成一詩而摘取之','鄭剛中','宋','宋诗','song-poetry','','[]','初見纍纍小圃中，鼠偷雀啄樹將空。',64,'全唐诗/poet.song.97000.json','["初見纍纍小圃中，鼠偷雀啄樹將空。", "久遭日暴皮先罅，未借霜寒子半紅。", "爽味尚堪供齒頰，清漿聊可潤心胸。", "小籃親摘提取便，聊得鋪排薦飯鍾。"]'),
('86f7468b-61b5-4ca0-bd0d-590900d47154','磨茶寄羅池一詩隨之後以無便茶與詩俱不往今謾錄于此過眼便焚切勿留','鄭剛中','宋','宋诗','song-poetry','','[]','有人遺我建溪香，茶具鄰家自借將。',64,'全唐诗/poet.song.97000.json','["有人遺我建溪香，茶具鄰家自借將。", "親磨無從親付汝，一推惟是一回腸。", "趨庭愧我繆知鯉，證父憐兒那得羊。", "淺啜飯餘深自省，再生天地屬君王。"]'),
('47bf9abb-942e-43d2-803d-56c1ab79851d','幾先坐上贈友人','鄭剛中','宋','宋诗','song-poetry','','[]','去歲吳江秋水平，繫船聊得一班荆。',64,'全唐诗/poet.song.97000.json','["去歲吳江秋水平，繫船聊得一班荆。", "相思只道心長折，此會那知眼再明。", "離合悲歡言不盡，東西南北恨還生。", "勸君勿復吝杯酌，漏箭銘盤将五更。"]'),
('875bb108-ae35-45cb-951d-ba2045c33183','宣和壬寅十月余游江南二十五日道出月巖方崇寧甲申先子休官長沙挈家人宿巖下此後二十年間哭父母失姊妹禍患百端今日雖使余富貴過此尚當悲感不自已况復羈孤無聊爲萬里旅人耶欲作一詩梗切未能就止以二十八字叙其事翌日得四韻  其一','鄭剛中','宋','宋诗','song-poetry','','[]','先親膝下共游人，孤影飄零只我身。',32,'全唐诗/poet.song.97000.json','["先親膝下共游人，孤影飄零只我身。", "今日再來如隔世，泫然衰淚落江濱。"]'),
('7406955b-8642-4157-b4a3-a712f2099be7','宣和壬寅十月余游江南二十五日道出月巖方崇寧甲申先子休官長沙挈家人宿巖下此後二十年間哭父母失姊妹禍患百端今日雖使余富貴過此尚當悲感不自已况復羈孤無聊爲萬里旅人耶欲作一詩梗切未能就止以二十八字叙其事翌日得四韻  其二','鄭剛中','宋','宋诗','song-poetry','','[]','石漏搖空一片天，月巖之號古相傳。',64,'全唐诗/poet.song.97000.json','["石漏搖空一片天，月巖之號古相傳。", "孤輪高潔誰爲比，老樹婆娑亦宛然。", "山礙不容千里見，崖侵常蝕二分偏。", "故知僞物誰叨冒，終竟天教不十全。"]'),
('97046609-c037-4073-bcdd-0ebfce9b164f','題洪州新建張令寄齋','鄭剛中','宋','宋诗','song-poetry','','[]','合倚金華步石渠，丹砂寧駐葛洪車。',64,'全唐诗/poet.song.97000.json','["合倚金華步石渠，丹砂寧駐葛洪車。", "有成用底三年政，必葺聊成一日居。", "簿令優游閑製錦，籖牌盤礴飽觀書。", "後來令尹須留意，莫道前人託宿廬。"]'),
('ad2004be-c867-449b-a0d7-429e43f33d11','和安之叔灰齋','鄭剛中','宋','宋诗','song-poetry','','[]','見說灰齋只數椽，先生燕息此於焉。',64,'全唐诗/poet.song.97000.json','["見說灰齋只數椽，先生燕息此於焉。", "聲名應恥暫時熱，喜怒端知不復然。", "春到豈無繁杏火，日高惟有篆爐烟。", "清幽此外萬緣冷，笑殺人間百慮煎。"]'),
('ceb3d560-c498-4813-8f65-bf091bde1d34','送張季平歸永嘉','鄭剛中','宋','宋诗','song-poetry','','[]','霜葉搖風九月秋，披披歸袖挽難留。',64,'全唐诗/poet.song.97000.json','["霜葉搖風九月秋，披披歸袖挽難留。", "知君久作陶山夢，無意相從鄭谷遊。", "率略杯盤常共醉，艱難身世最同憂。", "人情易得成疏冷，頻有音書寄我不。"]'),
('b0656a80-41f7-471d-9108-f0559077cc44','和何元章新秋','鄭剛中','宋','宋诗','song-poetry','','[]','玉露寒凝顆，銀河澹瀉流。',48,'全唐诗/poet.song.97000.json','["玉露寒凝顆，銀河澹瀉流。", "每年纔到此，無處不驚秋。", "便有清凉意，潛消旱涸憂。", "附炎蚊弄喙，可笑不知休。"]'),
('03c15c8e-376d-4e6e-91cc-92a6135fb845','鼓子花','鄭剛中','宋','宋诗','song-poetry','','[]','鼓子花堪愛，疏葩淡碧時。',48,'全唐诗/poet.song.97000.json','["鼓子花堪愛，疏葩淡碧時。", "未陪葵向日，且伴菊當籬。", "土厚根條達，凉多世俗希。", "可憐紅槿類，無益自衰遲。"]'),
('99ef00cd-4bea-4494-89be-e9dc2b02ee4e','和潘叔愚書懷','鄭剛中','宋','宋诗','song-poetry','','[]','冷落秋風宅一區，悲歌豈爲食無魚。',64,'全唐诗/poet.song.97000.json','["冷落秋風宅一區，悲歌豈爲食無魚。", "去來軍馬潛窺伺，出沒神姦未掃除。", "許國有心雖感激，濟時無路謾欷歔。", "何當成就周宣業，再勒岐陽石鼓書。"]'),
('9cb1debe-2592-4b91-8854-7a8f4f250425','癸丑年暖閣初成','鄭剛中','宋','宋诗','song-poetry','','[]','枯葉寒梢夜夜聲，圍爐小閣喜初成。',64,'全唐诗/poet.song.97000.json','["枯葉寒梢夜夜聲，圍爐小閣喜初成。", "護風簾密香烟潤，弄日窗低書卷明。", "况有酒漿初暖熱，從他歲律自崢嶸。", "塊然危坐得佳處，萬事人間一唾輕。"]'),
('05b0d4b6-9e73-499f-9d8f-6503f9211f1a','和思老夏日山居','鄭剛中','宋','宋诗','song-poetry','','[]','世俗沸如湯，公於靜處藏。',48,'全唐诗/poet.song.97000.json','["世俗沸如湯，公於靜處藏。", "忘機身不老，無事日偏長。", "地僻松篁密，僧疏殿閣凉。", "何須有妻子，涕泣似王章。"]'),
('45cb61ff-c179-4c88-a486-d4a0faa5d113','和石希孟','鄭剛中','宋','宋诗','song-poetry','','[]','暌闊星霜又欲周，詩書深恐廢前修。',64,'全唐诗/poet.song.97000.json','["暌闊星霜又欲周，詩書深恐廢前修。", "相承韡韡常怡悦，有罵申申正噢咻。", "一暴而寒非所喜，半塗之畫最堪羞。", "茅簷紫竹窗前榻，我尚殷勤爲爾留。"]'),
('0132a07a-8dff-4912-8f2a-07263661eb55','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','望春樓上倚闌時，祗此霜天也自奇。',64,'全唐诗/poet.song.97000.json','["望春樓上倚闌時，祗此霜天也自奇。", "遠水平山渾似畫，新寒愛日穏催詩。", "不知木葉藏村舍，忽有鷄聲過短籬。", "閑卻主人朝省步，經年端坐看清暉。"]'),
('7ead2cfd-f4c2-4126-8bb0-de891545fb15','悼八嬸孺人  其一','鄭剛中','宋','宋诗','song-poetry','','[]','當年棗栗奉高堂，顦顇俄驚哭杞梁。',64,'全唐诗/poet.song.97000.json','["當年棗栗奉高堂，顦顇俄驚哭杞梁。", "目見兩孤成乳酪，坐聞一節勝冰霜。", "仙遊已作朝霞會，塵世空將舊屨藏。", "莫問生來壽何許，曾孫兒女亦成行。"]'),
('a1faebcb-1506-4d87-a139-8d6c1594da13','悼八嬸孺人  其二','鄭剛中','宋','宋诗','song-poetry','','[]','最幸平時省拜頻，雍容常欲面生春。',64,'全唐诗/poet.song.97000.json','["最幸平時省拜頻，雍容常欲面生春。", "鬢華雖覺年彌老，齒宿其如語自新。", "兩劍共埋知有日，一杯持奠阻無因。", "泫然空落風前淚，終愧西山執紼人。"]'),
('0f52b75e-f45e-4ade-af42-52cd42e05e56','悼陳庭玉','鄭剛中','宋','宋诗','song-poetry','','[]','力就揚雄宅一區，知公有意賦歸歟。',64,'全唐诗/poet.song.97000.json','["力就揚雄宅一區，知公有意賦歸歟。", "兩楹豈謂哲人夢，三徑空留君子居。", "厚德所傳唯裔嗣，清名難朽是詩書。", "天公到底慳風俗，不使斯人在里閭。"]'),
('8e6aff42-e96e-4597-abba-d97a32592468','悼六兄宗魯  其一','鄭剛中','宋','宋诗','song-poetry','','[]','王粲全身不偶然，意公所享尚綿綿。',64,'全唐诗/poet.song.97000.json','["王粲全身不偶然，意公所享尚綿綿。", "誰知慶弔在反掌，到底死生難問天。", "萬頃良田空沃壤，九原幽恨獨新阡。", "階庭富有諸郎外，所喜東床兩婿賢。"]'),
('a4f1d6a2-8450-416e-8948-1dc8a69b237e','悼六兄宗魯  其二','鄭剛中','宋','宋诗','song-poetry','','[]','去歲擔簦入上都，公能别我意踟蹰。',64,'全唐诗/poet.song.97000.json','["去歲擔簦入上都，公能别我意踟蹰。", "微疴未覺鴒原急，永訣那知雁序孤。", "奠拜昔猶棺在殯，送車今又客登途。", "爲公回首生清恨，空有池邊宅一區。"]'),
('8c3d5586-dee0-46bc-a162-ce7350714e38','悼顧與權夫人','鄭剛中','宋','宋诗','song-poetry','','[]','高文司諫筆如椽，肯作夫人識墓篇。',64,'全唐诗/poet.song.97000.json','["高文司諫筆如椽，肯作夫人識墓篇。", "但考銘詩無玷闕，自應遺型遠流傳。", "女無妬色誠希有，士不妨功可並賢。", "安得芝蘭勿叢秀，藹揚餘懿屬他年。"]'),
('09931fb1-7d18-4279-a4dc-33f175351ed8','悼陳子濟教授','鄭剛中','宋','宋诗','song-poetry','','[]','憶昔聯書上辟廱，公如玉樹照春風。',64,'全唐诗/poet.song.97000.json','["憶昔聯書上辟廱，公如玉樹照春風。", "鶱騰尚惜十年晚，銷散俄驚一夢空。", "世事正兹同沸鼎，我身今亦類飛蓬。", "愴懷爲執歸山紼，松柏蕭森淚眼中。"]'),
('ce1adeac-0211-4d49-b903-5cfd80c244dc','悼潘權仲','鄭剛中','宋','宋诗','song-poetry','','[]','一生丘壑賦幽閑，雅躅飄蕭未易攀。',64,'全唐诗/poet.song.97000.json','["一生丘壑賦幽閑，雅躅飄蕭未易攀。", "時縱高談塵俗外，頗傳佳句里閭間。", "身名昔已無虧闕，世路今方足險難。", "公獨髙培一阡土，想應無恨入桐山。"]'),
('813c7e8b-cfcc-43fc-8c72-ea8c686146d6','悼潘義榮母','鄭剛中','宋','宋诗','song-poetry','','[]','去年兩槳泛清深，正是隨雛出鳳林。',64,'全唐诗/poet.song.97000.json','["去年兩槳泛清深，正是隨雛出鳳林。", "綵仗渾如天上去，壽光俄向斗邊沈。", "金花象軸恩雖在，雲隴山原痛可任。", "我亦堂前飛鶴起，强成哀挽倍傷心。"]'),
('4558b26f-8d08-470a-8b01-11461e6cbb60','離平江','鄭剛中','宋','宋诗','song-poetry','','[]','橋外客舟連夜發，飽吹十幅風蒲滑。',32,'全唐诗/poet.song.97000.json','["橋外客舟連夜發，飽吹十幅風蒲滑。", "天明無處覓髙城，但見吳江波浪闊。"]'),
('4fe03976-f35c-44eb-a01f-4dfaf4a80029','讀光明經捨身品','鄭剛中','宋','宋诗','song-poetry','','[]','摩訶薩埵真奇特，虎口捐身資福德。',32,'全唐诗/poet.song.97000.json','["摩訶薩埵真奇特，虎口捐身資福德。", "卻有同時畏避人，後来亦自成彌勒。"]'),
('d5050b65-13d4-4f23-be40-468ff21c9375','浦江道中','鄭剛中','宋','宋诗','song-poetry','','[]','驚憂度歲月，靡覺佳序臨。',24,'全唐诗/poet.song.97000.json','["驚憂度歲月，靡覺佳序臨。", "玉露破金菊，方知秋氣深。"]'),
('b581b5b6-84d9-46ed-9fda-ec568dae7e54','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','何時見池舘，一二佳友生。',24,'全唐诗/poet.song.97000.json','["何時見池舘，一二佳友生。", "酣飲入深夜，竹間燈火明。"]'),
('8700b657-239f-45ac-a7f1-fcaab0867fa0','潞公與梅聖俞論古人有純用平聲字爲詩如枯桑知天風是也而未有用側字者翌日聖俞爲詩云月出斷岸口照此别舸背獨且與婦飲頗勝俗客對大爲潞公所賞追用其語作側字四絕平字梅花一篇 側字 其一','鄭剛中','宋','宋诗','song-poetry','','[]','久雨閉陋室，薜荔絡敗壘。',24,'全唐诗/poet.song.97000.json','["久雨閉陋室，薜荔絡敗壘。", "乙子語大慧，我聽勿入耳。"]'),
('07bc59a5-09c2-4b29-bf89-f9b48e7d376d','潞公與梅聖俞論古人有純用平聲字爲詩如枯桑知天風是也而未有用側字者翌日聖俞爲詩云月出斷岸口照此别舸背獨且與婦飲頗勝俗客對大爲潞公所賞追用其語作側字四絕平字梅花一篇 側字 其二','鄭剛中','宋','宋诗','song-poetry','','[]','具酒作社飲，此事古倡始。',24,'全唐诗/poet.song.97000.json','["具酒作社飲，此事古倡始。", "孰肯具果蔬，被肘醉子美。"]'),
('ac1126ab-8b37-4b9c-9aaa-995936dab76b','潞公與梅聖俞論古人有純用平聲字爲詩如枯桑知天風是也而未有用側字者翌日聖俞爲詩云月出斷岸口照此别舸背獨且與婦飲頗勝俗客對大爲潞公所賞追用其語作側字四絕平字梅花一篇 側字 其三','鄭剛中','宋','宋诗','song-poetry','','[]','節物暗老我，壮志特未已。',24,'全唐诗/poet.song.97000.json','["節物暗老我，壮志特未已。", "事業力自致，貴賤命可委。"]'),
('29837824-5134-4618-b3b4-3c7de2055502','潞公與梅聖俞論古人有純用平聲字爲詩如枯桑知天風是也而未有用側字者翌日聖俞爲詩云月出斷岸口照此别舸背獨且與婦飲頗勝俗客對大爲潞公所賞追用其語作側字四絕平字梅花一篇 側字 其四','鄭剛中','宋','宋诗','song-poetry','','[]','案上具筆硯，砌下秀菊杞。',24,'全唐诗/poet.song.97000.json','["案上具筆硯，砌下秀菊杞。", "我顧乏大屋，尚賴有此爾。"]'),
('146f1086-70c9-49c7-920f-84504543fe62','潞公與梅聖俞論古人有純用平聲字爲詩如枯桑知天風是也而未有用側字者翌日聖俞爲詩云月出斷岸口照此别舸背獨且與婦飲頗勝俗客對大爲潞公所賞追用其語作側字四絕平字梅花一篇 平字梅花','鄭剛中','宋','宋诗','song-poetry','','[]','江梅非凡根，先春花南枝。',96,'全唐诗/poet.song.97000.json','["江梅非凡根，先春花南枝。", "玲瓏皆瑤英，雕鐫誰爲之。", "天髙孤芳寒，風来幽香随。", "朝暾晞霜華，蘭膏塗真妃。", "移之當疏簾，吟腸清相宜。", "吾將讒花神，妖紅徒紛披。", "何如今江梅，芬芳無休時。", "終愁芝蘭嗔，侵渠名聲衰。"]'),
('9da86a16-3e26-4c1a-b7e0-6a56c9192bf5','得雨偶書','鄭剛中','宋','宋诗','song-poetry','','[]','夏暑踰秋驕未盡，萬物皇皇久焦窘。',32,'全唐诗/poet.song.97000.json','["夏暑踰秋驕未盡，萬物皇皇久焦窘。", "大雨一霈天地涼，星斗明焕草木潤。"]'),
('b5c5d91d-66e8-4394-a2b6-7c975df846ee','曉起','鄭剛中','宋','宋诗','song-poetry','','[]','昨夜花間成酩酊，今日天風吹始醒。',32,'全唐诗/poet.song.97000.json','["昨夜花間成酩酊，今日天風吹始醒。", "爐香深炷坐中庭，獨看竹梢移午影。"]'),
('e16be469-7f55-4dc0-8f35-7e1d64150c4f','夜坐','鄭剛中','宋','宋诗','song-poetry','','[]','酒軟剛腸愁脉脉，夜静微風搖老柏。',32,'全唐诗/poet.song.97000.json','["酒軟剛腸愁脉脉，夜静微風搖老柏。", "七星插卯雲縱横，月影昏昏半墻白。"]'),
('f3e33c5f-7166-4336-bc43-5a1ae64e95d8','村居二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','山風拂拂堕松釵，午日亭亭覆矮槐。',32,'全唐诗/poet.song.97000.json','["山風拂拂堕松釵，午日亭亭覆矮槐。", "一唾閑名歸酒盞，萬鈞清思入詩懷。"]'),
('4f94aac8-31a4-4238-9f3a-a5aa177a6d97','村居二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','清心只有前溪水，息念唯憑一炷香。',32,'全唐诗/poet.song.97000.json','["清心只有前溪水，息念唯憑一炷香。", "不覺青春倐過去，滿村桑葉吐新黄。"]'),
('57376504-0d8a-4e2d-b28b-e14d3d3a2373','浦江道中三絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','瘦骨巖巖禍患餘，追随人事愈馳驅。',32,'全唐诗/poet.song.97000.json','["瘦骨巖巖禍患餘，追随人事愈馳驅。", "何時洒掃松楸畔，小蓋茅庵只讀書。"]'),
('40de1c9c-d705-4f5b-96a1-8ab98d0dd34f','浦江道中三絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','籃輿風緊揭疏簾，雨著春衣潤欲粘。',32,'全唐诗/poet.song.97000.json','["籃輿風緊揭疏簾，雨著春衣潤欲粘。", "滿眼陰雲壓平野，此時懷抱惡憎嫌。"]'),
('30cab349-83d5-4c1c-b991-85cacb54051c','浦江道中三絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','寒梅蓄積香成蕾，古柳安排綠入絛。',32,'全唐诗/poet.song.97000.json','["寒梅蓄積香成蕾，古柳安排綠入絛。", "景物年年覺新好，所憐幽獨自蕭騷。"]'),
('9fc8f3a8-483d-42c3-a2af-a0082aa175cd','寺前書院','鄭剛中','宋','宋诗','song-poetry','','[]','竹屋紙窗無限好，觀書學字不妨清。',32,'全唐诗/poet.song.97000.json','["竹屋紙窗無限好，觀書學字不妨清。", "誰知夜夢饒驚枕，荘舄依前自越聲。"]'),
('82189608-38dd-48b1-870a-6333e348a536','和季平哭小女時避地靈峰','鄭剛中','宋','宋诗','song-poetry','','[]','荒山藤束木皮棺，見此令人鼻骨酸。',32,'全唐诗/poet.song.97000.json','["荒山藤束木皮棺，見此令人鼻骨酸。", "自是杏殤風易翦，不須慚痛淚闌干。"]'),
('3607128a-8b6b-48f8-a365-b0dedcad0e16','題後鄭壁','鄭剛中','宋','宋诗','song-poetry','','[]','滿眼烟塵雜鼓旗，經冬首鼠負憂疑。',32,'全唐诗/poet.song.97000.json','["滿眼烟塵雜鼓旗，經冬首鼠負憂疑。", "樹頭新綠今如此，孤負春光固可知。"]'),
('b26d79b0-2771-41f0-98cf-5e0169b764b6','題靈峰見山閣','鄭剛中','宋','宋诗','song-poetry','','[]','兵火相尋音問絕，登髙寓目空傷神。',32,'全唐诗/poet.song.97000.json','["兵火相尋音問絕，登髙寓目空傷神。", "金華山且望不見，况乃欲見山下人。"]'),
('b2c0d831-b6db-4e92-b6bf-52b3d8727eab','避方寇五絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','皇家休運正無疆，撼樹蚍蜉不自量。',32,'全唐诗/poet.song.97000.json','["皇家休運正無疆，撼樹蚍蜉不自量。", "未作天街一杯血，暫憑山谷恣跳梁。"]'),
('185581d9-82c8-436c-80c9-41074027c507','避方寇五絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','啖惑愚民倚怪神，誅鋤當見不淹旬。',32,'全唐诗/poet.song.97000.json','["啖惑愚民倚怪神，誅鋤當見不淹旬。", "何嘗耳目親旗鼓，只是流離失業人。"]'),
('69c42184-2c64-46a9-a4c6-5a119e126d47','避方寇五絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','朝廷平日祗尊儒，文武於今遂兩途。',32,'全唐诗/poet.song.97000.json','["朝廷平日祗尊儒，文武於今遂兩途。", "聞說官軍又旗靡，誰收黄石老人書。"]'),
('441f2f3c-a4fe-4d47-95e4-1701cda85a30','避方寇五絕  其四','鄭剛中','宋','宋诗','song-poetry','','[]','獵獵霜風捲地寒，狼星奮角夜漫漫。',32,'全唐诗/poet.song.97000.json','["獵獵霜風捲地寒，狼星奮角夜漫漫。", "書生無路堪馳騁，被酒燈前把劍看。"]'),
('63fe58be-ee36-485c-bf0e-e7b725d76fdd','避方寇五絕  其五','鄭剛中','宋','宋诗','song-poetry','','[]','將軍失策又顛摧，感激令人動壮懷。',32,'全唐诗/poet.song.97000.json','["將軍失策又顛摧，感激令人動壮懷。", "安得帳前圍百萬，悠悠旌旆夜銜枚。"]'),
('11777137-de24-4bac-babe-5fa2f89d3ad8','即事','鄭剛中','宋','宋诗','song-poetry','','[]','梅子垂垂傍短墻，淡烟微雨暗池塘。',32,'全唐诗/poet.song.97000.json','["梅子垂垂傍短墻，淡烟微雨暗池塘。", "年来自覺傷春甚，覧鏡欷歔淚數行。"]'),
('d6f28b9f-0bb8-4e9b-ac24-ab2bca1b072e','清明前十日大雪二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','五花素色逼窗簷，紙帳重將布被添。',32,'全唐诗/poet.song.97000.json','["五花素色逼窗簷，紙帳重將布被添。", "天爲韶陽太妖冶，故令翦水作清嚴。"]'),
('4f69e018-bec4-445d-956f-39e9a616003a','清明前十日大雪二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','南山春晏蕨生芽，怪得清寒數倍加。',32,'全唐诗/poet.song.97000.json','["南山春晏蕨生芽，怪得清寒數倍加。", "一雪洗將紅紫去，髙低林樹試瑤花。"]'),
('ba6a2660-5893-465a-9224-8f1af5a4188e','度金沙嶺','鄭剛中','宋','宋诗','song-poetry','','[]','兩行古木影交加，山欲侵雲水見沙。',32,'全唐诗/poet.song.97000.json','["兩行古木影交加，山欲侵雲水見沙。", "最好嶺前鷗鷺起，竹林深處兩三家。"]'),
('a5423042-6a72-48cd-84b0-b09fa17639b1','渡胡源口二絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','暫出箯輿上小航，眼明重喜見江鄉。',32,'全唐诗/poet.song.97000.json','["暫出箯輿上小航，眼明重喜見江鄉。", "夢魂孤寄浪頭宿，一夜随潮入富陽。"]'),
('30fb0a1c-ba3c-4d87-9f2c-d905a554e688','渡胡源口二絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','梨棗迎霜壓樹黄，蓋茅新屋漸成行。',32,'全唐诗/poet.song.97000.json','["梨棗迎霜壓樹黄，蓋茅新屋漸成行。", "人情喜見兵戈息，路上時聞酒甕香。"]'),
('b9f7cf78-952b-4dc4-9484-f89a8a48e6b6','吳江有三髙祠謂鴟夷子皮步兵校尉甪里先生也先有一人題其祠曰是非名利等煎熬白盡英雄兩鬢毛自古五湖風月好至今分付屬三髙因和之','鄭剛中','宋','宋诗','song-poetry','','[]','外物由来如夢幻，達人輕視等毫毛。',32,'全唐诗/poet.song.97000.json','["外物由来如夢幻，達人輕視等毫毛。", "投身爲有區區者，始覺諸公節行髙。"]');
